def generate_view_code(schema: AppSchema | None = None):
    global metadata, engine
    output = []

    def generate_chart_view_code():
        global metadata, engine
        s = f"{[(table.name, snake_to_label(table.name)) for table in metadata.tables.values()]}"
        return CHART_VIEW_BODY.format(tbls=s)

    def get_foreign_keys(table):
        return [fk for fk in table.foreign_keys]

    def schema_table(table_name):
        if schema is None:
            return None
        for table_schema in schema.tables:
            if table_schema.name == table_name or underscore(table_schema.name) == underscore(table_name):
                return table_schema
        return None

    def schema_view(table_name):
        if schema is None:
            return None
        for view in schema.views:
            if view.table == table_name or underscore(view.table) == underscore(table_name):
                return view
        return None

    def lookup_label_fields(table_name):
        table_schema = schema_table(table_name)
        if table_schema is None:
            return ("id",)
        visible = [
            column
            for column in table_schema.columns
            if not column.hidden and not column.derived and not column.primary_key
        ]
        preferred = [
            _model_attribute_name(column)
            for column in visible
            if column.searchable or column.name.lower() in {"name", "title", "code", "email"}
        ]
        fallback = [_model_attribute_name(column) for column in visible[:2]]
        return tuple(dict.fromkeys(preferred or fallback or ["id"]))

    def lookup_fields(table_schema):
        if table_schema is None:
            return {}
        lookups = {}
        for column in table_schema.columns:
            if column.hidden or column.derived or column.references is None:
                continue
            target_table, target_column = column.references
            lookups[_model_attribute_name(column)] = {
                "field": _model_attribute_name(column),
                "source_column": column.name,
                "target_table": target_table,
                "target_column": target_column,
                "label_fields": lookup_label_fields(target_table),
                "required": not column.nullable and not column.primary_key,
            }
        return lookups

    def column_attr(column):
        if isinstance(column, ColumnSchema):
            return _model_attribute_name(column)
        return column.name

    def view_columns(table_name, table):
        table_schema = schema_table(table_name)
        if table_schema is None:
            columns = [column.name for column in table.columns if column.name != "id"]
            return columns, columns, columns

        visible_columns = [
            column
            for column in table_schema.columns
            if not column.hidden and not column.derived and column.name != "id"
        ]
        visible_by_name = {column.name: column for column in visible_columns}
        visible_by_attr = {column_attr(column): column for column in visible_columns}
        form_columns = [column_attr(column) for column in visible_columns]

        declared_view = schema_view(table_name)
        if declared_view and declared_view.fields:
            selected = []
            for field in declared_view.fields:
                column = visible_by_name.get(field) or visible_by_attr.get(field)
                if column is not None:
                    selected.append(column_attr(column))
            list_columns = selected
        else:
            list_columns = form_columns

        if any(column.searchable for column in table_schema.columns):
            search_columns = [
                column_attr(column)
                for column in visible_columns
                if column.searchable
            ]
        else:
            search_columns = form_columns
        return form_columns, list_columns, search_columns

    def view_sections(table_name):
        table_schema = schema_table(table_name)
        declared_view = schema_view(table_name)
        if table_schema is None or declared_view is None or not declared_view.sections:
            return [], {}
        attr_by_name = {
            column.name: column_attr(column)
            for column in table_schema.columns
            if not column.hidden and not column.derived and column.name != "id"
        }
        attr_by_attr = {
            column_attr(column): column_attr(column)
            for column in table_schema.columns
            if not column.hidden and not column.derived and column.name != "id"
        }
        sections = []
        tabs = {}
        for section in declared_view.sections:
            section_fields = []
            for field in section.fields:
                resolved = attr_by_name.get(field) or attr_by_attr.get(field)
                if resolved is not None:
                    section_fields.append(resolved)
            if section_fields:
                section_name = underscore(section.name)
                section_spec = {
                    "name": section_name,
                    "label": snake_to_label(section.name),
                    "fields": section_fields,
                }
                sections.append(section_spec)
                tabs[section_name] = {
                    "title": section_spec["label"],
                    "fields": section_fields,
                }
        return sections, tabs

    def generate_view(table_name, table):
        class_name = snake_to_pascal(table_name)
        snk_table_name = snake_to_pascal(table_name)
        form_columns, list_columns, search_columns = view_columns(table_name, table)
        rt_cols = str(REF_TYPE_MIXIN_FIELDS)
        rt_fld_set = str(REF_TYPE_MIXIN_FIELDSET)
        table_schema = schema_table(table_name)
        sections, tabs = view_sections(table_name)
        label_columns = (
            table_schema.columns
            if table_schema is not None
            else tuple(table.columns)
        )
        lbl_cols = (
            f"{{"
            + ', '.join(
                [
                    f'"{column.name}": "{column.name}"'
                    for column in label_columns
                    if not column.name.startswith('id')
                    and not getattr(column, "hidden", False)
                ]
            )
            + "}"
        )
        output.append(
            VIEW_BODY.format(
                class_name=class_name,
                table_name=table_name,
                snk_table_name=snk_table_name,
                tbl_columns=form_columns,
                form_columns=form_columns,
                list_columns=list_columns,
                search_columns=search_columns,
                view_sections=sections,
                view_tabs=tabs,
                lookup_fields=lookup_fields(table_schema),
                rt_cols=rt_cols,
                rt_fld_set=rt_fld_set,
                lbl_cols=lbl_cols,
            )
        )

    def generate_master_detail_view(table_name, table, foreign_key):
        related_table_name = foreign_key.column.table.name
        related_class_name = snake_to_pascal(related_table_name)
        class_name = snake_to_pascal(table_name)
        output.append(
            VIEW_MASTER_DETAIL.format(
                related_table_name=related_table_name,
                related_class_name=related_class_name,
                class_name=class_name,
            )
        )

    def generate_multiple_view(table_name, table):
        class_name = snake_to_pascal(table_name)
        output.append(f"class {class_name}MultipleModelView(MultipleView):")
        output.append(
            f"    views = [{class_name}ModelView, "
            + ', '.join(
                [
                    f"{class_name}{snake_to_pascal(related_class)}ModelView"
                    for related_class in related_classes
                ]
            )
            + "]"
        )
        output.append("\n")

    for table_name, table in metadata.tables.items():
        foreign_keys = get_foreign_keys(table)
        generate_view(table_name, table)

        if len(foreign_keys) == 1:
            generate_master_detail_view(table_name, table, foreign_keys[0])
        elif len(foreign_keys) > 1:
            related_classes = [fk.column.table.name for fk in foreign_keys]
            for fk in foreign_keys:
                generate_master_detail_view(table_name, table, fk)

            generate_multiple_view(table_name, table)

    # Now append chart form code
    output.append(generate_chart_view_code())
    output.append("\n")
    output.append(VIEW_SCHEMA_CODE)

    # Now register the views generated
    output.append("def init_views(appbuilder):")
    for table_name, table in metadata.tables.items():
        class_name = snake_to_pascal(table_name)
        view_name = f"{class_name}ModelView"
        output.append(
            f"    appbuilder.add_view({view_name}, '{class_name}', "
            "icon='fa-table', category='Tables')"
        )

        foreign_keys = get_foreign_keys(table)
        if len(foreign_keys) == 1:
            related_class_name = snake_to_pascal(foreign_keys[0].column.table.name)
            view_name = f"{class_name}{related_class_name}ModelView"
            output.append(
                f"    appbuilder.add_view({view_name}, "
                f"'{class_name} {related_class_name} Master Detail', "
                "icon='fa-table', category='Master Detail')"
            )

        elif len(foreign_keys) > 1:
            view_name = f"{class_name}MultipleModelView"
            output.append(
                f"    appbuilder.add_view({view_name}, '{class_name} Multiple', "
                "icon='fa-table', category='Multiple')"
            )

    output.append("    appbuilder.add_separator('Tables')")
    output.append(
        "    appbuilder.add_view(ChartView, 'Draw Chart', "
        "icon='fa-bar-chart', category='Charts')"
    )
    output.append('    appbuilder.add_view(SchemaView, "Schema View", category="Database")')

    return "\n".join(output)


def generate_model_code(schema: AppSchema | None = None):
    output = []
    enum_values = {enum.name: tuple(enum.values) for enum in schema.enums} if schema else {}
    schema_columns = {
        (table.name, column.name): column
        for table in schema.tables
        for column in table.columns
    } if schema else {}

    def get_foreign_keys(table):
        return [fk for fk in table.foreign_keys]

    def is_association_table(table):
        foreign_keys = [c for c in table.columns if c.foreign_keys]
        return len(foreign_keys) == 2 and all(fk.primary_key for fk in foreign_keys)

    def get_relationship_type(table, column):
        for constraint in table.constraints:
            if (
                isinstance(constraint, ForeignKeyConstraint)
                and column.name in constraint.columns.keys()
            ):
                foreign_table = constraint.elements[0].column.table
                if is_association_table(table):
                    return "Many-to-Many", foreign_table.name
                return (
                    "One-to-Many" if foreign_table != table else "One-to-One",
                    foreign_table.name,
                )
        return None, None

    def render_column(column):
        schema_column = schema_columns.get((column.table.name, column.name))
        if schema_column is not None and schema_column.type_name in enum_values:
            values = ", ".join(repr(value) for value in enum_values[schema_column.type_name])
            fab_column_type = f"Enum({values}, name='{underscore(schema_column.type_name)}_enum')"
        else:
            column_type = column.type.compile(engine.dialect)
            fab_column_type = map_pgsql_datatypes(column_type.lower())
        fk, remote_table = get_relationship_type(column.table, column)

        if fk == "One-to-Many":
            return (
                f"Column({fab_column_type}, ForeignKey('{remote_table}.id'), "
                f"nullable={column.nullable})",
                underscore(remote_table),
            )
        elif fk == "One-to-One":
            return (
                f"Column({fab_column_type}, ForeignKey('{remote_table}.id'), "
                f"nullable={column.nullable}, unique=True)",
                underscore(remote_table),
            )
        elif fk == "Many-to-Many":
            return (
                f"Column({fab_column_type}, ForeignKey('{remote_table}.id'), "
                f"primary_key=True, nullable={column.nullable})",
                underscore(remote_table),
            )
        elif column.primary_key:
            return (
                f"Column({fab_column_type}, primary_key=True, "
                f"nullable={column.nullable}, autoincrement=True)",
                None,
            )
        else:
            return f"Column({fab_column_type}, nullable={column.nullable})", None

    for table_name, table in metadata.tables.items():
        class_name = snake_to_pascal(table_name)

        output.append(
            f"class {class_name}(RefTypeMixin, Model):  "
            "# RefTypeMixin, TransientMixin, PlaceMixin, DocMixin, PersonMixin"
        )
        output.append(f"    __tablename__ = '{table_name}'")

        primary_key_exists = any(column.primary_key for column in table.columns)
        if not primary_key_exists:
            print(table_name, 'NO PRIMARY KEY')
            output.append("    id = Column(Integer, primary_key=True, nullable=False, autoincrement=True)")

        for column in table.columns:
            column_name = underscore(column.name)
            column_def, col_type = render_column(column)
            if col_type is not None:
                column_name = col_type
            output.append(f"    {column_name} = {column_def}")

        m2m_relationships = [fk for fk in table.foreign_keys if fk.column.table != table]

        if len(m2m_relationships) == 2:
            related_table = m2m_relationships[1].column.table.name
            related_class = snake_to_pascal(related_table)
            output.append(
                f"    {related_class.lower()}_assoc = association_proxy('{snake_to_pascal(m2m_relationships[0].parent.name)}', '{related_class}')"
            )

        output.append("\n")

    return "\n".join(output)


def write_model_file(output_dir, schema: AppSchema | None = None):
    output_dir = Path(output_dir)
    output_dir.mkdir(parents=True, exist_ok=True)
    model_code = generate_model_code(schema)   # TODO change this to a template
    with open(output_dir / "models.py", "w") as f:
        f.write(
            "from sqlalchemy import (Column, Integer, String, ForeignKey, "
            "DateTime, Boolean, Float, Text, Date, Time, Numeric, Interval, Enum)\n"
        )
        f.write("from sqlalchemy.orm import relationship, backref\n")
        f.write("from sqlalchemy.ext.associationproxy import association_proxy\n")
        f.write("from flask_appbuilder import Model\n\n")
        f.write("from app.model_mixins import *\n")
        f.write("Base = Model\n\n")
        f.write(model_code)



def write_view_file(output_dir, schema: AppSchema | None = None):
    output_dir = Path(output_dir)
    output_dir.mkdir(parents=True, exist_ok=True)
    view_code = generate_view_code(schema) # TODO change this to a template
    with open(output_dir / "views.py", "w") as f:
        f.write("import sys, os\n")
        f.write(
            "from flask_appbuilder import (ModelView, MultipleView, MasterDetailView, "
            "SimpleFormView, BaseView, expose)\n"
        )
        f.write("from flask_appbuilder.models.sqla.interface import SQLAInterface\n")
        f.write("from sqlalchemy import create_engine, inspect, MetaData, ForeignKeyConstraint\n")
        f.write("from wtforms import Form, SelectField, SubmitField\n")
        f.write("from wtforms.validators import DataRequired\n")
        f.write("from flask import current_app, flash\n")
        f.write("from app.models import *\n")
        f.write("from app.model_mixins import *\n")
        f.write("from app.view_mixins import *\n")
        f.write("from app import appbuilder\n")
        f.write("from app.extensions import before_save_row, after_save_row\n\n")
        f.write("def _appgen_model_row(item, columns):\n")
        f.write("    return {column: getattr(item, column, None) for column in columns}\n\n")
        f.write("def _appgen_apply_row(item, row):\n")
        f.write("    for key, value in dict(row).items():\n")
        f.write("        if hasattr(item, key):\n")
        f.write("            setattr(item, key, value)\n")
        f.write("    return item\n\n")
        f.write("# For the chart drawing module\n")
        f.write("engine = create_engine(appbuilder.app.config['SQLALCHEMY_DATABASE_URI'])\n")
        f.write("metadata = MetaData()\n")
        f.write("metadata.reflect(bind=engine)\n\n\n")
        f.write(view_code)


def write_api_file(output_dir, schema: AppSchema):
    """Write Flask-AppBuilder REST APIs for every generated model."""
    output_dir = Path(output_dir)
    output_dir.mkdir(parents=True, exist_ok=True)
    permission_map = {
        "get": "read",
        "get_list": "read",
        "info": "read",
        "post": "create",
        "put": "update",
        "delete": "delete",
    }
    with open(output_dir / "api.py", "w") as f:
        f.write("from flask_appbuilder import ModelRestApi\n")
        f.write("from flask_appbuilder.models.sqla.interface import SQLAInterface\n\n")
        f.write("from . import appbuilder\n")
        f.write("from .extensions import before_save_row, after_save_row\n")
        f.write("from .models import *\n\n\n")
        f.write(f"API_PERMISSION_MAP = {permission_map!r}\n\n\n")
        f.write("def _appgen_model_row(item, columns):\n")
        f.write("    return {column: getattr(item, column, None) for column in columns}\n\n\n")
        f.write("def _appgen_apply_row(item, row):\n")
        f.write("    for key, value in dict(row).items():\n")
        f.write("        if hasattr(item, key):\n")
        f.write("            setattr(item, key, value)\n")
        f.write("    return item\n\n\n")
        for table in schema.tables:
            class_name = snake_to_pascal(table.name)
            columns = [
                _model_attribute_name(column)
                for column in table.columns
                if not column.hidden and not column.derived
            ]
            f.write(f"class {class_name}RestApi(ModelRestApi):\n")
            f.write(f"    resource_name = \"{table.name}\"\n")
            f.write(f"    class_permission_name = \"{table.name}\"\n")
            f.write("    method_permission_name = API_PERMISSION_MAP\n")
            f.write(f"    datamodel = SQLAInterface({class_name})\n")
            f.write(f"    include_columns = {columns!r}\n")
            f.write("    allow_browser_login = True\n\n")
            f.write("    def pre_add(self, item):\n")
            f.write(f"        normalized = before_save_row({table.name!r}, _appgen_model_row(item, self.include_columns))\n")
            f.write("        _appgen_apply_row(item, normalized)\n\n")
            f.write("    def pre_update(self, item):\n")
            f.write(f"        normalized = before_save_row({table.name!r}, _appgen_model_row(item, self.include_columns))\n")
            f.write("        _appgen_apply_row(item, normalized)\n\n")
            f.write("    def post_add(self, item):\n")
            f.write(f"        after_save_row({table.name!r}, _appgen_model_row(item, self.include_columns))\n\n")
            f.write("    def post_update(self, item):\n")
            f.write(f"        after_save_row({table.name!r}, _appgen_model_row(item, self.include_columns))\n\n\n")
            f.write(f"appbuilder.add_api({class_name}RestApi)\n\n\n")


def write_openapi_file(output_dir, schema: AppSchema):
    """Write a generated OpenAPI contract view and helper module."""
    output_dir = Path(output_dir)
    output_dir.mkdir(parents=True, exist_ok=True)
    (output_dir / "openapi.py").write_text(_openapi_text(schema, _app_name(schema)))


def write_gql_file(output_dir, schema: AppSchema):
    """Write a Graphene schema for generated models."""
    output_dir = Path(output_dir)
    output_dir.mkdir(parents=True, exist_ok=True)
    with open(output_dir / "gql.py", "w") as f:
        f.write("import graphene\n\n")
        f.write("from .models import *\n\n\n")
        for table in schema.tables:
            class_name = snake_to_pascal(table.name)
            f.write(f"class {class_name}Object(graphene.ObjectType):\n")
            for column in table.columns:
                if column.hidden or column.derived:
                    continue
                f.write(
                    f"    {_model_attribute_name(column)} = "
                    f"{_graphene_field(column.type_name)}\n"
                )
            f.write("\n\n")

        f.write("class Query(graphene.ObjectType):\n")
        if schema.tables:
            for table in schema.tables:
                class_name = snake_to_pascal(table.name)
                field_name = underscore(table.name)
                f.write(f"    {field_name} = graphene.List({class_name}Object)\n")
            f.write("\n")
            for table in schema.tables:
                class_name = snake_to_pascal(table.name)
                field_name = underscore(table.name)
                f.write(f"    def resolve_{field_name}(self, info):\n")
                f.write(f"        return {class_name}.query.all()\n\n")
        else:
            f.write("    health = graphene.String()\n\n")
            f.write("    def resolve_health(self, info):\n")
            f.write("        return \"ok\"\n\n")
        f.write("\n\nschema = graphene.Schema(query=Query)\n")


def write_security_file(output_dir, schema: AppSchema):
    """Write role and permission seed metadata for generated apps."""
    output_dir = Path(output_dir)
    output_dir.mkdir(parents=True, exist_ok=True)
    security_resources = tuple(
        {
            "table": table.name,
            "fields": tuple(column.name for column in table.columns),
            "protected_fields": tuple(
                column.name
                for column in table.columns
                if column.hidden or column.type_name.lower().split("(", 1)[0] in {"file", "image", "blob", "binary", "bytea"}
            ),
            "relationship_fields": tuple(column.name for column in table.columns if column.references),
        }
        for table in schema.tables
    )
    with open(output_dir / "security.py", "w") as f:
        f.write('"""Generated RBAC seed metadata for AppGen apps."""\n\n')
        f.write("from __future__ import annotations\n\n")
        f.write(f"SECURITY_RESOURCES = {security_resources!r}\n\n")
        f.write("ROLE_POLICIES = {\n")
        for role in schema.roles:
            f.write(f"    {role.name!r}: {{\n")
            for permission in role.permissions:
                f.write(
                    f"        {permission.resource!r}: {list(permission.actions)!r},\n"
                )
            f.write("    },\n")
        f.write("}\n\n")
        f.write("def allowed_actions(role_name, resource):\n")
        f.write("    \"\"\"Return actions allowed for a role on a resource.\"\"\"\n")
        f.write("    return tuple(ROLE_POLICIES.get(role_name, {}).get(resource, ()))\n\n")
        f.write("def can(role_name, resource, action):\n")
        f.write("    \"\"\"Return whether a role is allowed to perform an action.\"\"\"\n")
        f.write("    action = action.lower()\n")
        f.write("    allowed = {item.lower() for item in allowed_actions(role_name, resource)}\n")
        f.write("    return action in allowed or '*' in allowed\n\n")
        f.write("def normalize_principal(principal):\n")
        f.write("    \"\"\"Return a normalized generated authorization principal.\"\"\"\n")
        f.write("    principal = {} if principal is None else dict(principal)\n")
        f.write("    roles = principal.get('roles') or principal.get('role') or ()\n")
        f.write("    if isinstance(roles, str):\n")
        f.write("        roles = (roles,)\n")
        f.write("    return {\n")
        f.write("        'id': principal.get('id') or principal.get('sub') or principal.get('username'),\n")
        f.write("        'roles': tuple(roles),\n")
        f.write("        'tenant_id': principal.get('tenant_id') or principal.get('tenant') or principal.get('organization_id'),\n")
        f.write("        'claims': principal,\n")
        f.write("    }\n\n")
        f.write("def principal_allowed_actions(principal, resource):\n")
        f.write("    \"\"\"Return all actions a multi-role principal can perform on one resource.\"\"\"\n")
        f.write("    normalized = normalize_principal(principal)\n")
        f.write("    actions = []\n")
        f.write("    for role_name in normalized['roles']:\n")
        f.write("        for action in allowed_actions(role_name, resource):\n")
        f.write("            if action not in actions:\n")
        f.write("                actions.append(action)\n")
        f.write("    return tuple(actions)\n\n")
        f.write("def authorize(principal, resource, action):\n")
        f.write("    \"\"\"Return a deterministic authorization decision for generated apps.\"\"\"\n")
        f.write("    normalized = normalize_principal(principal)\n")
        f.write("    allowed = principal_allowed_actions(normalized, resource)\n")
        f.write("    action_lower = str(action).lower()\n")
        f.write("    allowed_lower = {item.lower() for item in allowed}\n")
        f.write("    ok = action_lower in allowed_lower or '*' in allowed_lower\n")
        f.write("    return {\n")
        f.write("        'ok': ok,\n")
        f.write("        'principal': normalized,\n")
        f.write("        'resource': resource,\n")
        f.write("        'action': action,\n")
        f.write("        'allowed_actions': allowed,\n")
        f.write("        'reason': 'allowed' if ok else 'missing_permission',\n")
        f.write("    }\n\n")
        f.write("def policy_matrix():\n")
        f.write("    \"\"\"Return role/resource/action matrix for UI and audits.\"\"\"\n")
        f.write("    rows = []\n")
        f.write("    for role_name, resources in sorted(ROLE_POLICIES.items()):\n")
        f.write("        for resource, actions in sorted(resources.items()):\n")
        f.write("            rows.append({'role': role_name, 'resource': resource, 'actions': tuple(actions)})\n")
        f.write("    return tuple(rows)\n\n")
        f.write("def authorization_audit_event(decision, *, request_id=None):\n")
        f.write("    \"\"\"Return an audit event for an authorization decision.\"\"\"\n")
        f.write("    return {\n")
        f.write("        'event': 'security.authorization.allowed' if decision.get('ok') else 'security.authorization.denied',\n")
        f.write("        'principal_id': decision.get('principal', {}).get('id'),\n")
        f.write("        'roles': tuple(decision.get('principal', {}).get('roles', ())),\n")
        f.write("        'resource': decision.get('resource'),\n")
        f.write("        'action': decision.get('action'),\n")
        f.write("        'ok': bool(decision.get('ok')),\n")
        f.write("        'reason': decision.get('reason'),\n")
        f.write("        'request_id': request_id,\n")
        f.write("    }\n\n")
        f.write("def access_change_proposal(role_name, resource, actions, *, actor=None):\n")
        f.write("    \"\"\"Return a reviewed RBAC policy change proposal.\"\"\"\n")
        f.write("    proposed = tuple(dict.fromkeys(str(action).lower() for action in actions))\n")
        f.write("    current = allowed_actions(role_name, resource)\n")
        f.write("    return {\n")
        f.write("        'kind': 'rbac_policy_change',\n")
        f.write("        'role': role_name,\n")
        f.write("        'resource': resource,\n")
        f.write("        'current_actions': current,\n")
        f.write("        'proposed_actions': proposed,\n")
        f.write("        'actor': actor,\n")
        f.write("        'review_required': True,\n")
        f.write("        'dsl': f'role {role_name} {{\\n  {resource}: {\", \".join(proposed)};\\n}}\\n',\n")
        f.write("    }\n\n")
        f.write("def security_resource_catalog():\n")
        f.write("    \"\"\"Return generated resources and protected fields for security review.\"\"\"\n")
        f.write("    return tuple(SECURITY_RESOURCES)\n\n")
        f.write("def threat_model():\n")
        f.write("    \"\"\"Return a generated threat model for the application surface.\"\"\"\n")
        f.write("    return {\n")
        f.write("        'format': 'appgen.security-threat-model.v1',\n")
        f.write("        'assets': tuple(resource['table'] for resource in SECURITY_RESOURCES),\n")
        f.write("        'protected_fields': tuple((resource['table'], field) for resource in SECURITY_RESOURCES for field in resource['protected_fields']),\n")
        f.write("        'trust_boundaries': ('browser_session', 'rest_api', 'graphql_api', 'database', 'background_jobs', 'external_integrations'),\n")
        f.write("        'threats': (\n")
        f.write("            {'id': 'authz-bypass', 'risk': 'high', 'surface': 'rest_api', 'mitigation': 'authorize every role/resource/action via ROLE_POLICIES'},\n")
        f.write("            {'id': 'secret-exposure', 'risk': 'high', 'surface': 'config', 'mitigation': 'scan generated config and environment for literal or default secrets'},\n")
        f.write("            {'id': 'injection', 'risk': 'medium', 'surface': 'database', 'mitigation': 'use SQLAlchemy models and reviewed SQL workbench guards'},\n")
        f.write("            {'id': 'tenant-leakage', 'risk': 'high', 'surface': 'database', 'mitigation': 'apply generated RLS and tenant filters when tenant fields exist'},\n")
        f.write("            {'id': 'file-upload-abuse', 'risk': 'medium', 'surface': 'media', 'mitigation': 'validate media fields, storage plans, and protected-field access'},\n")
        f.write("            {'id': 'session-replay', 'risk': 'medium', 'surface': 'browser_session', 'mitigation': 'runtime security headers and inactivity timeout'},\n")
        f.write("        ),\n")
        f.write("        'required_reviews': ('rbac_matrix', 'secret_scan', 'runtime_headers', 'dependency_scan', 'rls_policy', 'api_contract_auth'),\n")
        f.write("    }\n\n")
        f.write("def secret_exposure_scan(values=None):\n")
        f.write("    \"\"\"Return deterministic findings for default or literal secret exposure.\"\"\"\n")
        f.write("    values = dict(values or {})\n")
        f.write("    findings = []\n")
        f.write("    secret_markers = ('SECRET', 'TOKEN', 'PASSWORD', 'API_KEY', 'PRIVATE_KEY')\n")
        f.write("    bad_values = {'', 'change-me', 'change-me-before-deploy', 'changeme', 'password', 'secret'}\n")
        f.write("    for key, value in values.items():\n")
        f.write("        key_text = str(key).upper()\n")
        f.write("        value_text = str(value or '')\n")
        f.write("        if any(marker in key_text for marker in secret_markers):\n")
        f.write("            normalized = value_text.strip().lower()\n")
        f.write("            if normalized in bad_values or normalized.startswith('change-me'):\n")
        f.write("                findings.append({'severity': 'critical', 'key': key, 'kind': 'default_secret'})\n")
        f.write("            elif value_text and not value_text.isupper() and len(value_text) < 24:\n")
        f.write("                findings.append({'severity': 'warning', 'key': key, 'kind': 'possible_literal_secret'})\n")
        f.write("    return {'format': 'appgen.secret-exposure-scan.v1', 'ok': not any(item['severity'] == 'critical' for item in findings), 'findings': tuple(findings)}\n\n")
        f.write("def dependency_security_plan(requirements=None):\n")
        f.write("    \"\"\"Return a generated dependency vulnerability review plan.\"\"\"\n")
        f.write("    packages = tuple(requirements or ('flask-appbuilder', 'sqlalchemy', 'flask', 'graphene'))\n")
        f.write("    return {\n")
        f.write("        'format': 'appgen.dependency-security-plan.v1',\n")
        f.write("        'packages': packages,\n")
        f.write("        'commands': ('python -m pip-audit -r requirements.txt', 'python -m pip check'),\n")
        f.write("        'review_gates': ('no_known_critical_vulnerabilities', 'pinned_runtime_dependencies', 'license_review', 'upgrade_plan_for_findings'),\n")
        f.write("        'requires_review': True,\n")
        f.write("    }\n\n")
        f.write("def api_security_test_plan():\n")
        f.write("    \"\"\"Return generated API authorization and abuse-case tests.\"\"\"\n")
        f.write("    cases = []\n")
        f.write("    for resource in SECURITY_RESOURCES:\n")
        f.write("        table = resource['table']\n")
        f.write("        cases.append({'name': f'unauthenticated_{table.lower()}_list', 'resource': table, 'action': 'read', 'expected': (401, 403)})\n")
        f.write("        cases.append({'name': f'forbidden_{table.lower()}_delete', 'resource': table, 'action': 'delete', 'expected': (401, 403)})\n")
        f.write("    return {'format': 'appgen.api-security-test-plan.v1', 'cases': tuple(cases), 'checks': ('unauthenticated_denied', 'forbidden_action_denied', 'protected_fields_hidden')}\n\n")
        f.write("def security_gate_plan(values=None, existing_paths=()):\n")
        f.write("    \"\"\"Return the generated security gate used by CI and release reviews.\"\"\"\n")
        f.write("    existing = set(existing_paths)\n")
        f.write("    required = {'app/security.py', 'app/runtime_security.py', 'app/identity.py', 'app/rls.py', 'app/compliance.py'}\n")
        f.write("    missing = tuple(sorted(required - existing))\n")
        f.write("    secret_scan = secret_exposure_scan(values)\n")
        f.write("    return {\n")
        f.write("        'format': 'appgen.security-gate-plan.v1',\n")
        f.write("        'ok': not missing and secret_scan['ok'] and bool(threat_model()['threats']) and bool(policy_matrix()),\n")
        f.write("        'missing_artifacts': missing,\n")
        f.write("        'threat_model': threat_model(),\n")
        f.write("        'secret_scan': secret_scan,\n")
        f.write("        'dependency_security': dependency_security_plan(),\n")
        f.write("        'api_security_tests': api_security_test_plan(),\n")
        f.write("        'review_gates': ('threat_model_reviewed', 'no_default_secrets', 'rbac_matrix_reviewed', 'api_security_tests_run', 'dependency_scan_reviewed'),\n")
        f.write("    }\n\n")
        f.write("def security_signoff(values=None, existing_paths=(), actor=None):\n")
        f.write("    \"\"\"Return a release signoff envelope for generated security controls.\"\"\"\n")
        f.write("    gate = security_gate_plan(values, existing_paths)\n")
        f.write("    return {\n")
        f.write("        'format': 'appgen.security-signoff.v1',\n")
        f.write("        'actor': actor,\n")
        f.write("        'ok': gate['ok'],\n")
        f.write("        'gate': gate,\n")
        f.write("        'decision': 'approved' if gate['ok'] else 'blocked',\n")
        f.write("        'required_before_release': not gate['ok'],\n")
        f.write("    }\n\n")
        f.write("def security_workbench(values=None, existing_paths=(), actor=None):\n")
        f.write("    \"\"\"Return IDE-ready RBAC and security readiness evidence.\"\"\"\n")
        f.write("    signoff = security_signoff(values, existing_paths, actor=actor)\n")
        f.write("    matrix = policy_matrix()\n")
        f.write("    first_policy = matrix[0] if matrix else {'role': None, 'resource': None, 'actions': ()}\n")
        f.write("    first_action = first_policy['actions'][0] if first_policy.get('actions') else 'read'\n")
        f.write("    decision = authorize({'id': actor or 'security-workbench', 'roles': (first_policy.get('role'),)}, first_policy.get('resource'), first_action) if first_policy.get('role') else {'ok': False}\n")
        f.write("    audit = authorization_audit_event(decision, request_id='security-workbench')\n")
        f.write("    proposal = access_change_proposal(first_policy.get('role') or 'Reviewer', first_policy.get('resource') or 'Resource', first_policy.get('actions') or ('read',), actor=actor)\n")
        f.write("    gate = signoff['gate']\n")
        f.write("    checks = (\n")
        f.write("        {'id': 'policy_matrix', 'ok': bool(matrix), 'evidence': matrix},\n")
        f.write("        {'id': 'authorization_decision', 'ok': bool(decision.get('ok')), 'evidence': decision},\n")
        f.write("        {'id': 'authorization_audit', 'ok': audit.get('event') in ('security.authorization.allowed', 'security.authorization.denied'), 'evidence': audit},\n")
        f.write("        {'id': 'rbac_change_proposal', 'ok': proposal['review_required'] is True and proposal['dsl'].startswith('role '), 'evidence': proposal},\n")
        f.write("        {'id': 'resource_catalog', 'ok': bool(security_resource_catalog()), 'evidence': security_resource_catalog()},\n")
        f.write("        {'id': 'threat_model', 'ok': threat_model()['format'] == 'appgen.security-threat-model.v1' and bool(threat_model()['threats']), 'evidence': threat_model()},\n")
        f.write("        {'id': 'secret_scan', 'ok': gate['secret_scan']['ok'], 'evidence': gate['secret_scan']},\n")
        f.write("        {'id': 'dependency_security', 'ok': gate['dependency_security']['requires_review'] is True, 'evidence': gate['dependency_security']},\n")
        f.write("        {'id': 'api_security_tests', 'ok': bool(gate['api_security_tests']['cases']), 'evidence': gate['api_security_tests']},\n")
        f.write("        {'id': 'security_gate', 'ok': gate['ok'], 'evidence': gate},\n")
        f.write("        {'id': 'security_signoff', 'ok': signoff['ok'] and signoff['decision'] == 'approved', 'evidence': signoff},\n")
        f.write("    )\n")
        f.write("    ok = all(check['ok'] for check in checks)\n")
        f.write("    return {\n")
        f.write("        'format': 'appgen.security-workbench.v1',\n")
        f.write("        'ok': ok,\n")
        f.write("        'decision': 'approved' if ok else 'blocked',\n")
        f.write("        'checks': checks,\n")
        f.write("        'policy_matrix': matrix,\n")
        f.write("        'authorization': decision,\n")
        f.write("        'audit': audit,\n")
        f.write("        'proposal': proposal,\n")
        f.write("        'gate': gate,\n")
        f.write("        'signoff': signoff,\n")
        f.write("    }\n\n")
        f.write("def seed_roles(appbuilder):\n")
        f.write("    \"\"\"Create declared roles if they do not already exist.\"\"\"\n")
        f.write("    security_manager = appbuilder.sm\n")
        f.write("    for role_name in ROLE_POLICIES:\n")
        f.write("        if security_manager.find_role(role_name) is None:\n")
        f.write("            security_manager.add_role(role_name)\n")
        f.write("    return ROLE_POLICIES\n")


def write_runtime_security_file(output_dir):
    """Write generated session timeout and response hardening helpers."""
    output_dir = Path(output_dir)
    output_dir.mkdir(parents=True, exist_ok=True)
    (output_dir / "runtime_security.py").write_text(_runtime_security_text())


def write_workflow_file(output_dir, schema: AppSchema):
    """Write executable workflow transition helpers for DSL flows."""
    output_dir = Path(output_dir)
    output_dir.mkdir(parents=True, exist_ok=True)
    workflow_actions = {"*", "admin", "approve", "create", "review", "transition", "update"}
    workflow_role_policies = []
    for role in schema.roles:
        resources = []
        actions = set()
        for permission in role.permissions:
            allowed = {action.lower() for action in permission.actions}
            if allowed & workflow_actions:
                resources.append(permission.resource)
                actions.update(allowed)
        if resources:
            workflow_role_policies.append(
                {
                    "role": role.name,
                    "resources": tuple(resources),
                    "actions": tuple(sorted(actions)),
                }
            )
    workflow_authorization = {
        flow.name: {
            "format": "appgen.workflow-authorization.v1",
            "workflow": flow.name,
            "authorization_required": bool(workflow_role_policies),
            "roles": tuple(policy["role"] for policy in workflow_role_policies),
            "role_policies": tuple(workflow_role_policies),
            "bypass_roles": ("Admin", "SecurityManager"),
        }
        for flow in schema.flows
    }
    with open(output_dir / "workflow.py", "w") as f:
        f.write('"""Generated workflow transition helpers for AppGen apps."""\n\n')
        f.write("from __future__ import annotations\n\n")
        f.write("from flask import jsonify, request\n")
        f.write("from flask_appbuilder import BaseView, expose\n\n\n")
        f.write("WORKFLOWS = {\n")
        for flow in schema.flows:
            f.write(f"    {flow.name!r}: (\n")
            for step in flow.steps:
                f.write(f"        ({step.source!r}, {step.target!r}),\n")
            f.write("    ),\n")
        f.write("}\n\n")
        f.write(f"WORKFLOW_AUTHORIZATION = {workflow_authorization!r}\n\n")
        f.write("def transitions(flow_name):\n")
        f.write("    \"\"\"Return all declared transitions for a workflow.\"\"\"\n")
        f.write("    return tuple(WORKFLOWS.get(flow_name, ()))\n\n")
        f.write("def next_states(flow_name, state):\n")
        f.write("    \"\"\"Return valid target states from the current state.\"\"\"\n")
        f.write("    return tuple(target for source, target in transitions(flow_name) if source == state)\n\n")
        f.write("def can_transition(flow_name, source, target):\n")
        f.write("    \"\"\"Return whether a transition is allowed.\"\"\"\n")
        f.write("    return (source, target) in transitions(flow_name)\n\n")
        f.write("def transition(flow_name, source, target):\n")
        f.write("    \"\"\"Validate and return the target state for a transition.\"\"\"\n")
        f.write("    if not can_transition(flow_name, source, target):\n")
        f.write("        raise ValueError(f'{flow_name}: cannot transition from {source} to {target}')\n")
        f.write("    return target\n\n")
        f.write("def states(flow_name):\n")
        f.write("    \"\"\"Return all states mentioned by a workflow.\"\"\"\n")
        f.write("    result = []\n")
        f.write("    for source, target in transitions(flow_name):\n")
        f.write("        if source not in result:\n")
        f.write("            result.append(source)\n")
        f.write("        if target not in result:\n")
        f.write("            result.append(target)\n")
        f.write("    return tuple(result)\n\n")
        f.write("def start_states(flow_name):\n")
        f.write("    \"\"\"Return states that only appear as transition sources.\"\"\"\n")
        f.write("    sources = {source for source, _target in transitions(flow_name)}\n")
        f.write("    targets = {target for _source, target in transitions(flow_name)}\n")
        f.write("    return tuple(state for state in states(flow_name) if state in sources - targets)\n\n")
        f.write("def terminal_states(flow_name):\n")
        f.write("    \"\"\"Return states that only appear as transition targets.\"\"\"\n")
        f.write("    sources = {source for source, _target in transitions(flow_name)}\n")
        f.write("    targets = {target for _source, target in transitions(flow_name)}\n")
        f.write("    return tuple(state for state in states(flow_name) if state in targets - sources)\n\n")
        f.write("def workflow_catalog():\n")
        f.write("    \"\"\"Return generated workflow metadata for UI and automation.\"\"\"\n")
        f.write("    return tuple(\n")
        f.write("        {\n")
        f.write("            'name': flow_name,\n")
        f.write("            'transitions': transitions(flow_name),\n")
        f.write("            'states': states(flow_name),\n")
        f.write("            'start_states': start_states(flow_name),\n")
        f.write("            'terminal_states': terminal_states(flow_name),\n")
        f.write("            'authorization': workflow_authorization_policy(flow_name),\n")
        f.write("        }\n")
        f.write("        for flow_name in sorted(WORKFLOWS)\n")
        f.write("    )\n\n")
        f.write("def _principal_roles(principal):\n")
        f.write("    \"\"\"Return normalized role names from a generated auth principal.\"\"\"\n")
        f.write("    if principal is None:\n")
        f.write("        return ()\n")
        f.write("    if isinstance(principal, str):\n")
        f.write("        return (principal,)\n")
        f.write("    if not hasattr(principal, 'get'):\n")
        f.write("        roles = getattr(principal, 'roles', ()) or ()\n")
        f.write("        if isinstance(roles, str):\n")
        f.write("            return (roles,)\n")
        f.write("        return tuple(roles)\n")
        f.write("    roles = principal.get('roles') or principal.get('role') or ()\n")
        f.write("    if isinstance(roles, str):\n")
        f.write("        return (roles,)\n")
        f.write("    return tuple(roles)\n\n")
        f.write("def workflow_authorization_policy(flow_name):\n")
        f.write("    \"\"\"Return role-aware authorization metadata for one workflow.\"\"\"\n")
        f.write("    return WORKFLOW_AUTHORIZATION.get(flow_name, {\n")
        f.write("        'format': 'appgen.workflow-authorization.v1',\n")
        f.write("        'workflow': flow_name,\n")
        f.write("        'authorization_required': False,\n")
        f.write("        'roles': (),\n")
        f.write("        'role_policies': (),\n")
        f.write("        'bypass_roles': ('Admin', 'SecurityManager'),\n")
        f.write("    })\n\n")
        f.write("def can_transition_as(flow_name, source, target, principal=None):\n")
        f.write("    \"\"\"Return whether a principal may execute a valid workflow transition.\"\"\"\n")
        f.write("    if not can_transition(flow_name, source, target):\n")
        f.write("        return False\n")
        f.write("    policy = workflow_authorization_policy(flow_name)\n")
        f.write("    if not policy['authorization_required']:\n")
        f.write("        return True\n")
        f.write("    principal_roles = set(_principal_roles(principal))\n")
        f.write("    allowed_roles = set(policy['roles']) | set(policy['bypass_roles'])\n")
        f.write("    return bool(principal_roles & allowed_roles)\n\n")
        f.write("def transition_authorization_plan(flow_name, source, target, principal=None):\n")
        f.write("    \"\"\"Return an explainable workflow authorization decision.\"\"\"\n")
        f.write("    policy = workflow_authorization_policy(flow_name)\n")
        f.write("    principal_roles = _principal_roles(principal)\n")
        f.write("    valid_transition = can_transition(flow_name, source, target)\n")
        f.write("    return {\n")
        f.write("        'format': 'appgen.workflow-transition-authorization.v1',\n")
        f.write("        'workflow': flow_name,\n")
        f.write("        'source': source,\n")
        f.write("        'target': target,\n")
        f.write("        'valid_transition': valid_transition,\n")
        f.write("        'allowed': valid_transition and can_transition_as(flow_name, source, target, principal),\n")
        f.write("        'authorization_required': policy['authorization_required'],\n")
        f.write("        'principal_roles': principal_roles,\n")
        f.write("        'required_roles': policy['roles'],\n")
        f.write("        'bypass_roles': policy['bypass_roles'],\n")
        f.write("        'role_policies': policy['role_policies'],\n")
        f.write("    }\n\n")
        f.write("def workflow_approval_route(flow_name):\n")
        f.write("    \"\"\"Return a multi-user approval route for each workflow transition.\"\"\"\n")
        f.write("    policy = workflow_authorization_policy(flow_name)\n")
        f.write("    roles = policy['roles'] or policy['bypass_roles']\n")
        f.write("    return {\n")
        f.write("        'format': 'appgen.workflow-approval-route.v1',\n")
        f.write("        'workflow': flow_name,\n")
        f.write("        'authorization_required': policy['authorization_required'],\n")
        f.write("        'steps': tuple(\n")
        f.write("            {\n")
        f.write("                'source': source,\n")
        f.write("                'target': target,\n")
        f.write("                'event': f'{source}_to_{target}',\n")
        f.write("                'approval_roles': roles,\n")
        f.write("                'decision': ('approve', 'reject', 'request_changes'),\n")
        f.write("                'audit_required': True,\n")
        f.write("            }\n")
        f.write("            for source, target in transitions(flow_name)\n")
        f.write("        ),\n")
        f.write("    }\n\n")
        f.write("def workflow_sla_plan(flow_name, hours=24):\n")
        f.write("    \"\"\"Return SLA and escalation metadata for workflow operations.\"\"\"\n")
        f.write("    policy = workflow_authorization_policy(flow_name)\n")
        f.write("    return {\n")
        f.write("        'format': 'appgen.workflow-sla.v1',\n")
        f.write("        'workflow': flow_name,\n")
        f.write("        'target_hours': int(hours),\n")
        f.write("        'escalation_after_hours': int(hours) * 2,\n")
        f.write("        'notify_roles': policy['roles'] or policy['bypass_roles'],\n")
        f.write("        'metrics': ('age_hours', 'overdue_count', 'transition_latency_p95'),\n")
        f.write("        'alerts': tuple(\n")
        f.write("            {'event': f'{source}_to_{target}', 'when': 'overdue', 'severity': 'warning'}\n")
        f.write("            for source, target in transitions(flow_name)\n")
        f.write("        ),\n")
        f.write("    }\n\n")
        f.write("def workflow_audit_event(flow_name, source, target, actor=None, decision='approve'):\n")
        f.write("    \"\"\"Return an audit event for a reviewed workflow transition.\"\"\"\n")
        f.write("    auth = transition_authorization_plan(flow_name, source, target, {'role': actor} if isinstance(actor, str) else actor)\n")
        f.write("    return {\n")
        f.write("        'format': 'appgen.workflow-audit-event.v1',\n")
        f.write("        'workflow': flow_name,\n")
        f.write("        'source': source,\n")
        f.write("        'target': target,\n")
        f.write("        'event': f'{flow_name}.{source}.{target}',\n")
        f.write("        'actor': actor,\n")
        f.write("        'decision': decision,\n")
        f.write("        'valid_transition': auth['valid_transition'],\n")
        f.write("        'allowed': auth['allowed'],\n")
        f.write("        'required_roles': auth['required_roles'],\n")
        f.write("        'principal_roles': auth['principal_roles'],\n")
        f.write("    }\n\n")
        f.write("def transition_runbook(flow_name, source, target, principal=None):\n")
        f.write("    \"\"\"Return the operational runbook for executing a workflow transition.\"\"\"\n")
        f.write("    return {\n")
        f.write("        'format': 'appgen.workflow-transition-runbook.v1',\n")
        f.write("        'workflow': flow_name,\n")
        f.write("        'source': source,\n")
        f.write("        'target': target,\n")
        f.write("        'authorization': transition_authorization_plan(flow_name, source, target, principal),\n")
        f.write("        'approval_route': workflow_approval_route(flow_name),\n")
        f.write("        'sla': workflow_sla_plan(flow_name),\n")
        f.write("        'audit_event': workflow_audit_event(flow_name, source, target, actor=principal),\n")
        f.write("        'checks': ('valid_transition', 'authorization', 'approval_recorded', 'audit_logged', 'notifications_queued'),\n")
        f.write("        'requires_review': True,\n")
        f.write("    }\n\n")
        f.write("def authorization_flow(flow_name):\n")
        f.write("    \"\"\"Return an FSM authorization graph for workflow designer UIs.\"\"\"\n")
        f.write("    policy = workflow_authorization_policy(flow_name)\n")
        f.write("    return {\n")
        f.write("        'format': 'appgen.workflow-authorization-flow.v1',\n")
        f.write("        'workflow': flow_name,\n")
        f.write("        'authorization_required': policy['authorization_required'],\n")
        f.write("        'roles': policy['roles'],\n")
        f.write("        'bypass_roles': policy['bypass_roles'],\n")
        f.write("        'role_policies': policy['role_policies'],\n")
        f.write("        'transitions': tuple(\n")
        f.write("            {\n")
        f.write("                'source': source,\n")
        f.write("                'target': target,\n")
        f.write("                'event': f'{source}_to_{target}',\n")
        f.write("                'roles': policy['roles'],\n")
        f.write("                'bypass_roles': policy['bypass_roles'],\n")
        f.write("            }\n")
        f.write("            for source, target in transitions(flow_name)\n")
        f.write("        ),\n")
        f.write("    }\n\n")
        f.write("def advance_plan(flow_name, start_state):\n")
        f.write("    \"\"\"Return a deterministic wizard path following first valid transitions.\"\"\"\n")
        f.write("    if start_state not in states(flow_name):\n")
        f.write("        raise ValueError(f'{flow_name}: unknown state {start_state}')\n")
        f.write("    path = [start_state]\n")
        f.write("    seen = {start_state}\n")
        f.write("    current = start_state\n")
        f.write("    while True:\n")
        f.write("        next_items = next_states(flow_name, current)\n")
        f.write("        if not next_items:\n")
        f.write("            return tuple(path)\n")
        f.write("        current = next_items[0]\n")
        f.write("        if current in seen:\n")
        f.write("            raise ValueError(f'{flow_name}: cycle detected at {current}')\n")
        f.write("        seen.add(current)\n")
        f.write("        path.append(current)\n\n")
        f.write("def transition_graph(flow_name):\n")
        f.write("    \"\"\"Return adjacency metadata for generated FSM/state-chart tooling.\"\"\"\n")
        f.write("    return {\n")
        f.write("        state: tuple(target for source, target in transitions(flow_name) if source == state)\n")
        f.write("        for state in states(flow_name)\n")
        f.write("    }\n\n")
        f.write("def statechart_mermaid(flow_name):\n")
        f.write("    \"\"\"Return a Mermaid state diagram for a generated workflow.\"\"\"\n")
        f.write("    lines = ['stateDiagram-v2']\n")
        f.write("    for state in start_states(flow_name):\n")
        f.write("        lines.append(f'  [*] --> {state}')\n")
        f.write("    for source, target in transitions(flow_name):\n")
        f.write("        lines.append(f'  {source} --> {target}')\n")
        f.write("    for state in terminal_states(flow_name):\n")
        f.write("        lines.append(f'  {state} --> [*]')\n")
        f.write("    return '\\n'.join(lines) + '\\n'\n\n")
        f.write("def fsm_export(flow_name):\n")
        f.write("    \"\"\"Return a provider-neutral finite-state-machine export.\"\"\"\n")
        f.write("    return {\n")
        f.write("        'name': flow_name,\n")
        f.write("        'states': states(flow_name),\n")
        f.write("        'initial': start_states(flow_name),\n")
        f.write("        'final': terminal_states(flow_name),\n")
        f.write("        'transitions': tuple(\n")
        f.write("            {'source': source, 'target': target, 'event': f'{source}_to_{target}'}\n")
        f.write("            for source, target in transitions(flow_name)\n")
        f.write("        ),\n")
        f.write("        'graph': transition_graph(flow_name),\n")
        f.write("        'mermaid': statechart_mermaid(flow_name),\n")
        f.write("    }\n\n")
        f.write("def _xml_escape(value):\n")
        f.write("    \"\"\"Escape a value for generated SCXML previews without extra dependencies.\"\"\"\n")
        f.write("    return str(value).replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;').replace('\"', '&quot;')\n\n")
        f.write("def scxml_export(flow_name):\n")
        f.write("    \"\"\"Return a compact SCXML preview for external state-chart tools.\"\"\"\n")
        f.write("    initials = start_states(flow_name) or states(flow_name)[:1]\n")
        f.write("    initial = initials[0] if initials else ''\n")
        f.write("    lines = [f'<scxml version=\"1.0\" initial=\"{_xml_escape(initial)}\" name=\"{_xml_escape(flow_name)}\">']\n")
        f.write("    finals = set(terminal_states(flow_name))\n")
        f.write("    for state in states(flow_name):\n")
        f.write("        tag = 'final' if state in finals else 'state'\n")
        f.write("        outgoing = next_states(flow_name, state)\n")
        f.write("        if not outgoing:\n")
        f.write("            lines.append(f'  <{tag} id=\"{_xml_escape(state)}\" />')\n")
        f.write("            continue\n")
        f.write("        lines.append(f'  <{tag} id=\"{_xml_escape(state)}\">')\n")
        f.write("        for target in outgoing:\n")
        f.write("            event = f'{state}_to_{target}'\n")
        f.write("            lines.append(f'    <transition event=\"{_xml_escape(event)}\" target=\"{_xml_escape(target)}\" />')\n")
        f.write("        lines.append(f'  </{tag}>')\n")
        f.write("    lines.append('</scxml>')\n")
        f.write("    return '\\n'.join(lines) + '\\n'\n\n")
        f.write("def transition_proposal(flow_name, source, target, actor=None):\n")
        f.write("    \"\"\"Return a reviewed state-chart edit proposal that can regenerate DSL.\"\"\"\n")
        f.write("    source = str(source).strip()\n")
        f.write("    target = str(target).strip()\n")
        f.write("    duplicate = can_transition(flow_name, source, target)\n")
        f.write("    known_states = set(states(flow_name))\n")
        f.write("    warnings = []\n")
        f.write("    if duplicate:\n")
        f.write("        warnings.append('Transition already exists.')\n")
        f.write("    if source and source not in known_states:\n")
        f.write("        warnings.append(f'New source state: {source}')\n")
        f.write("    if target and target not in known_states:\n")
        f.write("        warnings.append(f'New target state: {target}')\n")
        f.write("    dsl = f'flow {flow_name} {{\\n  {source} -> {target};\\n}}\\n'\n")
        f.write("    return {\n")
        f.write("        'kind': 'add_transition',\n")
        f.write("        'flow': flow_name,\n")
        f.write("        'source': source,\n")
        f.write("        'target': target,\n")
        f.write("        'actor': actor,\n")
        f.write("        'duplicate': duplicate,\n")
        f.write("        'warnings': tuple(warnings),\n")
        f.write("        'requires_review': True,\n")
        f.write("        'dsl': dsl,\n")
        f.write("    }\n\n")
        f.write("def statechart_workbench(flow_name):\n")
        f.write("    \"\"\"Return the generated state-chart designer workspace for one workflow.\"\"\"\n")
        f.write("    return {\n")
        f.write("        'flow': flow_name,\n")
        f.write("        'fsm': fsm_export(flow_name),\n")
        f.write("        'exports': {\n")
        f.write("            'mermaid': statechart_mermaid(flow_name),\n")
        f.write("            'scxml': scxml_export(flow_name),\n")
        f.write("        },\n")
        f.write("        'authorization': authorization_flow(flow_name),\n")
        f.write("        'approval_route': workflow_approval_route(flow_name),\n")
        f.write("        'sla': workflow_sla_plan(flow_name),\n")
        f.write("        'diagnostics': workflow_graph_check(flow_name),\n")
        f.write("        'commands': ('add_transition', 'export_mermaid', 'export_scxml', 'inspect_authorization', 'inspect_approval_route', 'validate_graph'),\n")
        f.write("    }\n\n")
        f.write("def statechart_designer_catalog():\n")
        f.write("    \"\"\"Return every workflow prepared for visual state-chart editing.\"\"\"\n")
        f.write("    return tuple(statechart_workbench(flow_name) for flow_name in sorted(WORKFLOWS))\n\n")
        f.write("def workflow_graph_check(flow_name):\n")
        f.write("    \"\"\"Return reachability and dead-end diagnostics for a generated workflow.\"\"\"\n")
        f.write("    all_states = states(flow_name)\n")
        f.write("    starts = start_states(flow_name) or all_states[:1]\n")
        f.write("    reachable = []\n")
        f.write("    stack = list(starts)\n")
        f.write("    while stack:\n")
        f.write("        state = stack.pop(0)\n")
        f.write("        if state in reachable:\n")
        f.write("            continue\n")
        f.write("        reachable.append(state)\n")
        f.write("        stack.extend(target for target in next_states(flow_name, state) if target not in reachable)\n")
        f.write("    unreachable = tuple(state for state in all_states if state not in reachable)\n")
        f.write("    terminals = set(terminal_states(flow_name))\n")
        f.write("    dead_ends = tuple(state for state in all_states if not next_states(flow_name, state) and state not in terminals)\n")
        f.write("    return {\n")
        f.write("        'flow': flow_name,\n")
        f.write("        'ok': not unreachable and not dead_ends,\n")
        f.write("        'reachable': tuple(reachable),\n")
        f.write("        'unreachable': unreachable,\n")
        f.write("        'dead_ends': dead_ends,\n")
        f.write("    }\n\n")
        f.write("def workflow_release_gate(existing_paths=()):\n")
        f.write("    \"\"\"Return release readiness for generated workflows and statecharts.\"\"\"\n")
        f.write("    existing = set(existing_paths or ())\n")
        f.write("    required = {'app/workflow.py', 'app/templates/appgen_workflows.html'}\n")
        f.write("    missing = tuple(sorted(required - existing))\n")
        f.write("    flow_names = tuple(sorted(WORKFLOWS))\n")
        f.write("    diagnostics = tuple(workflow_graph_check(flow_name) for flow_name in flow_names)\n")
        f.write("    workbenches = tuple(statechart_workbench(flow_name) for flow_name in flow_names)\n")
        f.write("    checks = (\n")
        f.write("        {'gate': 'artifacts', 'ok': not missing, 'missing': missing},\n")
        f.write("        {'gate': 'workflow_catalog', 'ok': bool(flow_names), 'workflows': flow_names},\n")
        f.write("        {'gate': 'statechart_exports', 'ok': bool(workbenches) and all(item['fsm']['transitions'] and item['exports']['mermaid'].startswith('stateDiagram-v2') and item['exports']['scxml'].startswith('<scxml') for item in workbenches)},\n")
        f.write("        {'gate': 'graph_diagnostics', 'ok': bool(diagnostics) and all(item['ok'] for item in diagnostics), 'diagnostics': diagnostics},\n")
        f.write("        {'gate': 'authorization_flows', 'ok': bool(workbenches) and all(item['authorization']['format'] == 'appgen.workflow-authorization-flow.v1' for item in workbenches)},\n")
        f.write("        {'gate': 'approval_routes', 'ok': bool(workbenches) and all(item['approval_route']['steps'] for item in workbenches)},\n")
        f.write("        {'gate': 'sla_runbooks', 'ok': bool(flow_names) and all(workflow_sla_plan(flow_name)['metrics'] and transition_runbook(flow_name, transitions(flow_name)[0][0], transitions(flow_name)[0][1])['requires_review'] for flow_name in flow_names if transitions(flow_name))},\n")
        f.write("    )\n")
        f.write("    ok = all(check['ok'] for check in checks)\n")
        f.write("    return {\n")
        f.write("        'format': 'appgen.workflow-release-gate.v1',\n")
        f.write("        'ok': ok,\n")
        f.write("        'decision': 'approved' if ok else 'blocked',\n")
        f.write("        'checks': checks,\n")
        f.write("        'diagnostics': diagnostics,\n")
        f.write("    }\n\n")
        f.write("def workflow_workbench(existing_paths=()):\n")
        f.write("    \"\"\"Return aggregate workflow and statechart evidence for generated IDEs.\"\"\"\n")
        f.write("    release_gate = workflow_release_gate(existing_paths)\n")
        f.write("    flow_names = tuple(sorted(WORKFLOWS))\n")
        f.write("    workbenches = statechart_designer_catalog()\n")
        f.write("    routes = (\n")
        f.write("        '/workflows/statecharts.json',\n")
        f.write("        '/workflows/workbench.json',\n")
        f.write("        '/workflows/release-gate.json',\n")
        f.write("        '/workflows/<flow_name>/statechart.json',\n")
        f.write("        '/workflows/<flow_name>/statechart.mmd',\n")
        f.write("        '/workflows/<flow_name>/statechart.scxml',\n")
        f.write("        '/workflows/<flow_name>/workbench.json',\n")
        f.write("        '/workflows/<flow_name>/authorization.json',\n")
        f.write("        '/workflows/<flow_name>/approval-route.json',\n")
        f.write("        '/workflows/<flow_name>/sla.json',\n")
        f.write("        '/workflows/<flow_name>/proposal',\n")
        f.write("    )\n")
        f.write("    checks = (\n")
        f.write("        {'id': 'release_gate', 'ok': release_gate['ok'], 'evidence': release_gate['decision']},\n")
        f.write("        {'id': 'workflow_catalog', 'ok': bool(flow_names), 'evidence': workflow_catalog()},\n")
        f.write("        {'id': 'statechart_exports', 'ok': bool(workbenches) and all(item['fsm']['transitions'] and item['exports']['mermaid'].startswith('stateDiagram-v2') and item['exports']['scxml'].startswith('<scxml') for item in workbenches), 'evidence': workbenches},\n")
        f.write("        {'id': 'graph_diagnostics', 'ok': all(item['diagnostics']['ok'] for item in workbenches), 'evidence': tuple(item['diagnostics'] for item in workbenches)},\n")
        f.write("        {'id': 'authorization_flows', 'ok': all(item['authorization']['format'] == 'appgen.workflow-authorization-flow.v1' for item in workbenches), 'evidence': tuple(item['authorization'] for item in workbenches)},\n")
        f.write("        {'id': 'approval_routes', 'ok': all(item['approval_route']['steps'] for item in workbenches), 'evidence': tuple(item['approval_route'] for item in workbenches)},\n")
        f.write("        {'id': 'sla_runbooks', 'ok': all(item['sla']['metrics'] and item['commands'] for item in workbenches), 'evidence': tuple(item['sla'] for item in workbenches)},\n")
        f.write("        {'id': 'route_surface', 'ok': all(route.startswith('/workflows/') for route in routes), 'evidence': {'routes': routes}},\n")
        f.write("    )\n")
        f.write("    ok = all(check['ok'] for check in checks)\n")
        f.write("    return {\n")
        f.write("        'format': 'appgen.workflow-workbench.v1',\n")
        f.write("        'ok': ok,\n")
        f.write("        'decision': 'approved' if ok else 'blocked',\n")
        f.write("        'workflows': workbenches,\n")
        f.write("        'routes': routes,\n")
        f.write("        'release_gate': release_gate,\n")
        f.write("        'checks': checks,\n")
        f.write("    }\n\n")
        f.write("class WorkflowView(BaseView):\n")
        f.write("    route_base = '/workflows'\n")
        f.write("    default_view = 'index'\n\n")
        f.write("    @expose('/')\n")
        f.write("    def index(self):\n")
        f.write("        return self.render_template('appgen_workflows.html', workflows=workflow_catalog())\n\n")
        f.write("    @expose('/<flow_name>/<state>/next')\n")
        f.write("    def next_for_state(self, flow_name, state):\n")
        f.write("        return jsonify({'flow': flow_name, 'state': state, 'next': next_states(flow_name, state)})\n\n")
        f.write("    @expose('/<flow_name>/statechart.json')\n")
        f.write("    def statechart_json(self, flow_name):\n")
        f.write("        return jsonify(fsm_export(flow_name))\n\n")
        f.write("    @expose('/<flow_name>/statechart.mmd')\n")
        f.write("    def statechart_mermaid_route(self, flow_name):\n")
        f.write("        return statechart_mermaid(flow_name), 200, {'Content-Type': 'text/plain; charset=utf-8'}\n\n")
        f.write("    @expose('/<flow_name>/statechart.scxml')\n")
        f.write("    def statechart_scxml_route(self, flow_name):\n")
        f.write("        return scxml_export(flow_name), 200, {'Content-Type': 'application/xml; charset=utf-8'}\n\n")
        f.write("    @expose('/<flow_name>/workbench.json')\n")
        f.write("    def statechart_workbench_json(self, flow_name):\n")
        f.write("        return jsonify(statechart_workbench(flow_name))\n\n")
        f.write("    @expose('/<flow_name>/authorization.json')\n")
        f.write("    def authorization_json(self, flow_name):\n")
        f.write("        return jsonify(authorization_flow(flow_name))\n\n")
        f.write("    @expose('/<flow_name>/approval-route.json')\n")
        f.write("    def approval_route_json(self, flow_name):\n")
        f.write("        return jsonify(workflow_approval_route(flow_name))\n\n")
        f.write("    @expose('/<flow_name>/sla.json')\n")
        f.write("    def sla_json(self, flow_name):\n")
        f.write("        return jsonify(workflow_sla_plan(flow_name))\n\n")
        f.write("    @expose('/statecharts.json')\n")
        f.write("    def statechart_catalog_json(self):\n")
        f.write("        return jsonify(statechart_designer_catalog())\n\n")
        f.write("    @expose('/workbench.json')\n")
        f.write("    def workbench_json(self):\n")
        f.write("        return jsonify(workflow_workbench({'app/workflow.py', 'app/templates/appgen_workflows.html'}))\n\n")
        f.write("    @expose('/release-gate.json')\n")
        f.write("    def release_gate_json(self):\n")
        f.write("        return jsonify(workflow_release_gate({'app/workflow.py', 'app/templates/appgen_workflows.html'}))\n\n")
        f.write("    @expose('/<flow_name>/proposal', methods=('POST',))\n")
        f.write("    def transition_proposal_json(self, flow_name):\n")
        f.write("        payload = request.get_json(silent=True) or {}\n")
        f.write("        return jsonify(transition_proposal(flow_name, payload.get('source', ''), payload.get('target', ''), actor=payload.get('actor')))\n\n")
        f.write("def register_workflows(appbuilder):\n")
        f.write("    appbuilder.add_view(\n")
        f.write("        WorkflowView,\n")
        f.write("        'Workflows',\n")
        f.write("        icon='fa-random',\n")
        f.write("        category='AppGen',\n")
        f.write("    )\n")


def write_rules_file(output_dir, schema: AppSchema):
    """Write executable business rule and decision helpers for DSL rules."""
    output_dir = Path(output_dir)
    output_dir.mkdir(parents=True, exist_ok=True)
    (output_dir / "rules.py").write_text(_rules_text(schema))


def write_validation_file(output_dir, schema: AppSchema):
    """Write generated schema-driven validation contracts."""
    output_dir = Path(output_dir)
    output_dir.mkdir(parents=True, exist_ok=True)
    (output_dir / "validation.py").write_text(_validation_text(schema))


def write_health_file(output_dir, schema: AppSchema):
    """Write a small health contract for generated app smoke checks."""
    output_dir = Path(output_dir)
    output_dir.mkdir(parents=True, exist_ok=True)
    with open(output_dir / "health.py", "w") as f:
        f.write('"""Generated health metadata for AppGen apps."""\n\n')
        f.write("from __future__ import annotations\n\n")
        f.write(f"APP_NAME = {(_app_name(schema))!r}\n")
        f.write(f"TABLE_COUNT = {len(schema.tables)!r}\n")
        f.write(f"RELATION_COUNT = {len(schema.relations)!r}\n")
        f.write(f"VIEW_COUNT = {len(schema.views)!r}\n")
        f.write(f"FLOW_COUNT = {len(schema.flows)!r}\n")
        f.write(f"ROLE_COUNT = {len(schema.roles)!r}\n\n")
        f.write("def status():\n")
        f.write("    \"\"\"Return generated application readiness metadata.\"\"\"\n")
        f.write("    return {\n")
        f.write("        'app': APP_NAME,\n")
        f.write("        'ok': True,\n")
        f.write("        'tables': TABLE_COUNT,\n")
        f.write("        'relations': RELATION_COUNT,\n")
        f.write("        'views': VIEW_COUNT,\n")
        f.write("        'flows': FLOW_COUNT,\n")
        f.write("        'roles': ROLE_COUNT,\n")
        f.write("    }\n")
        f.write("\n\n")
        f.write("def health_summary():\n")
        f.write("    \"\"\"Return generated health metadata with readiness checks.\"\"\"\n")
        f.write("    payload = status()\n")
        f.write("    checks = {\n")
        f.write("        'app_name': bool(payload['app']),\n")
        f.write("        'schema_counts': payload['tables'] >= 0 and payload['relations'] >= 0,\n")
        f.write("        'ui_counts': payload['views'] >= 0,\n")
        f.write("        'automation_counts': payload['flows'] >= 0 and payload['roles'] >= 0,\n")
        f.write("    }\n")
        f.write("    return {\n")
        f.write("        'format': 'appgen.health-summary.v1',\n")
        f.write("        'ok': all(checks.values()) and payload['ok'] is True,\n")
        f.write("        'status': payload,\n")
        f.write("        'checks': checks,\n")
        f.write("    }\n")
        f.write("\n\n")
        f.write("def health_release_gate(existing_paths=()):\n")
        f.write("    \"\"\"Return deterministic release evidence for generated health metadata.\"\"\"\n")
        f.write("    existing = set(existing_paths)\n")
        f.write("    required = {'app/health.py'}\n")
        f.write("    summary = health_summary()\n")
        f.write("    checks = (\n")
        f.write("        {\n")
        f.write("            'gate': 'artifact_coverage',\n")
        f.write("            'ok': required.issubset(existing),\n")
        f.write("            'required': tuple(sorted(required)),\n")
        f.write("            'missing': tuple(sorted(required - existing)),\n")
        f.write("        },\n")
        f.write("        {\n")
        f.write("            'gate': 'status_payload',\n")
        f.write("            'ok': summary['status']['ok'] is True and summary['status']['app'] == APP_NAME,\n")
        f.write("            'app': APP_NAME,\n")
        f.write("        },\n")
        f.write("        {\n")
        f.write("            'gate': 'schema_metadata',\n")
        f.write("            'ok': summary['checks']['schema_counts'] and summary['status']['tables'] == TABLE_COUNT,\n")
        f.write("            'tables': TABLE_COUNT,\n")
        f.write("            'relations': RELATION_COUNT,\n")
        f.write("        },\n")
        f.write("        {\n")
        f.write("            'gate': 'ui_and_automation_metadata',\n")
        f.write("            'ok': summary['checks']['ui_counts'] and summary['checks']['automation_counts'],\n")
        f.write("            'views': VIEW_COUNT,\n")
        f.write("            'flows': FLOW_COUNT,\n")
        f.write("            'roles': ROLE_COUNT,\n")
        f.write("        },\n")
        f.write("    )\n")
        f.write("    return {\n")
        f.write("        'format': 'appgen.health-release-gate.v1',\n")
        f.write("        'ok': all(check['ok'] for check in checks),\n")
        f.write("        'checks': checks,\n")
        f.write("        'summary': summary,\n")
        f.write("    }\n")


