def write_pbc_runtime_file(output_dir, schema: AppSchema):
    """Write generated composable capability runtime helpers."""
    output_dir = Path(output_dir)
    output_dir.mkdir(parents=True, exist_ok=True)
    (output_dir / "pbc_runtime.py").write_text(_pbc_runtime_text(schema))


def write_component_contract_files(output_dir):
    """Write one generated implementation module per built-in component and package."""
    output_dir = Path(output_dir)
    component_dir = output_dir / "component_contracts"
    package_dir = output_dir / "component_packages"
    component_test_dir = output_dir / "component_tests"
    package_test_dir = output_dir / "component_package_tests"
    component_dir.mkdir(parents=True, exist_ok=True)
    package_dir.mkdir(parents=True, exist_ok=True)
    component_test_dir.mkdir(parents=True, exist_ok=True)
    package_test_dir.mkdir(parents=True, exist_ok=True)
    component_names = (
        "Label", "TextBox", "EmailInput", "TextArea", "Select", "Checkbox",
        "Lookup",
        "DatePicker", "DateTimePicker", "TimePicker", "NumberInput",
        "ImageUpload", "FileUpload", "RelationshipPicker", "Button",
        "Section", "Tabs", "Panel", "GroupBox", "RadioGroup", "RadioButton", "ListBox",
        "ListView", "TreeView", "Grid", "StringGrid", "PageControl", "Layout",
        "ScrollBox", "FlowLayout", "GridLayout", "VerticalBoxLayout", "HorizontalBoxLayout",
        "MainMenu", "PopupMenu", "ToolBar", "ActionList", "SplashScreen", "Image",
        "Shape", "PathShape", "Rectangle", "Ellipse", "Line", "Bitmap", "Chart", "ReportViewer",
        "WebBrowser", "Timer", "DataSource", "BindingSource", "RESTClient",
        "CameraView", "LocationSensor", "MotionSensor", "OrientationSensor", "NotificationCenter",
        "PhotoPicker", "BiometricAuth", "ContactsPicker", "CalendarEvents", "SecureStore",
        "PushClient", "BluetoothClient", "NfcReader", "FilePicker", "ShareSheet", "BackgroundTask", "Animation",
        "FloatAnimation", "ColorAnimation", "PathAnimation", "Effect", "StyleBook", "StyleManager",
        "GestureManager", "Gesture", "Viewport3D", "Dummy3D", "Camera3D", "Light3D", "Mesh3D",
        "DatabaseConnection", "TableAdapter", "ClientDataSet",
    )
    package_ids = (
        "devexpress-native", "tms-fnc", "fastreport", "teechart", "skia4rad",
        "jvcl-jcl", "virtual-treeview", "indy", "devart-data-access",
        "intraweb-unigui",
    )
    (component_dir / "__init__.py").write_text(_component_contract_init_text(component_names), encoding="utf-8")
    (package_dir / "__init__.py").write_text(_component_package_init_text(package_ids), encoding="utf-8")
    (component_test_dir / "__init__.py").write_text(_component_test_init_text(component_names), encoding="utf-8")
    (package_test_dir / "__init__.py").write_text(_component_package_test_init_text(package_ids), encoding="utf-8")
    for component_name in component_names:
        (component_dir / f"{_module_name(component_name)}.py").write_text(
            _component_contract_module_text(component_name),
            encoding="utf-8",
        )
        (component_test_dir / f"test_{_module_name(component_name)}.py").write_text(
            _component_test_module_text(component_name),
            encoding="utf-8",
        )
    for package_id in package_ids:
        (package_dir / f"{_module_name(package_id)}.py").write_text(
            _component_package_module_text(package_id),
            encoding="utf-8",
        )
        (package_test_dir / f"test_{_module_name(package_id)}.py").write_text(
            _component_package_test_module_text(package_id),
            encoding="utf-8",
        )


