def _model_attribute_name(column: ColumnSchema) -> str:
    if column.references is not None:
        return underscore(column.references[0])
    return underscore(column.name)


def _graphene_field(type_name: str) -> str:
    normalized = type_name.lower().split("(", 1)[0]
    if normalized in {"int", "integer", "serial", "smallint", "bigint", "bigserial"}:
        return "graphene.Int()"
    if normalized in {"float", "real", "double", "double precision", "decimal", "numeric", "money"}:
        return "graphene.Float()"
    if normalized in {"bool", "boolean"}:
        return "graphene.Boolean()"
    if normalized in {"date", "datetime", "timestamp", "timestamptz", "time"}:
        return "graphene.String()"
    return "graphene.String()"


def _openapi_schema_for_column(column: ColumnSchema, enum_values: dict[str, tuple[str, ...]]) -> dict:
    """Return an OpenAPI schema fragment for a generated column."""
    if column.type_name in enum_values:
        return {
            "type": "string",
            "enum": list(enum_values[column.type_name]),
            "description": f"{column.type_name} lookup value",
        }

    normalized = column.type_name.lower().split("(", 1)[0]
    normalized = normalized.removesuffix("[]")
    if normalized in {"int", "integer", "serial", "smallint", "bigint", "bigserial"}:
        return {"type": "integer"}
    if normalized in {"float", "real", "double", "double precision", "decimal", "numeric", "money"}:
        return {"type": "number"}
    if normalized in {"bool", "boolean"}:
        return {"type": "boolean"}
    if normalized == "date":
        return {"type": "string", "format": "date"}
    if normalized in {"datetime", "timestamp", "timestamptz", "time"}:
        return {"type": "string", "format": "date-time"}
    if normalized in {"image", "file", "blob", "binary", "bytea"}:
        return {"type": "string", "format": "binary"}
    if column.type_name.endswith("[]"):
        return {"type": "array", "items": {"type": "string"}}
    return {"type": "string"}


def _openapi_spec(schema: AppSchema, app_name: str) -> dict:
    """Build a generated OpenAPI 3.1 contract for the REST API surface."""
    enum_values = {enum.name: tuple(enum.values) for enum in schema.enums}
    paths: dict[str, dict] = {}
    component_schemas: dict[str, dict] = {}
    tags = []

    for table in schema.tables:
        class_name = snake_to_pascal(table.name)
        route_name = underscore(table.name)
        tag_name = snake_to_label(table.name)
        tags.append({"name": table.name, "description": f"{tag_name} resource"})
        properties = {}
        required = []
        for column in table.columns:
            if column.hidden or column.derived:
                continue
            field_name = _model_attribute_name(column)
            field_schema = _openapi_schema_for_column(column, enum_values)
            field_schema["title"] = snake_to_label(column.name)
            if column.references is not None:
                field_schema["description"] = (
                    f"Relationship to {column.references[0]}.{column.references[1]}"
                )
            properties[field_name] = field_schema
            if not column.nullable and not column.primary_key:
                required.append(field_name)

        component_schemas[class_name] = {
            "type": "object",
            "additionalProperties": False,
            "properties": properties,
        }
        if required:
            component_schemas[class_name]["required"] = required

        collection_path = f"/api/v1/{route_name}/"
        item_path = f"/api/v1/{route_name}/{{id}}"
        schema_ref = f"#/components/schemas/{class_name}"
        paths[collection_path] = {
            "get": {
                "tags": [table.name],
                "summary": f"List {tag_name}",
                "operationId": f"list{class_name}",
                "responses": {
                    "200": {
                        "description": f"{tag_name} list",
                        "content": {
                            "application/json": {
                                "schema": {"type": "array", "items": {"$ref": schema_ref}}
                            }
                        },
                    }
                },
            },
            "post": {
                "tags": [table.name],
                "summary": f"Create {tag_name}",
                "operationId": f"create{class_name}",
                "requestBody": {
                    "required": True,
                    "content": {"application/json": {"schema": {"$ref": schema_ref}}},
                },
                "responses": {
                    "201": {
                        "description": f"{tag_name} created",
                        "content": {"application/json": {"schema": {"$ref": schema_ref}}},
                    }
                },
            },
        }
        paths[item_path] = {
            "get": {
                "tags": [table.name],
                "summary": f"Get {tag_name}",
                "operationId": f"get{class_name}",
                "parameters": [_openapi_id_parameter()],
                "responses": {
                    "200": {
                        "description": f"{tag_name} detail",
                        "content": {"application/json": {"schema": {"$ref": schema_ref}}},
                    },
                    "404": {"description": "Not found"},
                },
            },
            "put": {
                "tags": [table.name],
                "summary": f"Update {tag_name}",
                "operationId": f"update{class_name}",
                "parameters": [_openapi_id_parameter()],
                "requestBody": {
                    "required": True,
                    "content": {"application/json": {"schema": {"$ref": schema_ref}}},
                },
                "responses": {
                    "200": {
                        "description": f"{tag_name} updated",
                        "content": {"application/json": {"schema": {"$ref": schema_ref}}},
                    },
                    "404": {"description": "Not found"},
                },
            },
            "delete": {
                "tags": [table.name],
                "summary": f"Delete {tag_name}",
                "operationId": f"delete{class_name}",
                "parameters": [_openapi_id_parameter()],
                "responses": {
                    "204": {"description": f"{tag_name} deleted"},
                    "404": {"description": "Not found"},
                },
            },
        }

    return {
        "openapi": "3.1.0",
        "info": {
            "title": f"{app_name} API",
            "version": "1.0.0",
            "description": "Generated AppGen REST API contract.",
        },
        "servers": [{"url": "/"}],
        "tags": tags,
        "paths": paths,
        "components": {
            "schemas": component_schemas,
            "securitySchemes": {
                "bearerAuth": {"type": "http", "scheme": "bearer", "bearerFormat": "JWT"}
            },
        },
        "security": [{"bearerAuth": []}],
    }


def _openapi_id_parameter() -> dict:
    return {
        "name": "id",
        "in": "path",
        "required": True,
        "schema": {"type": "integer"},
        "description": "Generated row identifier.",
    }


def _openapi_text(schema: AppSchema, app_name: str) -> str:
    spec = _openapi_spec(schema, app_name)
    return f'''"""Generated OpenAPI helpers for AppGen REST APIs."""

from __future__ import annotations

from copy import deepcopy

from flask import jsonify
from flask_appbuilder import BaseView
from flask_appbuilder import expose


OPENAPI_SPEC = {spec!r}


def openapi_spec():
    """Return the generated OpenAPI contract."""
    return deepcopy(OPENAPI_SPEC)


def schema_names():
    """Return generated component schema names."""
    return tuple(OPENAPI_SPEC["components"]["schemas"])


def path_summary():
    """Return generated API paths and HTTP methods."""
    return tuple(
        {{"path": path, "methods": tuple(sorted(operations))}}
        for path, operations in OPENAPI_SPEC["paths"].items()
    )


def operation_count():
    """Return the number of generated OpenAPI operations."""
    return sum(len(operations) for operations in OPENAPI_SPEC["paths"].values())


def openapi_check(existing_paths=()):
    """Return readiness for generated OpenAPI artifacts."""
    existing = set(existing_paths)
    required = {{
        "app/openapi.py",
        "app/templates/appgen_openapi.html",
        "docs/openapi.json",
    }}
    missing = tuple(sorted(required - existing))
    return {{
        "ok": not missing and OPENAPI_SPEC["openapi"] == "3.1.0" and operation_count() > 0,
        "missing": missing,
        "schemas": schema_names(),
        "operations": operation_count(),
    }}


def openapi_release_gate(existing_paths=()):
    """Return release readiness for generated OpenAPI contracts."""
    readiness = openapi_check(existing_paths)
    spec = openapi_spec()
    paths = spec.get("paths", {{}})
    schemas = spec.get("components", {{}}).get("schemas", {{}})
    operations = tuple(
        dict(operation, path=path, method=method)
        for path, methods in paths.items()
        for method, operation in methods.items()
    )
    security_schemes = spec.get("components", {{}}).get("securitySchemes", {{}})
    gates = (
        {{"gate": "artifacts", "ok": readiness["ok"], "missing": readiness["missing"]}},
        {{"gate": "openapi_version", "ok": spec.get("openapi") == "3.1.0" and bool(spec.get("info", {{}}).get("title")), "version": spec.get("openapi"), "info": spec.get("info", {{}})}},
        {{"gate": "path_catalog", "ok": bool(paths) and all(path.startswith("/api/v1/") for path in paths), "paths": path_summary()}},
        {{"gate": "operation_contracts", "ok": bool(operations) and all(operation.get("operationId") and operation.get("responses") for operation in operations), "operation_count": len(operations)}},
        {{"gate": "component_schemas", "ok": bool(schemas) and all(schema.get("type") == "object" and schema.get("properties") for schema in schemas.values()), "schemas": schema_names()}},
        {{"gate": "security_scheme", "ok": security_schemes.get("bearerAuth", {{}}).get("scheme") == "bearer" and bool(spec.get("security")), "security": security_schemes}},
    )
    ok = all(gate["ok"] for gate in gates)
    return {{
        "format": "appgen.openapi-release-gate.v1",
        "ok": ok,
        "decision": "approved" if ok else "blocked",
        "gates": gates,
    }}


def openapi_workbench(existing_paths=()):
    """Return generated OpenAPI evidence for API builders and SDK generators."""
    existing = set(existing_paths or ())
    required = {{"app/openapi.py", "app/templates/appgen_openapi.html", "docs/openapi.json"}}
    spec = openapi_spec()
    paths = spec.get("paths", {{}})
    schemas = spec.get("components", {{}}).get("schemas", {{}})
    operations = tuple(
        dict(operation, path=path, method=method)
        for path, methods in paths.items()
        for method, operation in methods.items()
    )
    security_schemes = spec.get("components", {{}}).get("securitySchemes", {{}})
    release = openapi_release_gate(existing)
    checks = (
        {{
            "id": "artifact_coverage",
            "ok": required.issubset(existing),
            "evidence": {{"required": tuple(sorted(required)), "missing": tuple(sorted(required - existing))}},
        }},
        {{
            "id": "openapi_version",
            "ok": spec.get("openapi") == "3.1.0" and bool(spec.get("info", {{}}).get("title")),
            "evidence": {{"version": spec.get("openapi"), "info": spec.get("info", {{}})}},
        }},
        {{
            "id": "path_catalog",
            "ok": bool(paths) and all(path.startswith("/api/v1/") for path in paths),
            "evidence": path_summary(),
        }},
        {{
            "id": "operation_contracts",
            "ok": bool(operations) and all(operation.get("operationId") and operation.get("responses") for operation in operations),
            "evidence": {{"operation_count": len(operations)}},
        }},
        {{
            "id": "component_schemas",
            "ok": bool(schemas) and all(schema.get("type") == "object" and schema.get("properties") for schema in schemas.values()),
            "evidence": schema_names(),
        }},
        {{
            "id": "security_scheme",
            "ok": security_schemes.get("bearerAuth", {{}}).get("scheme") == "bearer" and bool(spec.get("security")),
            "evidence": security_schemes,
        }},
        {{
            "id": "release_gate",
            "ok": release["ok"],
            "evidence": release["format"],
        }},
        {{
            "id": "route_surface",
            "ok": True,
            "evidence": {{"routes": ("/openapi/openapi.json", "/openapi/workbench.json", "/openapi/release-gate.json")}},
        }},
    )
    ok = all(check["ok"] for check in checks)
    return {{
        "format": "appgen.openapi-workbench.v1",
        "ok": ok,
        "decision": "approved" if ok else "blocked",
        "checks": checks,
        "paths": path_summary(),
        "schemas": schema_names(),
        "operations": operation_count(),
        "release_gate": release,
    }}


class OpenAPIView(BaseView):
    route_base = "/openapi"
    default_view = "index"

    @expose("/")
    def index(self):
        return self.render_template(
            "appgen_openapi.html",
            spec=OPENAPI_SPEC,
            paths=path_summary(),
            schemas=schema_names(),
            operation_count=operation_count(),
        )

    @expose("/openapi.json")
    def openapi_json(self):
        return jsonify(OPENAPI_SPEC)

    @expose("/workbench.json")
    def workbench_json(self):
        return jsonify(openapi_workbench({{"app/openapi.py", "docs/openapi.json", "app/templates/appgen_openapi.html"}}))

    @expose("/release-gate.json")
    def release_gate_json(self):
        return jsonify(openapi_release_gate({{"app/openapi.py", "docs/openapi.json", "app/templates/appgen_openapi.html"}}))


def register_openapi(appbuilder):
    appbuilder.add_view(
        OpenAPIView,
        "OpenAPI",
        icon="fa-code",
        category="AppGen",
    )
'''


