def _package_contract_text(schema: AppSchema, app_name: str) -> str:
    table_names = tuple(table.name for table in schema.tables)
    slug = _package_slug(app_name)
    return f'''"""Generated publishable package and FAB-extension contract."""

from __future__ import annotations

from pathlib import Path

APP_NAME = {app_name!r}
PACKAGE_NAME = "appgen-{slug}"
TABLES = {table_names!r}
REQUIRED_PACKAGE_PATHS = (
    "pyproject.toml",
    "MANIFEST.in",
    "README.md",
    "requirements.txt",
    "app/__init__.py",
    "app/appgen.json",
    "app/templates/my_index.html",
    "app_custom/extensions.py",
    "cookiecutter/cookiecutter.json",
    "cookiecutter/{{{{cookiecutter.project_slug}}}}/pyproject.toml",
    "cookiecutter/{{{{cookiecutter.project_slug}}}}/app/__init__.py",
)


def package_metadata():
    """Return publishable package metadata for this generated app."""
    return {{
        "app_name": APP_NAME,
        "package_name": PACKAGE_NAME,
        "tables": TABLES,
        "entry_point": "appgen-quality",
        "build_command": "python -m build",
        "publish_command": "python -m twine upload dist/*",
    }}


def fab_extension_contract():
    """Return the reusable Flask-AppBuilder extension surface."""
    return {{
        "module": "app",
        "factory": "app",
        "register_hook": "app.extensions.register_extensions",
        "custom_hooks": "app_custom.extensions",
        "templates": "app/templates",
        "static": "app/static",
    }}


def cookiecutter_context(extra=None):
    """Return default context for the generated Cookiecutter template."""
    context = {{
        "project_name": APP_NAME,
        "project_slug": PACKAGE_NAME.replace("-", "_"),
        "package_name": PACKAGE_NAME,
        "description": "Generated AppGen application template",
    }}
    if extra:
        context.update(extra)
    return context


def packaging_check(existing_paths):
    """Return readiness for build, publish, FAB extension, and Cookiecutter artifacts."""
    existing = set(existing_paths)
    missing = tuple(path for path in REQUIRED_PACKAGE_PATHS if path not in existing)
    return {{
        "ok": not missing,
        "missing": missing,
        "package": package_metadata(),
        "fab_extension": fab_extension_contract(),
        "cookiecutter": cookiecutter_context(),
    }}


def packaging_release_gate(existing_paths=()):
    """Return release readiness for generated packaging and template artifacts."""
    readiness = packaging_check(existing_paths)
    package = package_metadata()
    extension = fab_extension_contract()
    cookiecutter = cookiecutter_context()
    gates = (
        {{"gate": "artifacts", "ok": readiness["ok"], "missing": readiness["missing"]}},
        {{"gate": "build_metadata", "ok": package["package_name"].startswith("appgen-") and package["build_command"] == "python -m build" and package["entry_point"] == "appgen-quality", "package": package}},
        {{"gate": "publish_metadata", "ok": package["publish_command"].startswith("python -m twine upload") and bool(package["tables"]), "package": package}},
        {{"gate": "fab_extension", "ok": extension["module"] == "app" and extension["custom_hooks"] == "app_custom.extensions" and extension["templates"] == "app/templates", "extension": extension}},
        {{"gate": "cookiecutter_template", "ok": cookiecutter["project_slug"].startswith("appgen_") and cookiecutter["package_name"] == PACKAGE_NAME and "project_name" in cookiecutter, "cookiecutter": cookiecutter}},
        {{"gate": "quality_entrypoint", "ok": package["entry_point"] == "appgen-quality", "command": "quality_command"}},
    )
    ok = all(gate["ok"] for gate in gates)
    return {{
        "format": "appgen.packaging-release-gate.v1",
        "ok": ok,
        "decision": "approved" if ok else "blocked",
        "gates": gates,
    }}


def packaging_workbench(existing_paths=()):
    """Return generated packaging evidence for publishable app templates."""
    existing = set(existing_paths or ())
    required = set(REQUIRED_PACKAGE_PATHS)
    package = package_metadata()
    extension = fab_extension_contract()
    cookiecutter = cookiecutter_context()
    release = packaging_release_gate(existing)
    checks = (
        {{
            "id": "artifact_coverage",
            "ok": required.issubset(existing),
            "evidence": {{"required": tuple(REQUIRED_PACKAGE_PATHS), "missing": tuple(path for path in REQUIRED_PACKAGE_PATHS if path not in existing)}},
        }},
        {{
            "id": "package_metadata",
            "ok": package["package_name"].startswith("appgen-") and package["tables"],
            "evidence": package,
        }},
        {{
            "id": "build_command",
            "ok": package["build_command"] == "python -m build",
            "evidence": package["build_command"],
        }},
        {{
            "id": "publish_metadata",
            "ok": package["publish_command"].startswith("python -m twine upload"),
            "evidence": package["publish_command"],
        }},
        {{
            "id": "fab_extension",
            "ok": extension["module"] == "app" and extension["custom_hooks"] == "app_custom.extensions",
            "evidence": extension,
        }},
        {{
            "id": "cookiecutter_template",
            "ok": cookiecutter["project_slug"].startswith("appgen_") and cookiecutter["package_name"] == PACKAGE_NAME,
            "evidence": cookiecutter,
        }},
        {{
            "id": "quality_entrypoint",
            "ok": package["entry_point"] == "appgen-quality",
            "evidence": package["entry_point"],
        }},
        {{
            "id": "release_gate",
            "ok": release["ok"],
            "evidence": release["format"],
        }},
    )
    ok = all(check["ok"] for check in checks)
    return {{
        "format": "appgen.packaging-workbench.v1",
        "ok": ok,
        "decision": "approved" if ok else "blocked",
        "checks": checks,
        "package": package,
        "fab_extension": extension,
        "cookiecutter": cookiecutter,
        "release_gate": release,
    }}


def quality_command():
    """Flask CLI entry point that runs the generated quality gate."""
    import subprocess
    import sys

    script = Path(__file__).resolve().parent / "scripts" / "appgen_quality.py"
    raise SystemExit(subprocess.call([sys.executable, str(script)]))
'''


