def runtime_assurance_matrix():
    """Return the generated runtime assurance areas and expected artifacts."""
    return ASSURANCE_AREAS


def _check_signal(name, signals):
    if name == "latency_slo":
        return float(signals.get("p95_ms", 0)) <= DEFAULT_SLO["p95_ms"]
    if name == "error_rate_slo":
        return float(signals.get("error_rate", 0)) <= DEFAULT_SLO["error_rate"]
    return bool(signals.get(name, False))


def runtime_assurance_report(signals=None):
    """Return an auditable readiness report for the generated app."""
    signals = dict(DEFAULT_SIGNALS if signals is None else {{**DEFAULT_SIGNALS, **signals}})
    areas = []
    for area in ASSURANCE_AREAS:
        checks = tuple(
            {{"name": check, "ok": _check_signal(check, signals)}}
            for check in area["checks"]
        )
        areas.append({{
            "id": area["id"],
            "label": area["label"],
            "ok": all(check["ok"] for check in checks),
            "checks": checks,
            "artifacts": area["artifacts"],
        }})
    return {{
        "format": "appgen.runtime-assurance.v1",
        "app": APP_NAME,
        "ok": all(area["ok"] for area in areas),
        "tables": TABLE_COUNT,
        "flows": FLOW_COUNT,
        "roles": ROLE_COUNT,
        "slo": DEFAULT_SLO,
        "areas": tuple(areas),
    }}


def runtime_assurance_check(existing_paths=()):
    """Return readiness for the generated runtime assurance artifact set."""
    existing = set(existing_paths)
    missing = tuple(path for path in REQUIRED_ARTIFACTS if path not in existing)
    report = runtime_assurance_report({{"required_artifacts": not missing}})
    return {{
        "ok": not missing and report["ok"],
        "missing": missing,
        "areas": tuple(area["id"] for area in report["areas"]),
        "required": REQUIRED_ARTIFACTS,
    }}


def _release_check_signal(name, signals):
    if name == "performance_slo":
        return bool(signals.get(name, False)) and _check_signal("latency_slo", signals) and _check_signal("error_rate_slo", signals)
    return bool(signals.get(name, False))


def application_release_gate(signals=None, existing_paths=()):
    """Return the generated release gate for a complete, shippable app."""
    signals = dict(DEFAULT_RELEASE_SIGNALS if signals is None else {{**DEFAULT_RELEASE_SIGNALS, **signals}})
    existing = set(existing_paths)
    missing = tuple(path for path in REQUIRED_RELEASE_ARTIFACTS if path not in existing)
    areas = []
    for area in RELEASE_GATE_AREAS:
        checks = tuple(
            {{"name": check, "ok": _release_check_signal(check, signals)}}
            for check in area["checks"]
        )
        area_missing = tuple(path for path in area["artifacts"] if path in missing)
        areas.append({{
            "id": area["id"],
            "label": area["label"],
            "ok": all(check["ok"] for check in checks) and not area_missing,
            "checks": checks,
            "artifacts": area["artifacts"],
            "missing_artifacts": area_missing,
        }})
    blockers = tuple(
        {{"area": area["id"], "kind": "check", "check": check["name"]}}
        for area in areas
        for check in area["checks"]
        if not check["ok"]
    ) + tuple({{"area": "artifacts", "kind": "missing", "path": path}} for path in missing)
    assurance = runtime_assurance_report({{
        "p95_ms": signals.get("p95_ms", 0),
        "error_rate": signals.get("error_rate", 0),
        "required_artifacts": not missing,
        "quality_gate": signals.get("quality_gate", True),
    }})
    return {{
        "format": "appgen.application-release-gate.v1",
        "app": APP_NAME,
        "ok": all(area["ok"] for area in areas) and assurance["ok"] and not blockers,
        "decision": "approved" if all(area["ok"] for area in areas) and assurance["ok"] and not blockers else "blocked",
        "tables": TABLE_COUNT,
        "flows": FLOW_COUNT,
        "roles": ROLE_COUNT,
        "areas": tuple(areas),
        "runtime_assurance": assurance,
        "required_artifacts": REQUIRED_RELEASE_ARTIFACTS,
        "missing_artifacts": missing,
        "blockers": blockers,
    }}


def generated_app_excellence_gate(signals=None, existing_paths=()):
    """Return a product-level gate for beautiful, secure, robust generated apps."""
    release = application_release_gate(signals, existing_paths)
    signal_values = dict(DEFAULT_RELEASE_SIGNALS if signals is None else {{**DEFAULT_RELEASE_SIGNALS, **signals}})
    release_by_id = {{area["id"]: area for area in release["areas"]}}
    categories = []
    for category in EXCELLENCE_CATEGORIES:
        checks = tuple(
            {{"name": check, "ok": _release_check_signal(check, signal_values)}}
            for check in category["checks"]
        )
        release_area = release_by_id.get(category["release_area"], {{"ok": False}})
        categories.append({{
            "id": category["id"],
            "label": category["label"],
            "ok": all(check["ok"] for check in checks) and bool(release_area.get("ok", False)),
            "checks": checks,
            "release_area": category["release_area"],
        }})
    blockers = tuple(
        {{"category": category["id"], "kind": "check", "check": check["name"]}}
        for category in categories
        for check in category["checks"]
        if not check["ok"]
    ) + tuple({{"category": "release", **blocker}} for blocker in release["blockers"])
    return {{
        "format": "appgen.generated-app-excellence-gate.v1",
        "app": APP_NAME,
        "ok": release["ok"] and all(category["ok"] for category in categories) and not blockers,
        "decision": "approved" if release["ok"] and all(category["ok"] for category in categories) and not blockers else "blocked",
        "categories": tuple(categories),
        "application_release_gate": release,
        "blockers": blockers,
    }}


def runtime_assurance_workbench(signals=None, existing_paths=()):
    """Return IDE-ready assurance, release, and excellence evidence."""
    existing = set(existing_paths)
    matrix = runtime_assurance_matrix()
    report = runtime_assurance_report(signals)
    artifact_check = runtime_assurance_check(existing)
    release_gate = application_release_gate(signals, existing)
    excellence_gate = generated_app_excellence_gate(signals, existing)
