def _component_for_column(column: ColumnSchema) -> str:
    normalized = column.type_name.lower().split("(", 1)[0]
    if column.references:
        return "RelationshipPicker"
    if normalized in {"text", "longtext", "textarea"}:
        return "TextArea"
    if normalized in {"image", "photo", "picture"}:
        return "ImageUpload"
    if normalized in {"file", "upload", "document", "attachment", "blob", "binary", "bytea"}:
        return "FileUpload"
    if normalized in {"bool", "boolean"}:
        return "Checkbox"
    if normalized in {"datetime", "timestamp", "timestamptz"}:
        return "DateTimePicker"
    if normalized == "time":
        return "TimePicker"
    if "date" in normalized:
        return "DatePicker"
    if normalized in {"int", "integer", "bigint", "float", "decimal", "numeric", "money"}:
        return "NumberInput"
    return "TextBox"


def _validation_text(schema: AppSchema) -> str:
    enums = {enum.name: tuple(enum.values) for enum in schema.enums}
    tables = {
        table.name: {
            "name": table.name,
            "label": snake_to_label(table.name),
            "fields": tuple(
                {
                    "name": column.name,
                    "attribute": _model_attribute_name(column),
                    "label": snake_to_label(column.name),
                    "type": column.type_name,
                    "required": not column.nullable and not column.primary_key and not column.derived,
                    "primary_key": column.primary_key,
                    "unique": column.unique,
                    "reference": column.references,
                    "hidden": column.hidden,
                    "searchable": column.searchable,
                    "derived": column.derived,
                    "enum_values": enums.get(column.type_name, ()),
                    "ui_component": "Select" if column.type_name in enums else _component_for_column(column),
                }
                for column in table.columns
            ),
        }
        for table in schema.tables
    }
    return f'''"""Generated schema-driven validation contracts for AppGen apps."""

from __future__ import annotations


ENUMS = {enums!r}
VALIDATION_TABLES = {tables!r}


def validation_catalog():
    """Return validation contracts for every generated table."""
    return tuple(VALIDATION_TABLES.values())


def table_validation_contract(table_name):
    """Return one table validation contract."""
    if table_name not in VALIDATION_TABLES:
        raise KeyError(table_name)
    return VALIDATION_TABLES[table_name]


def field_validation_contract(table_name, field_name):
    """Return one field validation contract by source column or model attribute."""
    table = table_validation_contract(table_name)
    for field in table["fields"]:
        if field["name"] == field_name or field["attribute"] == field_name:
            return field
    raise KeyError(f"{{table_name}}.{{field_name}}")


def _blank(value):
    return value is None or value == ""


def _normalized_type(type_name):
    return str(type_name or "").lower().split("(", 1)[0].strip()


def _type_ok(type_name, value):
    if _blank(value):
        return True
    normalized = _normalized_type(type_name)
    if normalized in {{"int", "integer", "serial", "smallint", "bigint", "bigserial"}}:
        return isinstance(value, int) and not isinstance(value, bool)
    if normalized in {{"float", "real", "double", "double precision", "decimal", "numeric", "money"}}:
        return isinstance(value, (int, float)) and not isinstance(value, bool)
    if normalized in {{"bool", "boolean"}}:
        return isinstance(value, bool)
    if normalized.endswith("[]"):
        return isinstance(value, (list, tuple))
    return True


def validate_field(table_name, field_name, value):
    """Validate one field value against generated schema constraints."""
    field = field_validation_contract(table_name, field_name)
    errors = []
    if field["required"] and _blank(value):
        errors.append({{"field": field["attribute"], "code": "required", "message": f"{{field['label']}} is required"}})
    if not _type_ok(field["type"], value):
        errors.append({{"field": field["attribute"], "code": "type", "message": f"{{field['label']}} must be {{field['type']}}"}})
    if field["enum_values"] and not _blank(value) and value not in field["enum_values"]:
        errors.append({{"field": field["attribute"], "code": "enum", "message": f"{{field['label']}} must be one of {{', '.join(field['enum_values'])}}"}})
    return {{"ok": not errors, "field": field, "errors": tuple(errors)}}


def validate_payload(table_name, payload, *, partial=False):
    """Validate a row or mutation payload before API, form, import, or chatbot writes."""
    payload = dict(payload or {{}})
    table = table_validation_contract(table_name)
    errors = []
    warnings = []
    known = {{field["attribute"] for field in table["fields"]}} | {{field["name"] for field in table["fields"]}}
    unknown = tuple(sorted(key for key in payload if key not in known))
    for key in unknown:
        warnings.append({{"field": key, "code": "unknown_field", "message": f"Unknown field: {{key}}"}})
    for field in table["fields"]:
        if field["primary_key"] or field["derived"]:
            continue
        present = field["attribute"] in payload or field["name"] in payload
        value = payload.get(field["attribute"], payload.get(field["name"]))
        if partial and not present:
            continue
        result = validate_field(table_name, field["attribute"], value)
        errors.extend(result["errors"])
    return {{
        "format": "appgen.validation-result.v1",
        "table": table_name,
        "ok": not errors,
        "errors": tuple(errors),
        "warnings": tuple(warnings),
    }}


def ui_validation_schema(table_name):
    """Return UI-friendly validation metadata for generated form designers."""
    table = table_validation_contract(table_name)
    return {{
        "format": "appgen.ui-validation.v1",
        "table": table_name,
        "fields": tuple(
            {{
                "name": field["attribute"],
                "label": field["label"],
                "required": field["required"],
                "component": field["ui_component"],
                "enum_values": field["enum_values"],
                "reference": field["reference"],
            }}
            for field in table["fields"]
            if not field["hidden"] and not field["derived"]
        ),
    }}


def validation_check(existing_paths):
    """Return readiness for generated validation artifacts."""
    existing = set(existing_paths)
    required = ("app/validation.py",)
    missing = tuple(path for path in required if path not in existing)
    return {{
        "ok": not missing and bool(VALIDATION_TABLES),
        "missing": missing,
        "tables": tuple(VALIDATION_TABLES),
    }}


def _sample_value(field):
    if field["enum_values"]:
        return field["enum_values"][0]
    normalized = _normalized_type(field["type"])
    if normalized in {{"int", "integer", "serial", "smallint", "bigint", "bigserial"}}:
        return 1
    if normalized in {{"float", "real", "double", "double precision", "decimal", "numeric", "money"}}:
        return 1.5
    if normalized in {{"bool", "boolean"}}:
        return True
    if normalized.endswith("[]"):
        return ("sample",)
    return f"sample_{{field['attribute']}}"


def _valid_payload(table_name):
    table = table_validation_contract(table_name)
    return {{
        field["attribute"]: _sample_value(field)
        for field in table["fields"]
        if not field["primary_key"] and not field["derived"] and not field["hidden"]
    }}


def _type_probe(field):
    normalized = _normalized_type(field["type"])
    if normalized in {{"int", "integer", "serial", "smallint", "bigint", "bigserial", "float", "real", "double", "double precision", "decimal", "numeric", "money"}}:
        return "not-a-number"
    if normalized in {{"bool", "boolean"}}:
        return "not-a-bool"
    if normalized.endswith("[]"):
        return "not-an-array"
    return None


def validation_release_gate(existing_paths=()):
    """Return release readiness for generated schema validation contracts."""
    readiness = validation_check(existing_paths)
    table_checks = []
    enum_checks = []
    type_checks = []
    for table in validation_catalog():
        table_name = table["name"]
        payload = _valid_payload(table_name)
        valid = validate_payload(table_name, payload)
        missing_required = validate_payload(table_name, {{}})
        partial = validate_payload(table_name, {{}}, partial=True)
        ui_schema = ui_validation_schema(table_name)
        table_checks.append({{
            "table": table_name,
            "valid_payload_ok": valid["ok"],
            "required_errors_ok": bool(missing_required["errors"]) or not any(field["required"] for field in table["fields"]),
            "partial_update_ok": partial["ok"],
            "ui_schema_ok": ui_schema["format"] == "appgen.ui-validation.v1" and all(field["name"] for field in ui_schema["fields"]),
        }})
        for field in table["fields"]:
            if field["enum_values"]:
                invalid_enum = validate_field(table_name, field["attribute"], "__invalid_enum__")
                enum_checks.append({{
                    "table": table_name,
                    "field": field["attribute"],
                    "ok": any(error["code"] == "enum" for error in invalid_enum["errors"]),
                }})
            probe = _type_probe(field)
            if probe is not None:
                invalid_type = validate_field(table_name, field["attribute"], probe)
                type_checks.append({{
                    "table": table_name,
                    "field": field["attribute"],
                    "ok": any(error["code"] == "type" for error in invalid_type["errors"]),
                }})
    checks = (
        {{"gate": "artifacts", "ok": readiness["ok"], "missing": readiness["missing"]}},
        {{"gate": "table_contracts", "ok": bool(table_checks) and all(item["valid_payload_ok"] and item["required_errors_ok"] and item["partial_update_ok"] and item["ui_schema_ok"] for item in table_checks), "checks": tuple(table_checks)}},
        {{"gate": "enum_contracts", "ok": not enum_checks or all(item["ok"] for item in enum_checks), "checks": tuple(enum_checks)}},
        {{"gate": "type_contracts", "ok": not type_checks or all(item["ok"] for item in type_checks), "checks": tuple(type_checks)}},
    )
    ok = all(check["ok"] for check in checks)
    return {{
        "format": "appgen.validation-release-gate.v1",
        "ok": ok,
        "decision": "approved" if ok else "blocked",
        "checks": checks,
    }}
'''


def _babel_config_text() -> str:
    return """[python: **.py]
[jinja2: app/templates/**.html]
extensions=jinja2.ext.autoescape,jinja2.ext.with_
"""


def _messages_po_text(schema: AppSchema, app_name: str) -> str:
    labels = _translation_labels(schema, app_name)
    lines = [
        'msgid ""',
        'msgstr ""',
        '"Project-Id-Version: AppGen Generated App\\n"',
        '"Language: en\\n"',
        '"Content-Type: text/plain; charset=UTF-8\\n"',
        "",
    ]
    for label in labels:
        escaped = label.replace('"', '\\"')
        lines.extend([f'msgid "{escaped}"', f'msgstr "{escaped}"', ""])
    return "\n".join(lines)


def _translation_labels(schema: AppSchema, app_name: str) -> tuple[str, ...]:
    labels = {
        app_name,
        "Reports",
        "Backups",
        "Configuration",
        "Workflows",
        "Designer",
    }
    for table in schema.tables:
        labels.add(snake_to_label(table.name))
        for column in table.columns:
            labels.add(snake_to_label(column.name))
    for flow in schema.flows:
        labels.add(flow.name)
        for step in flow.steps:
            labels.add(step.source)
            labels.add(step.target)
    for role in schema.roles:
        labels.add(role.name)
    return tuple(sorted(labels))


def _i18n_text(schema: AppSchema, app_name: str) -> str:
    labels = _translation_labels(schema, app_name)
    catalog = {
        "en": {label: label for label in labels},
        "es": {},
        "fr": {},
    }
    locales = {
        "en": {"locale": "en", "label": "English", "direction": "ltr"},
        "es": {"locale": "es", "label": "Spanish", "direction": "ltr"},
        "fr": {"locale": "fr", "label": "French", "direction": "ltr"},
    }
    return f'''"""Generated localization helpers for AppGen apps."""

from __future__ import annotations

import re
from pathlib import Path

from flask import jsonify
from flask import request
from flask_appbuilder import BaseView
from flask_appbuilder import expose


DEFAULT_LOCALE = "en"
LOCALES = {locales!r}
TRANSLATIONS = {catalog!r}


def locale_catalog():
    """Return supported locale metadata and sample translation keys."""
    return tuple(
        {{
            **locale,
            "sample_keys": tuple(list(TRANSLATIONS[locale_key])[:5]),
            "translation_count": len(TRANSLATIONS[locale_key]),
        }}
        for locale_key, locale in LOCALES.items()
    )


def translation_catalog(locale=DEFAULT_LOCALE):
    """Return one generated translation catalog."""
    return dict(TRANSLATIONS.get(locale) or TRANSLATIONS[DEFAULT_LOCALE])


def translate(message_id, locale=DEFAULT_LOCALE, fallback_locale=DEFAULT_LOCALE):
    """Translate a generated label with deterministic fallback."""
    key = str(message_id)
    selected = TRANSLATIONS.get(locale, {{}})
    if key in selected:
        return selected[key]
    fallback = TRANSLATIONS.get(fallback_locale, {{}})
    return fallback.get(key, key)


def negotiate_locale(accept_language="", supported=None, default=DEFAULT_LOCALE):
    """Choose the best generated locale from an Accept-Language-style header."""
    supported_locales = tuple(supported or LOCALES)
    header = str(accept_language or "")
    for part in header.split(","):
        candidate = part.split(";", 1)[0].strip().casefold()
        if not candidate:
            continue
        direct = candidate.replace("_", "-")
        short = direct.split("-", 1)[0]
        if direct in supported_locales:
            return direct
        if short in supported_locales:
            return short
    return default if default in supported_locales else supported_locales[0]


def missing_translation_report(locales=None):
    """Return missing translation keys by locale."""
    selected = tuple(locales or LOCALES)
    source_keys = set(TRANSLATIONS[DEFAULT_LOCALE])
    missing = {{}}
    for locale in selected:
        if locale == DEFAULT_LOCALE:
            continue
        keys = set(TRANSLATIONS.get(locale, {{}}))
        missing[locale] = tuple(sorted(source_keys - keys))
    return {{
        "format": "appgen.i18n-missing.v1",
        "default_locale": DEFAULT_LOCALE,
        "locales": selected,
        "missing": missing,
        "complete": all(not values for values in missing.values()),
    }}


def translation_payload(locale=DEFAULT_LOCALE):
    """Return a runtime payload for UI and generated frontend translation bootstraps."""
    negotiated = negotiate_locale(locale)
    return {{
        "format": "appgen.i18n-payload.v1",
        "locale": negotiated,
        "direction": LOCALES[negotiated]["direction"],
        "translations": translation_catalog(negotiated),
        "fallback_locale": DEFAULT_LOCALE,
    }}


def i18n_check(existing_paths=()):
    """Return readiness for generated localization artifacts."""
    existing = set(existing_paths)
    required = {{
        "babel.cfg",
        "app/i18n.py",
        "app/templates/appgen_i18n.html",
        "app/translations/en/LC_MESSAGES/messages.po",
    }}
    missing = tuple(sorted(required - existing))
    return {{
        "ok": not missing and DEFAULT_LOCALE in TRANSLATIONS and bool(TRANSLATIONS[DEFAULT_LOCALE]),
        "missing": missing,
        "locales": tuple(LOCALES),
        "default_locale": DEFAULT_LOCALE,
        "translation_count": len(TRANSLATIONS[DEFAULT_LOCALE]),
    }}


def i18n_release_gate(existing_paths=()):
    """Return deterministic release evidence for generated localization readiness."""
    existing = set(existing_paths)
    required = {{
        "babel.cfg",
        "app/i18n.py",
        "app/templates/appgen_i18n.html",
        "app/translations/en/LC_MESSAGES/messages.po",
    }}
    default_catalog = translation_catalog(DEFAULT_LOCALE)
    missing_report = missing_translation_report()
    sample_key = next(iter(default_catalog), "")
    es_payload = translation_payload("es")
    negotiated = negotiate_locale("fr-CA,fr;q=0.9,en;q=0.8")
    checks = (
        {{
            "gate": "artifact_coverage",
            "ok": required.issubset(existing),
            "required": tuple(sorted(required)),
            "missing": tuple(sorted(required - existing)),
        }},
        {{
            "gate": "locale_catalog",
            "ok": DEFAULT_LOCALE in LOCALES
            and bool(LOCALES)
            and all(locale.get("locale") and locale.get("label") and locale.get("direction") in {{"ltr", "rtl"}} for locale in LOCALES.values()),
            "locales": tuple(LOCALES),
        }},
        {{
            "gate": "default_catalog",
            "ok": bool(default_catalog) and all(key == value for key, value in default_catalog.items()),
            "translation_count": len(default_catalog),
        }},
        {{
            "gate": "fallback_translation",
            "ok": bool(sample_key)
            and translate(sample_key, locale="es") == default_catalog[sample_key]
            and translate("__missing__", locale="es") == "__missing__",
            "fallback_locale": DEFAULT_LOCALE,
        }},
        {{
            "gate": "locale_negotiation",
            "ok": negotiated == "fr" and negotiate_locale("zz-ZZ") == DEFAULT_LOCALE,
            "sample": negotiated,
        }},
        {{
            "gate": "missing_key_report",
            "ok": missing_report["format"] == "appgen.i18n-missing.v1"
            and DEFAULT_LOCALE == missing_report["default_locale"]
            and all(locale in missing_report["missing"] for locale in LOCALES if locale != DEFAULT_LOCALE),
            "complete": missing_report["complete"],
        }},
        {{
            "gate": "runtime_payload",
            "ok": es_payload["format"] == "appgen.i18n-payload.v1"
            and es_payload["fallback_locale"] == DEFAULT_LOCALE
            and es_payload["direction"] in {{"ltr", "rtl"}}
            and isinstance(es_payload["translations"], dict),
            "locale": es_payload["locale"],
        }},
    )
    return {{
        "format": "appgen.i18n-release-gate.v1",
        "ok": all(check["ok"] for check in checks),
        "checks": checks,
    }}


def i18n_workbench(existing_paths=()):
    """Return an IDE-ready localization design and readiness workbench."""
    default_catalog = translation_catalog(DEFAULT_LOCALE)
    sample_key = next(iter(default_catalog), "")
    missing_report = missing_translation_report()
    payload = translation_payload("fr-CA,fr;q=0.9,en;q=0.8")
    release = i18n_release_gate(existing_paths)
    routes = (
        "/localization/catalog.json",
        "/localization/missing.json",
        "/localization/workbench.json",
        "/localization/release-gate.json",
    )
    checks = (
        {{
            "id": "locale_catalog",
            "ok": DEFAULT_LOCALE in LOCALES and len(locale_catalog()) >= 3,
            "evidence": {{"locales": locale_catalog()}},
        }},
        {{
            "id": "default_catalog",
            "ok": bool(default_catalog) and sample_key in default_catalog,
            "evidence": {{"sample_key": sample_key, "translation_count": len(default_catalog)}},
        }},
        {{
            "id": "fallback_translation",
            "ok": bool(sample_key) and translate(sample_key, locale="es") == default_catalog[sample_key] and translate("__missing__", locale="es") == "__missing__",
            "evidence": {{"fallback_locale": DEFAULT_LOCALE, "sample_key": sample_key}},
        }},
        {{
            "id": "locale_negotiation",
            "ok": payload["locale"] == "fr" and negotiate_locale("zz-ZZ") == DEFAULT_LOCALE,
            "evidence": payload,
        }},
        {{
            "id": "missing_key_report",
            "ok": missing_report["format"] == "appgen.i18n-missing.v1" and all(locale in missing_report["missing"] for locale in LOCALES if locale != DEFAULT_LOCALE),
            "evidence": missing_report,
        }},
        {{
            "id": "artifact_evidence",
            "ok": release["ok"],
            "evidence": {{"blocking_gates": tuple(check["gate"] for check in release["checks"] if not check["ok"])}},
        }},
        {{
            "id": "route_surface",
            "ok": all(route.startswith("/localization/") for route in routes),
            "evidence": {{"routes": routes}},
        }},
    )
    ok = all(check["ok"] for check in checks)
    return {{
        "format": "appgen.i18n-workbench.v1",
        "ok": ok,
        "decision": "approved" if ok else "blocked",
        "locales": locale_catalog(),
        "missing_report": missing_report,
        "payload": payload,
        "release_gate": release,
        "checks": checks,
    }}


class LocalizationView(BaseView):
    route_base = "/localization"
    default_view = "index"

    @expose("/")
    def index(self):
        return self.render_template("appgen_i18n.html", locales=locale_catalog())

    @expose("/catalog.json")
    def catalog_json(self):
        locale = negotiate_locale(request.headers.get("Accept-Language", ""))
        return jsonify(translation_payload(locale))

    @expose("/missing.json")
    def missing_json(self):
        return jsonify(missing_translation_report())

    @expose("/workbench.json")
    def workbench_json(self):
        return jsonify(i18n_workbench({{"babel.cfg", "app/i18n.py", "app/templates/appgen_i18n.html", "app/translations/en/LC_MESSAGES/messages.po"}}))

    @expose("/release-gate.json")
    def release_gate_json(self):
        return jsonify(i18n_release_gate({{"babel.cfg", "app/i18n.py", "app/templates/appgen_i18n.html", "app/translations/en/LC_MESSAGES/messages.po"}}))


def register_i18n(appbuilder):
    appbuilder.add_view(
        LocalizationView,
        "Localization",
        icon="fa-language",
        category="AppGen",
    )
'''


def _pwa_manifest_text(app_name: str, branding: dict) -> str:
    palette = branding["palette"]
    manifest = {
        "name": app_name,
        "short_name": app_name[:24],
        "description": "Generated AppGen application shell",
        "start_url": "/",
        "scope": "/",
        "display": "standalone",
        "background_color": palette["surface"],
        "theme_color": palette["primary"],
        "icons": [
            {
                "src": "/static/appgen-icon.svg",
                "sizes": "any",
                "type": "image/svg+xml",
                "purpose": "any maskable",
            }
        ],
    }
    return json.dumps(manifest, indent=2, sort_keys=True) + "\n"


def _service_worker_text() -> str:
    return """const APPGEN_CACHE = "appgen-shell-v1";
const APPGEN_ASSETS = [
  "/",
  "/static/appgen.webmanifest",
  "/static/appgen-icon.svg",
  "/static/appgen-theme.css",
  "/static/appgen-offline.html"
];

self.addEventListener("install", (event) => {
  event.waitUntil(
    caches.open(APPGEN_CACHE).then((cache) => cache.addAll(APPGEN_ASSETS))
  );
  self.skipWaiting();
});

self.addEventListener("activate", (event) => {
  event.waitUntil(
    caches.keys().then((keys) =>
      Promise.all(keys.filter((key) => key !== APPGEN_CACHE).map((key) => caches.delete(key)))
    )
  );
  self.clients.claim();
});

self.addEventListener("fetch", (event) => {
  if (event.request.method !== "GET") {
    return;
  }
  event.respondWith(
    fetch(event.request)
      .then((response) => {
        const copy = response.clone();
        caches.open(APPGEN_CACHE).then((cache) => cache.put(event.request, copy));
        return response;
      })
      .catch(() => caches.match(event.request).then((cached) => cached || caches.match("/static/appgen-offline.html")))
  );
});
"""


