def _focus_ring_value(primary: str) -> str:
    color = primary.lstrip("#")
    if len(color) == 6:
        try:
            red = int(color[0:2], 16)
            green = int(color[2:4], 16)
            blue = int(color[4:6], 16)
            return f"0 0 0 3px rgba({red}, {green}, {blue}, 0.28)"
        except ValueError:
            pass
    return "0 0 0 3px rgba(47, 111, 94, 0.28)"


