def context_menu_for(surface):
    """Return one generated context menu by surface name."""
    menu = next((item for item in context_menu_catalog() if item["surface"] == surface), None)
    if menu is None:
        raise KeyError(f"Unknown context menu surface: {{surface}}")
    return menu


def context_menu_action_plan(surface, action_id, payload=None):
    """Return a reviewed action plan for one right-click menu command."""
    menu = context_menu_for(surface)
    action = next((item for item in menu["actions"] if item["id"] == action_id), None)
    if action is None:
        raise KeyError(f"Unknown context menu action: {{surface}}.{{action_id}}")
    return {{
        "format": "appgen.context-menu-action-plan.v1",
        "surface": surface,
        "action": action,
        "payload": dict(payload or {{}}),
        "requires_review": bool(action["requires_review"]),
        "side_effect": action["side_effect"],
    }}


def ui_customization_workbench(existing_paths=None):
    """Return splash, menu, context-menu, and fine-tuning evidence for generated UI."""
    existing = set(existing_paths or ())
    required_assets = ("app/branding.py", "app/static/appgen-theme.css", "app/templates/appgen_branding.html")
    missing_assets = tuple(path for path in required_assets if path not in existing) if existing_paths is not None else ()
    splash = splash_screen_contract()
    menus = menu_catalog()
    menu_schema = menu_edit_schema()
    valid_menu_plan = menu_edit_plan((
        {{"menu": "primary", "item": "reports", "operation": "update", "fields": ("label", "order"), "route": "/reports/"}},
    ))
    invalid_menu_plan = menu_edit_plan((
        {{"menu": "primary", "item": "external", "operation": "update", "fields": ("label", "unsafe"), "route": "http://example.test"}},
    ))
    context_menus = context_menu_catalog()
    reviewed_actions = tuple(
        context_menu_action_plan(item["surface"], next(action["id"] for action in item["actions"] if action["requires_review"]))
        for item in context_menus
        if any(action["requires_review"] for action in item["actions"])
    )
    checks = (
        {{"id": "artifact_coverage", "ok": not missing_assets, "evidence": {{"required": required_assets, "missing": missing_assets}}}},
        {{"id": "splash_screen", "ok": splash["min_duration_ms"] < splash["max_duration_ms"] and "reduced_motion" in splash["motion"], "evidence": splash}},
        {{"id": "editable_menus", "ok": bool(menus) and all(item["items"] for item in menus) and menu_schema["review_required"], "evidence": menus}},
        {{"id": "menu_edit_guards", "ok": valid_menu_plan["ok"] and not invalid_menu_plan["ok"] and invalid_menu_plan["violations"], "evidence": {{"valid": valid_menu_plan, "invalid": invalid_menu_plan}}}},
        {{"id": "context_menus", "ok": bool(context_menus) and all(item["trigger"] == "contextmenu" and item["actions"] for item in context_menus), "evidence": context_menus}},
        {{"id": "reviewed_actions", "ok": bool(reviewed_actions) and all(item["requires_review"] for item in reviewed_actions), "evidence": reviewed_actions}},
        {{"id": "fine_tuning", "ok": bool(design_tokens()) and bool(component_state_matrix()) and bool(viewport_contract()), "evidence": ("design_tokens", "component_state_matrix", "viewport_contract", "layout_contract")}},
        {{"id": "route_surface", "ok": True, "evidence": {{"routes": ("/branding/splash.json", "/branding/menus.json", "/branding/context-menus.json", "/branding/ui-customization-workbench.json")}}}},
    )
    ok = all(check["ok"] for check in checks)
    return {{
        "format": "appgen.ui-customization-workbench.v1",
        "ok": ok,
        "decision": "approved" if ok else "blocked",
        "checks": checks,
        "splash": splash,
        "menus": menus,
        "menu_edit_schema": menu_schema,
        "context_menus": context_menus,
        "fine_tuning": {{
            "tokens": design_tokens(),
            "layouts": layout_contract(),
            "states": component_state_matrix(),
            "viewports": viewport_contract(),
        }},
    }}


def _load_generated_module(path, name):
    spec = importlib.util.spec_from_file_location(name, path)
    module = importlib.util.module_from_spec(spec)
    if spec.loader is None:
        raise RuntimeError(f"Could not load generated module: {{path}}")
    spec.loader.exec_module(module)
    return module


def ui_chrome_module_file_manifest():
    """Return file-level evidence for generated UI chrome modules."""
    modules = (
        ("splash_module", "splash_screen"),
        ("menu_editor_module", "menu_editor"),
        ("context_menu_module", "context_menu"),
        ("ui_fine_tuning_module", "ui_fine_tuning"),
    )
    expected_exports = ("module_contract", "runtime_manifest", "run_design_operation", "smoke_test")
    module_dir = Path(__file__).with_name("ui_chrome_modules")
    entries = []
    for module_name, surface in modules:
        module_path = module_dir / f"{{module_name}}.py"
        exports = ()
        contract_ok = False
        smoke_ok = False
        if module_path.exists():
            module = _load_generated_module(module_path, f"generated_ui_chrome_module_{{module_name}}")
            exports = tuple(name for name in expected_exports if hasattr(module, name))
            contract = module.module_contract()
            smoke = module.smoke_test()
            contract_ok = contract["ok"] and contract["module"] == module_name and contract["surface"] == surface
            smoke_ok = smoke["ok"] and smoke["surface"] == surface
        entries.append(
            {{
                "module": module_name,
                "surface": surface,
                "path": f"app/ui_chrome_modules/{{module_name}}.py",
                "exists": module_path.exists(),
                "exports": exports,
                "expected_exports": expected_exports,
                "contract_ok": contract_ok,
                "smoke_ok": smoke_ok,
            }}
        )
    return {{
        "format": "appgen.generated-ui-chrome-module-file-manifest.v1",
        "ok": bool(entries)
        and all(
            item["exists"]
            and item["contract_ok"]
            and item["smoke_ok"]
            and set(item["expected_exports"]) <= set(item["exports"])
            for item in entries
        ),
        "modules": tuple(entries),
        "guards": ("one_file_per_ui_chrome_module", "declared_exports_present", "module_smoke_loads"),
        "side_effects": (),
    }}


def ui_chrome_module_test_file_manifest():
    """Return file-level evidence for generated UI chrome module tests."""
    modules = ui_chrome_module_file_manifest()["modules"]
    required_exports = (
        "load_ui_chrome_module",
        "test_ui_chrome_module_contract",
        "test_ui_chrome_module_smoke",
        "smoke_test",
    )
    test_dir = Path(__file__).with_name("ui_chrome_module_tests")
    entries = []
    for item in modules:
        module_name = item["module"]
        module_path = test_dir / f"test_{{module_name}}.py"
        exports = ()
        smoke_ok = False
        if module_path.exists():
            module = _load_generated_module(module_path, f"generated_ui_chrome_module_test_{{module_name}}")
            exports = tuple(name for name in required_exports if hasattr(module, name))
            smoke_ok = module.smoke_test()["ok"]
        entries.append(
            {{
                "module": module_name,
                "surface": item["surface"],
                "path": f"app/ui_chrome_module_tests/test_{{module_name}}.py",
                "target": item["path"],
                "exists": module_path.exists(),
                "exports": exports,
                "smoke_ok": smoke_ok,
            }}
        )
    return {{
        "format": "appgen.generated-ui-chrome-module-test-file-manifest.v1",
        "ok": bool(entries)
        and all(item["exists"] and item["smoke_ok"] and set(required_exports) <= set(item["exports"]) for item in entries),
        "tests": tuple(entries),
        "required_exports": required_exports,
        "guards": ("one_test_file_per_ui_chrome_module", "contract_and_smoke_tests_exported"),
        "side_effects": (),
    }}


def ui_chrome_readiness_contract(existing_paths=None):
    """Prove generated splash, menu, context-menu, and fine-tuning chrome as one ordered path."""
    existing = set(existing_paths or ())
    required_assets = ("app/branding.py", "app/static/appgen-theme.css", "app/templates/appgen_branding.html")
    missing_assets = tuple(path for path in required_assets if path not in existing) if existing_paths is not None else ()
    splash = splash_screen_contract()
    menus = menu_catalog()
    menu_schema = menu_edit_schema()
    valid_menu_plan = menu_edit_plan((
        {{"menu": "primary", "item": "reports", "operation": "update", "fields": ("label", "order"), "route": "/reports/"}},
    ))
    invalid_menu_plan = menu_edit_plan((
        {{"menu": "primary", "item": "external", "operation": "update", "fields": ("label", "unsafe"), "route": "http://example.test"}},
    ))
    context_menus = context_menu_catalog()
    reviewed_actions = tuple(
        context_menu_action_plan(item["surface"], next(action["id"] for action in item["actions"] if action["requires_review"]))
        for item in context_menus
        if any(action["requires_review"] for action in item["actions"])
    )
    customization = ui_customization_workbench(existing_paths)
    module_manifest = ui_chrome_module_file_manifest()
    test_manifest = ui_chrome_module_test_file_manifest()
    release = ui_experience_release_gate(existing_paths)
    phases = (
        {{
            "phase": "splash_screen",
            "ok": splash["min_duration_ms"] < splash["max_duration_ms"]
            and "reduced_motion" in splash["motion"]
            and {{"web", "pwa", "mobile", "desktop"}} <= set(splash["targets"]),
            "evidence": splash,
        }},
        {{
            "phase": "menu_editor",
            "ok": bool(menus)
            and all(item["items"] for item in menus)
            and menu_schema["review_required"]
            and valid_menu_plan["ok"]
            and not invalid_menu_plan["ok"],
            "evidence": {{"menus": menus, "schema": menu_schema, "valid": valid_menu_plan, "invalid": invalid_menu_plan}},
        }},
        {{
            "phase": "context_menu",
            "ok": bool(context_menus)
            and all(item["trigger"] == "contextmenu" and item["actions"] for item in context_menus)
            and bool(reviewed_actions)
            and all(item["requires_review"] for item in reviewed_actions),
            "evidence": {{"menus": context_menus, "reviewed_actions": reviewed_actions}},
        }},
        {{
            "phase": "ui_fine_tuning",
            "ok": bool(design_tokens())
            and bool(component_state_matrix())
            and bool(viewport_contract())
            and bool(layout_contract()),
            "evidence": ("design_tokens", "component_state_matrix", "viewport_contract", "layout_contract"),
        }},
        {{
            "phase": "generated_modules",
            "ok": module_manifest["ok"]
            and {{"splash_screen", "menu_editor", "context_menu", "ui_fine_tuning"}} == {{item["surface"] for item in module_manifest["modules"]}},
            "evidence": module_manifest,
        }},
        {{
            "phase": "generated_tests",
            "ok": test_manifest["ok"]
            and {{"splash_screen", "menu_editor", "context_menu", "ui_fine_tuning"}} == {{item["surface"] for item in test_manifest["tests"]}},
            "evidence": test_manifest,
        }},
        {{
            "phase": "release_gate",
            "ok": customization["ok"] and release["ok"] and not release["blocking_gaps"],
            "evidence": {{"customization": customization["format"], "release": release["format"]}},
        }},
    )
    phase_names = tuple(item["phase"] for item in phases)
    checks = (
        {{"id": "artifact_coverage_ready", "ok": not missing_assets, "evidence": {{"required": required_assets, "missing": missing_assets}}}},
        {{"id": "splash_before_menu_ready", "ok": phase_names.index("splash_screen") < phase_names.index("menu_editor"), "evidence": phase_names}},
        {{"id": "menus_before_context_ready", "ok": phase_names.index("menu_editor") < phase_names.index("context_menu"), "evidence": phase_names}},
        {{"id": "context_before_fine_tuning_ready", "ok": phase_names.index("context_menu") < phase_names.index("ui_fine_tuning"), "evidence": phase_names}},
        {{"id": "generated_modules_ready", "ok": module_manifest["ok"], "evidence": module_manifest}},
        {{"id": "generated_tests_ready", "ok": test_manifest["ok"], "evidence": test_manifest}},
        {{"id": "release_gate_ready", "ok": release["ok"] and not release["blocking_gaps"], "evidence": release}},
        {{"id": "phase_order_ready", "ok": phase_names == ("splash_screen", "menu_editor", "context_menu", "ui_fine_tuning", "generated_modules", "generated_tests", "release_gate"), "evidence": phase_names}},
        {{"id": "side_effect_guard_ready", "ok": not module_manifest["side_effects"] and not test_manifest["side_effects"], "evidence": (module_manifest["side_effects"], test_manifest["side_effects"])}},
    )
    ok = all(item["ok"] for item in phases) and all(check["ok"] for check in checks)
    return {{
        "format": "appgen.ui-chrome-readiness-contract.v1",
        "ok": ok,
        "decision": "approved" if ok else "blocked",
        "phases": phases,
        "checks": checks,
        "side_effects": (),
        "blocking_gaps": tuple(check for check in checks if not check["ok"]) + tuple(phase for phase in phases if not phase["ok"]),
    }}


