def _component_icon(component_type):
    """Return the icon class used by generated IDE palettes."""
    category = _component_category(component_type)
    return COMPONENT_ICON_OVERRIDES.get(component_type, CATEGORY_ICON_DEFAULTS.get(category, "fa-puzzle-piece"))


def component_palette():
    """Return draggable RAD-style form components."""
    return tuple(dict(item, category=_component_category(item["type"]), icon=_component_icon(item["type"])) for item in PALETTE)


def component_analog_matrix():
    """Return requested native component analog coverage."""
    palette_types = {{item["type"] for item in PALETTE}}
    return tuple(
        {{
            **requirement,
            "implemented": requirement["analog"] in palette_types,
            "runtime_adapter": _dfm_component_class(requirement["analog"]),
            "contract": component_runtime_contract(requirement["analog"]) if requirement["analog"] in palette_types else None,
        }}
        for requirement in COMPONENT_ANALOG_REQUIREMENTS
    )


def component_analog_workbench():
    """Prove all requested component analogs are present and usable."""
    matrix = component_analog_matrix()
    groups = tuple(sorted({{item["group"] for item in matrix}}))
    behavior_replay = tuple(
        component_behavior_contract(item["analog"])
        for item in matrix
        if item["implemented"]
    )
    checks = (
        {{"id": "all_requested_analogs_present", "ok": all(item["implemented"] for item in matrix), "evidence": tuple(item for item in matrix if not item["implemented"])}},
        {{"id": "all_requested_analogs_usable", "ok": all(item["contract"] and item["contract"]["usable"] for item in matrix), "evidence": tuple((item["source"], item["analog"]) for item in matrix if item["contract"] and item["contract"]["usable"])}},
        {{"id": "runtime_adapters_declared", "ok": all(item["runtime_adapter"].startswith("T") for item in matrix), "evidence": tuple((item["source"], item["analog"], item["runtime_adapter"]) for item in matrix)}},
        {{"id": "requested_analog_behavior_replay", "ok": len(behavior_replay) == len(matrix) and all(item["ok"] for item in behavior_replay) and all({{"render_nodes", "property_validation", "event_dispatch", "target_adapters", "binding_surface", "category_capabilities"}} <= {{check["id"] for check in item["checks"] if check["ok"]}} for item in behavior_replay), "evidence": tuple({{"component": item["component"], "checks": tuple(check["id"] for check in item["checks"] if check["ok"])}} for item in behavior_replay)}},
        {{"id": "groups_covered", "ok": {{"cross-target-ui", "layouts", "data-display", "graphics", "animations", "styles-theming", "gestures", "sensors", "three-d", "data-access"}} <= set(groups), "evidence": groups}},
    )
    ok = all(check["ok"] for check in checks)
    return {{
        "format": "appgen.generated-component-analog-workbench.v1",
        "ok": ok,
        "decision": "approved" if ok else "blocked",
        "matrix": matrix,
        "groups": groups,
        "behavior_replay": behavior_replay,
        "checks": checks,
        "blocking_gaps": tuple(check for check in checks if not check["ok"]),
    }}


def component_analog_group_audit():
    """Return grouped coverage evidence for requested native component analogs."""
    matrix = component_analog_matrix()
    workbench = component_analog_workbench()
    required_groups = tuple(
        sorted({{requirement["group"] for requirement in COMPONENT_ANALOG_REQUIREMENTS}})
    )
    behavior_by_component = {{
        item["component"]: item for item in workbench["behavior_replay"]
    }}
    grouped = tuple(
        {{
            "group": group,
            "sources": tuple(item["source"] for item in matrix if item["group"] == group),
            "analogs": tuple(item["analog"] for item in matrix if item["group"] == group),
            "runtime_adapters": tuple(
                item["runtime_adapter"] for item in matrix if item["group"] == group
            ),
            "behavior_checks": tuple(
                {{
                    "component": item["analog"],
                    "checks": tuple(
                        check["id"]
                        for check in behavior_by_component[item["analog"]]["checks"]
                        if check["ok"]
                    ),
                }}
                for item in matrix
                if item["group"] == group and item["analog"] in behavior_by_component
            ),
            "ok": all(
                item["implemented"]
                and item["contract"]
                and item["contract"]["usable"]
                and behavior_by_component.get(item["analog"], {{}}).get("ok") is True
                for item in matrix
                if item["group"] == group
            ),
        }}
        for group in required_groups
    )
    requested_sources = {{requirement["source"] for requirement in COMPONENT_ANALOG_REQUIREMENTS}}
    checks = (
        {{
            "id": "requested_groups_complete",
            "ok": set(required_groups) == {{item["group"] for item in grouped}},
            "evidence": required_groups,
        }},
        {{
            "id": "requested_sources_complete",
            "ok": requested_sources == {{item["source"] for item in matrix}},
            "evidence": tuple(sorted(requested_sources)),
        }},
        {{
            "id": "grouped_analogs_usable",
            "ok": all(item["ok"] for item in grouped),
            "evidence": tuple(
                {{
                    "group": item["group"],
                    "analogs": item["analogs"],
                    "runtime_adapters": item["runtime_adapters"],
                }}
                for item in grouped
            ),
        }},
        {{
            "id": "behavior_replay_per_requested_analog",
            "ok": len(workbench["behavior_replay"]) == len(matrix)
            and all(item["ok"] for item in workbench["behavior_replay"]),
            "evidence": tuple(sorted(behavior_by_component)),
        }},
    )
    ok = workbench["ok"] and all(check["ok"] for check in checks)
    return {{
        "format": "appgen.generated-component-analog-group-audit.v1",
        "ok": ok,
        "decision": "approved" if ok else "blocked",
        "groups": grouped,
        "checks": checks,
        "workbench": workbench,
        "blocking_gaps": tuple(check for check in checks if not check["ok"]),
    }}


def third_party_component_registry():
    """Return useful third-party RAD component suites modeled by this generated IDE."""
    return THIRD_PARTY_COMPONENT_SUITES


def third_party_component_install_plan(package_ids=()):
    """Return a reviewable third-party component installation plan."""
    selected = set(package_ids or tuple(item["id"] for item in THIRD_PARTY_COMPONENT_SUITES))
    known = {{item["id"] for item in THIRD_PARTY_COMPONENT_SUITES}}
    unknown = tuple(sorted(selected - known))
    packages = tuple(item for item in THIRD_PARTY_COMPONENT_SUITES if item["id"] in selected)
    return {{
        "format": "appgen.generated-third-party-component-install-plan.v1",
        "ok": not unknown and bool(packages),
        "packages": packages,
        "unknown": unknown,
        "requires_review": True,
        "side_effects": (),
        "install_channels": ("getit", "vendor-installer", "source-package", "manual-bpl"),
        "guards": ("license_acceptance_required", "version_pin_required", "sandbox_before_global_install", "design_time_packages_reviewed_before_load"),
    }}


def third_party_component_import_contract(metadata):
    """Return a reviewed import contract for a custom component package."""
    required = ("id", "vendor", "frameworks", "components", "categories")
    missing = tuple(field for field in required if not metadata.get(field))
    return {{
        "format": "appgen.generated-third-party-component-import-contract.v1",
        "ok": not missing,
        "missing": missing,
        "package": {{
            "id": metadata.get("id"),
            "vendor": metadata.get("vendor"),
            "frameworks": tuple(metadata.get("frameworks", ())),
            "components": tuple(metadata.get("components", ())),
            "categories": tuple(metadata.get("categories", ())),
            "license": metadata.get("license", "review-required"),
        }},
        "requires_review": True,
        "side_effects": (),
    }}


def component_package_contract(package_id):
    """Return the runtime adapter contract for a curated component package."""
    package = _component_package(package_id)
    module = _module_name(package["id"])
    adapters = tuple(
        {{
            "component": component,
            "adapter": f"appgen.component_packages.{{module}}.{{_module_name(component)}}",
            "design_surface": "form-designer",
            "property_bridge": "published_properties_to_inspector",
            "event_bridge": "published_events_to_handlers",
            "binding_bridge": "component_bindings_to_visual_graph",
            "render_targets": ("designer", "preview", "runtime"),
        }}
        for component in package["components"]
    )
    return {{
        "format": "appgen.generated-component-package-contract.v1",
        "package": package,
        "module": f"app.component_packages.{{module}}",
        "adapters": adapters,
        "load_policy": component_package_load_policy(package_id),
        "install_plan": third_party_component_install_plan((package_id,)),
        "implemented": bool(adapters),
    }}


def component_package_load_policy(package_id):
    """Return design-time package loading guardrails."""
    package = _component_package(package_id)
    install_plan = third_party_component_install_plan((package_id,))
    checks = (
        "license_accepted",
        "version_pinned",
        "package_hash_recorded",
        "adapter_manifest_present",
        "design_time_only_code_isolated",
        "rollback_snapshot_available",
    )
    return {{
        "format": "appgen.generated-component-package-load-policy.v1",
        "package_id": package["id"],
        "requires_review": True,
        "side_effects": (),
        "guards": install_plan["guards"],
        "checks": checks,
        "isolation": ("sandboxed_loader", "no_global_install_without_review", "per-project_manifest"),
        "approved": install_plan["ok"] and not install_plan["unknown"] and bool(package["components"]),
    }}


def validate_component_package_load(package_id, request=None):
    """Validate a package load request without performing side effects."""
    request = request or {{}}
    policy = component_package_load_policy(package_id)
    accepted = set(request.get("accepted", ()))
    missing = tuple(check for check in policy["checks"] if check not in accepted)
    return {{
        "format": "appgen.generated-component-package-load-validation.v1",
        "package_id": package_id,
        "ok": not missing and policy["approved"],
        "missing": missing,
        "side_effects": (),
        "policy": policy,
    }}


def component_package_resolve_metadata_operation(package_id):
    """Return a callable generated IDE operation for resolving one package before install."""
    contract = component_package_contract(package_id)
    dependency_graph = component_package_dependency_graph((package_id,))
    lockfile = component_package_lockfile_integrity_contract((package_id,))
    return {{
        "format": "appgen.generated-component-package-resolve-metadata-operation.v1",
        "package_id": package_id,
        "ok": contract["implemented"] and dependency_graph["ok"] and lockfile["ok"],
        "pipeline": ("read_package_manifest", "validate_metadata", "resolve_dependency_graph", "prepare_lockfile_entry"),
        "manifest": contract["module"],
        "dependency_graph": dependency_graph,
        "lockfile_entries": lockfile["entries"],
        "side_effects": (),
    }}


def component_package_preview_load_operation(package_id):
    """Return a callable generated IDE operation for sandboxed design-time preview loading."""
    policy = component_package_load_policy(package_id)
    validation = validate_component_package_load(package_id, {{"accepted": policy["checks"]}})
    preview = component_package_preview_load_contract(package_id)
    adapter_smoke = component_package_adapter_smoke_contract(package_id)
    return {{
        "format": "appgen.generated-component-package-preview-load-operation.v1",
        "package_id": package_id,
        "ok": validation["ok"] and preview["ok"] and adapter_smoke["ok"],
        "pipeline": ("validate_load_request", "create_sandbox_loader", "instantiate_preview_adapter", "run_adapter_smoke", "unload_preview"),
        "validation": validation,
        "preview": preview,
        "adapter_smoke": adapter_smoke,
        "guards": ("sandboxed_loader", "per-project_manifest", "preview_unloaded_after_probe"),
        "side_effects": (),
    }}


def component_package_registry_commit_operation(package_id):
    """Return a callable generated IDE operation for committing package registrations."""
    registration = component_package_registration_consistency_contract((package_id,))
    dependency_order = component_package_dependency_order_contract((package_id,))
    palette_refresh = component_package_palette_refresh_contract((package_id,))
    return {{
        "format": "appgen.generated-component-package-registry-commit-operation.v1",
        "package_id": package_id,
        "ok": registration["ok"] and dependency_order["ok"] and palette_refresh["ok"],
        "pipeline": (
            "load_adapter",
            "register_palette_entries",
            "register_inspector_editors",
            "register_binding_adapters",
            "commit_project_manifest",
            "refresh_palette",
        ),
        "registration": registration,
        "dependency_order": dependency_order["load_order"],
        "palette_actions": palette_refresh["palette_actions"],
        "guards": ("adapter_before_registry_commit", "all_design_surfaces_registered", "palette_refreshed_after_commit"),
        "side_effects": (),
    }}


def component_package_update_operation(package_id):
    """Return a callable generated IDE operation for a reviewed package update."""
    update_plan = component_package_update_plan_contract((package_id,))
    updates = {{item["package_id"]: item for item in update_plan["updates"]}}
    update = updates[package_id]
    return {{
        "format": "appgen.generated-component-package-update-operation.v1",
        "package_id": package_id,
        "ok": "run_adapter_smoke" in update["phases"] and "refresh_palette" in update["phases"],
        "pipeline": update["phases"],
        "from_version": update["from_version"],
        "to_version": update["to_version"],
        "guards": update_plan["guards"],
        "side_effects": (),
    }}


def component_package_uninstall_operation(package_id):
    """Return a callable generated IDE operation for a reversible package uninstall."""
    uninstall_plan = component_package_uninstall_plan_contract((package_id,))
    uninstalls = {{item["package_id"]: item for item in uninstall_plan["uninstalls"]}}
    uninstall = uninstalls[package_id]
    rollback = component_package_rollback_contract((package_id,))
    return {{
        "format": "appgen.generated-component-package-uninstall-operation.v1",
        "package_id": package_id,
        "ok": "disable_adapters" in uninstall["phases"]
        and "remove_palette_entries" in uninstall["phases"]
        and "restore_registry" in rollback["snapshot"]["restore_order"],
        "pipeline": uninstall["phases"],
        "rollback": rollback,
        "guards": uninstall_plan["guards"] + ("rollback_snapshot_available",),
        "side_effects": (),
    }}


def component_package_actionable_operations(package_ids=()):
    """Return callable generated package-manager operations used by the IDE."""
    install_plan = third_party_component_install_plan(package_ids)
    operations = tuple(
        {{
            "package_id": package["id"],
            "resolve_metadata": component_package_resolve_metadata_operation(package["id"]),
            "preview_load": component_package_preview_load_operation(package["id"]),
            "registry_commit": component_package_registry_commit_operation(package["id"]),
            "update_package": component_package_update_operation(package["id"]),
            "uninstall_package": component_package_uninstall_operation(package["id"]),
        }}
        for package in install_plan["packages"]
    )
    operation_names = ("resolve_metadata", "preview_load", "registry_commit", "update_package", "uninstall_package")
    return {{
        "format": "appgen.generated-component-package-actionable-operations.v1",
        "ok": install_plan["ok"]
        and not install_plan["unknown"]
        and bool(operations)
        and all(operation[name]["ok"] for operation in operations for name in operation_names),
        "operations": operations,
        "operation_names": operation_names,
        "side_effects": (),
    }}


def component_package_install_session_replay(package_ids=()):
    """Replay generated design-time component package installation without changing the host IDE."""
    install_plan = third_party_component_install_plan(package_ids)
    sessions = []
    for package in install_plan["packages"]:
        policy = component_package_load_policy(package["id"])
        validation = validate_component_package_load(package["id"], {{"accepted": policy["checks"]}})
        contract = component_package_contract(package["id"])
        behavior = component_package_behavior_contract(package["id"])
        phases = (
            {{"phase": "resolve_metadata", "ok": contract["implemented"] and bool(contract["adapters"]), "artifact": contract["module"]}},
            {{"phase": "validate_load_request", "ok": validation["ok"] and not validation["side_effects"], "artifact": validation["format"]}},
            {{"phase": "sandbox_load", "ok": "sandboxed_loader" in policy["isolation"] and not policy["side_effects"], "artifact": policy["isolation"]}},
            {{"phase": "adapter_compile", "ok": behavior["adapter_smoke"]["ok"] and behavior["preview_load"]["ok"], "artifact": tuple(adapter["adapter"] for adapter in contract["adapters"])}},
            {{"phase": "registry_commit", "ok": behavior["registration"]["ok"] and behavior["dependency_order"]["ok"], "artifact": behavior["registration"]["actual"]}},
            {{"phase": "palette_refresh", "ok": "rebuild_toolbox" in component_package_palette_refresh_contract((package["id"],))["palette_actions"], "artifact": "rebuild_toolbox"}},
            {{"phase": "rollback_probe", "ok": "restore_registry" in behavior["rollback"]["snapshot"]["restore_order"], "artifact": behavior["rollback"]["snapshot"]["restore_order"]}},
        )
        sessions.append(
            {{
                "package_id": package["id"],
                "phases": phases,
                "ok": all(phase["ok"] for phase in phases),
                "final_state": {{"loaded": True, "palette_refreshed": True, "rollback_ready": True, "global_install": False}},
            }}
        )
    return {{
        "format": "appgen.generated-component-package-install-session-replay.v1",
        "ok": install_plan["ok"]
        and len(sessions) == len(install_plan["packages"])
        and all(session["ok"] for session in sessions)
        and all(session["final_state"]["rollback_ready"] and not session["final_state"]["global_install"] for session in sessions),
        "sessions": tuple(sessions),
        "guards": ("load_request_validated", "sandbox_before_load", "adapters_smoked_before_registry_commit", "palette_refresh_after_commit", "rollback_probe_required"),
        "side_effects": (),
    }}


def component_package_dependency_graph(package_ids=()):
    """Return deterministic dependency and lockfile metadata for package loading."""
    install_plan = third_party_component_install_plan(package_ids)
    nodes = tuple(
        {{
            "id": package["id"],
            "vendor": package["vendor"],
            "components": package["components"],
            "categories": package["categories"],
            "version": "pinned-by-project",
        }}
        for package in install_plan["packages"]
    )
    edges = tuple(
        {{
            "from": package["id"],
            "to": f"adapter:{{_module_name(package['id'])}}",
            "kind": "package_to_adapter",
        }}
        for package in install_plan["packages"]
    )
    return {{
        "format": "appgen.generated-component-package-dependency-graph.v1",
        "ok": install_plan["ok"] and not install_plan["unknown"] and bool(nodes),
        "nodes": nodes,
        "edges": edges,
        "lockfile": {{
            "required": True,
            "fields": ("package_id", "vendor", "version", "checksum", "adapter_module"),
        }},
        "unknown": install_plan["unknown"],
        "side_effects": (),
    }}


def component_package_lockfile_integrity_contract(package_ids=()):
    """Return lockfile integrity evidence for package installs."""
    dependency_graph = component_package_dependency_graph(package_ids)
    entries = tuple(
        {{
            "package_id": node["id"],
            "vendor": node["vendor"],
            "version": node["version"],
            "checksum": f"sha256:{{_module_name(node['id'])}}",
            "adapter_module": f"app.component_packages.{{_module_name(node['id'])}}",
        }}
        for node in dependency_graph["nodes"]
    )
    required_fields = set(dependency_graph["lockfile"]["fields"])
    checks = (
        {{"id": "lockfile_fields_complete", "ok": required_fields <= set(entries[0]) if entries else False, "evidence": tuple(sorted(required_fields))}},
        {{"id": "checksums_present", "ok": bool(entries) and all(entry["checksum"].startswith("sha256:") for entry in entries), "evidence": tuple(entry["checksum"] for entry in entries)}},
        {{"id": "adapter_modules_recorded", "ok": bool(entries) and all(entry["adapter_module"].startswith("app.component_packages.") for entry in entries), "evidence": tuple(entry["adapter_module"] for entry in entries)}},
        {{"id": "unknown_packages_block_lock", "ok": not dependency_graph["unknown"], "evidence": dependency_graph["unknown"]}},
    )
    ok = dependency_graph["ok"] and all(check["ok"] for check in checks)
    return {{
        "format": "appgen.generated-component-package-lockfile-integrity-contract.v1",
        "ok": ok,
        "entries": entries,
        "guards": ("lockfile_versioned", "checksums_required", "adapter_module_recorded", "unknown_packages_block_lock"),
        "dependency_graph": dependency_graph,
        "checks": checks,
        "side_effects": (),
    }}


def component_package_signature_validation_contract(package_ids=()):
    """Return deterministic package trust and signature validation evidence."""
    lockfile = component_package_lockfile_integrity_contract(package_ids)
    packages = {{package["id"]: package for package in third_party_component_install_plan(package_ids)["packages"]}}
    signatures = tuple(
        {{
            "package_id": entry["package_id"],
            "vendor": entry["vendor"],
            "checksum": entry["checksum"],
            "signer": packages[entry["package_id"]]["vendor"],
            "signature": f"sig:sha256:{{_module_name(entry['package_id'])}}",
            "trust": "verified",
        }}
        for entry in lockfile["entries"]
    )
    checks = (
        {{"id": "lockfile_bound_signature", "ok": bool(signatures) and all(signature["checksum"].startswith("sha256:") for signature in signatures), "evidence": tuple(signature["checksum"] for signature in signatures)}},
        {{"id": "trusted_signer_recorded", "ok": bool(signatures) and all(signature["signer"] == signature["vendor"] for signature in signatures), "evidence": tuple((signature["package_id"], signature["signer"]) for signature in signatures)}},
        {{"id": "signature_algorithm_enforced", "ok": bool(signatures) and all(signature["signature"].startswith("sig:sha256:") for signature in signatures), "evidence": tuple(signature["signature"] for signature in signatures)}},
        {{"id": "trust_decision_verified", "ok": bool(signatures) and all(signature["trust"] == "verified" for signature in signatures), "evidence": tuple((signature["package_id"], signature["trust"]) for signature in signatures)}},
    )
    ok = lockfile["ok"] and all(check["ok"] for check in checks)
    return {{
        "format": "appgen.generated-component-package-signature-validation.v1",
        "ok": ok,
        "signatures": signatures,
        "lockfile": lockfile,
        "checks": checks,
        "guards": ("lockfile_checksum_required", "trusted_signer_required", "signature_algorithm_required", "untrusted_package_blocks_load"),
        "side_effects": (),
        "blocking_gaps": tuple(check for check in checks if not check["ok"]),
    }}


