def component_runtime_contract(component_type):
    """Return the runtime/editor contract that makes a generated component usable."""
    spec = _palette_spec(component_type)
    category = _component_category(component_type)
    properties = _component_properties(component_type, category)
    nonvisual = category in ("nonvisual", "data", "integration") and component_type not in ("Grid", "Chart", "ReportViewer", "WebBrowser")
    renderers = {{
        "web": f"appgen.components.{{component_type}}",
        "mobile": f"appgen.mobile.{{component_type}}",
        "desktop": f"appgen.desktop.{{component_type}}",
    }}
    if nonvisual:
        renderers = {{
            "web": f"appgen.services.{{component_type}}",
            "mobile": f"appgen.mobile_services.{{component_type}}",
            "desktop": f"appgen.desktop_services.{{component_type}}",
        }}
    return {{
        "format": "appgen.generated-component-runtime-contract.v1",
        "component": component_type,
        "category": category,
        "renderers": renderers,
        "default_size": spec["defaults"],
        "default_props": {{name: _default_property_value(name, component_type, category) for name in properties}},
        "property_editors": tuple({{"name": name, "type": _property_editor_type(name)}} for name in properties),
        "events": _component_events(component_type, category),
        "bindings": {{
            "data_bound": category in ("input", "choice", "calendar", "data", "analytics", "reports", "relationship", "media"),
            "field_types": _component_field_types(category),
            "binding_modes": ("read", "write") if category not in ("container", "menu", "effects", "three_d", "nonvisual") else (),
        }},
        "validation_rules": _component_validation_rules(component_type, category),
        "preview": {{"available": True, "preview_kind": "service-node" if nonvisual else "visual-control"}},
        "usable": True,
    }}


def component_render_contract(component_type):
    """Return deterministic render-node behavior for a generated component."""
    contract = component_runtime_contract(component_type)
    return {{
        "format": "appgen.generated-component-render-contract.v1",
        "component": component_type,
        "nodes": tuple(
            {{
                "target": target,
                "renderer": renderer,
                "props": contract["default_props"],
                "events": contract["events"],
                "bindings": contract["bindings"],
            }}
            for target, renderer in contract["renderers"].items()
        ),
        "accessibility": {{
            "focusable": contract["category"] not in ("graphics", "theme", "nonvisual"),
            "label_source": "caption" if "caption" in contract["default_props"] else "label",
            "keyboard": ("tab", "enter", "space") if contract["category"] in ("input", "choice", "action") else (),
        }},
        "side_effects": (),
    }}


def component_prop_validation_contract(component_type, props=None):
    """Return property validation behavior for a generated component."""
    contract = component_runtime_contract(component_type)
    supplied = props or contract["default_props"]
    allowed = set(contract["default_props"])
    editors = {{item["name"]: item["type"] for item in contract["property_editors"]}}
    unknown = tuple(sorted(set(supplied) - allowed))
    typed = tuple(
        {{
            "property": name,
            "expected": editors.get(name, "string"),
            "ok": name in allowed,
        }}
        for name in supplied
    )
    return {{
        "format": "appgen.generated-component-prop-validation-contract.v1",
        "component": component_type,
        "ok": not unknown and all(item["ok"] for item in typed),
        "unknown": unknown,
        "typed": typed,
        "rules": contract["validation_rules"],
        "side_effects": (),
    }}


def component_event_dispatch_contract(component_type):
    """Return event dispatch metadata for a generated component."""
    contract = component_runtime_contract(component_type)
    handlers = tuple(
        {{
            "event": event,
            "handler": f"{{_module_name(component_type)}}_{{_module_name(event)}}",
            "phases": ("capture", "validate", "dispatch", "bubble"),
            "side_effects": (),
        }}
        for event in contract["events"]
    )
    return {{
        "format": "appgen.generated-component-event-dispatch-contract.v1",
        "component": component_type,
        "handlers": handlers,
        "guards": ("handler_signature_checked", "disabled_components_skip_dispatch", "errors_reported_to_designer"),
    }}


def component_target_adapter_contract(component_type):
    """Return cross-target adapter metadata for a generated component."""
    contract = component_runtime_contract(component_type)
    return {{
        "format": "appgen.generated-component-target-adapter-contract.v1",
        "component": component_type,
        "adapters": tuple(
            {{
                "target": target,
                "renderer": renderer,
                "lifecycle": ("create", "update", "validate", "destroy"),
                "supports_preview": True,
                "side_effects": (),
            }}
            for target, renderer in contract["renderers"].items()
        ),
        "guards": ("stable_component_id", "target_specific_props_reviewed", "preview_matches_runtime_shape"),
    }}


def component_state_model_contract(component_type):
    """Return the design/runtime state machine for one generated component."""
    contract = component_runtime_contract(component_type)
    interactive = contract["category"] in {{"input", "choice", "action", "data", "navigation", "mobile"}}
    states = ("created", "loaded", "visible", "enabled", "focused", "invalid") if interactive else ("created", "loaded", "visible", "enabled")
    return {{
        "format": "appgen.generated-component-state-model-contract.v1",
        "component": component_type,
        "states": states,
        "transitions": (
            {{"from": "created", "to": "loaded", "event": "attach_to_form"}},
            {{"from": "loaded", "to": "visible", "event": "show"}},
            {{"from": "visible", "to": "enabled", "event": "enable"}},
            {{"from": "enabled", "to": "focused", "event": "focus"}} if interactive else {{"from": "enabled", "to": "visible", "event": "refresh"}},
            {{"from": "focused", "to": "invalid", "event": "validation_failed"}} if interactive else {{"from": "visible", "to": "loaded", "event": "hide"}},
        ),
        "guards": ("stable_component_id", "state_changes_emit_designer_event", "runtime_state_round_trips"),
        "side_effects": (),
    }}


def component_serialization_contract(component_type):
    """Return the property/resource streaming contract for one generated component."""
    contract = component_runtime_contract(component_type)
    asset_props = tuple(prop for prop in contract["default_props"] if prop in {{"source", "mesh", "material", "report"}})
    return {{
        "format": "appgen.generated-component-serialization-contract.v1",
        "component": component_type,
        "streams": ("text_design_stream", "json_design_stream", "binary_resource_stream"),
        "property_stream": tuple(sorted(contract["default_props"])),
        "asset_stream": asset_props,
        "resource_fingerprints": tuple(f"{{prop}}_sha256" for prop in asset_props),
        "round_trip_guards": ("unknown_properties_preserved", "property_order_stable", "resource_hash_recorded", "component_identity_preserved"),
        "side_effects": (),
    }}


def component_binding_surface_contract(component_type):
    """Return data/command binding surfaces for one generated component."""
    contract = component_runtime_contract(component_type)
    bindable_props = tuple(prop for prop in contract["default_props"] if prop in {{"label", "caption", "checked", "items", "data_source", "source", "text", "value", "columns", "series", "url"}})
    return {{
        "format": "appgen.generated-component-binding-surface-contract.v1",
        "component": component_type,
        "data_bound": contract["bindings"]["data_bound"],
        "field_types": contract["bindings"]["field_types"],
        "binding_modes": contract["bindings"]["binding_modes"] or ("command", "event"),
        "bindable_properties": bindable_props or tuple(contract["default_props"])[:1],
        "converter_hooks": ("format", "parse", "coerce", "validate"),
        "validator_hooks": ("required", "range", "pattern", "custom"),
        "side_effects": (),
    }}


def _component_capability_operations(component_type, category):
    """Return category-specific operations a generated component must support."""
    by_category = {{
        "display": ("render_text", "resolve_style", "publish_accessible_label"),
        "input": ("set_value", "validate_value", "commit_value", "emit_change"),
        "choice": ("load_items", "select_item", "validate_selection", "emit_change"),
        "calendar": ("open_picker", "select_date", "format_value", "validate_range"),
        "media": ("select_asset", "validate_asset", "render_preview", "clear_asset"),
        "relationship": ("open_lookup", "filter_candidates", "select_record", "sync_foreign_key"),
        "action": ("evaluate_enabled", "execute_action", "dispatch_command", "record_result"),
        "app_shell": ("render_splash", "build_main_menu", "open_context_menu", "apply_ui_tuning"),
        "container": ("measure_children", "arrange_children", "resolve_constraints", "publish_drop_zones"),
        "navigation": ("load_nodes", "expand_node", "select_node", "sync_selection"),
        "data": ("bind_dataset", "refresh_rows", "track_selection", "commit_edits"),
        "menu": ("build_items", "resolve_shortcuts", "open_menu", "dispatch_menu_action"),
        "analytics": ("bind_series", "refresh_chart", "select_data_point", "export_snapshot"),
        "reports": ("bind_parameters", "preview_report", "export_report", "print_report"),
        "integration": ("prepare_request", "send_request", "map_response", "surface_error"),
        "nonvisual": ("start_service", "stop_service", "emit_tick", "surface_status"),
        "mobile": ("request_permission", "start_capture", "read_device_value", "handle_denied"),
        "effects": ("build_timeline", "start_animation", "pause_animation", "apply_final_state"),
        "graphics": ("build_draw_path", "paint_surface", "hit_test_shape", "export_vector"),
        "theme": ("load_resources", "resolve_token", "apply_theme", "publish_variant"),
        "gesture": ("register_recognizer", "resolve_conflict", "recognize_input", "dispatch_gesture"),
        "three_d": ("load_scene_node", "bind_material", "render_frame", "hit_test_scene"),
        "data_access": ("open_connection", "prepare_query", "fetch_rows", "sync_offline_cache"),
    }}
    return by_category.get(category, ("load_custom_component", "render_custom_component", "validate_custom_component"))


def component_capability_contract(component_type):
    """Return category-specific execution capabilities for one generated component."""
    contract = component_runtime_contract(component_type)
    category = contract["category"]
    operations = _component_capability_operations(component_type, category)
    required_guards = (
        "side_effects_declared",
        "designer_preview_supported",
        "runtime_adapter_mapped",
        "smoke_probe_declared",
    )
    probes = tuple(
        {{
            "operation": operation,
            "targets": tuple(contract["renderers"]),
            "requires_binding": operation in {{"commit_value", "sync_foreign_key", "bind_dataset", "fetch_rows", "sync_offline_cache"}},
            "side_effects": (),
        }}
        for operation in operations
    )
    return {{
        "format": "appgen.generated-component-capability-contract.v1",
        "component": component_type,
        "category": category,
        "operations": operations,
        "probes": probes,
        "guards": required_guards,
        "ok": bool(operations)
        and all({{"web", "mobile", "desktop"}} <= set(probe["targets"]) for probe in probes)
        and all(not probe["side_effects"] for probe in probes)
        and set(required_guards) == {{"side_effects_declared", "designer_preview_supported", "runtime_adapter_mapped", "smoke_probe_declared"}},
        "side_effects": (),
    }}


def component_designer_metadata_contract(component_type):
    """Return design-time metadata required by generated palette, canvas, and inspector tooling."""
    contract = component_runtime_contract(component_type)
    return {{
        "format": "appgen.generated-component-designer-metadata-contract.v1",
        "component": component_type,
        "palette": {{"category": contract["category"], "glyph": _module_name(component_type), "default_size": contract["default_size"]}},
        "inspector": {{"tabs": ("Properties", "Events", "Bindings", "Layout", "Accessibility"), "property_editors": contract["property_editors"], "event_editors": contract["events"]}},
        "canvas": {{"drop_constraints": ("snap_to_grid", "no_overlap", "within_bounds"), "resize_handles": ("n", "e", "s", "w", "ne", "se", "sw", "nw"), "supports_nested_children": contract["category"] in {{"container", "menu", "three_d", "app_shell"}}}},
        "side_effects": (),
    }}


def component_design_surface_contract(component_type):
    """Return toolbox, drop preview, context menu, and gesture metadata."""
    contract = component_runtime_contract(component_type)
    metadata = component_designer_metadata_contract(component_type)
    category = contract["category"]
    common_actions = (
        "inspect",
        "edit_bindings",
        "align_to_grid",
        "bring_to_front",
        "send_to_back",
        "duplicate",
        "delete",
    )
    category_actions = {{
        "action": ("edit_action", "assign_shortcut"),
        "app_shell": ("edit_splash", "edit_main_menu", "edit_context_menus", "fine_tune_ui"),
        "analytics": ("edit_series", "preview_chart"),
        "calendar": ("edit_display_format", "validate_range"),
        "choice": ("edit_items", "toggle_multi_select"),
        "container": ("edit_children", "set_layout"),
        "data": ("bind_dataset", "preview_rows"),
        "data_access": ("edit_connection", "preview_rows"),
        "effects": ("edit_timeline", "preview_motion"),
        "gesture": ("edit_recognizer", "test_gesture"),
        "graphics": ("edit_shape", "export_vector"),
        "integration": ("edit_endpoint", "test_request"),
        "media": ("select_asset", "clear_asset"),
        "menu": ("edit_menu_items", "assign_roles"),
        "mobile": ("edit_permission", "simulate_device_event"),
        "navigation": ("edit_nodes", "preview_lazy_load"),
        "nonvisual": ("configure_service", "show_status"),
        "relationship": ("edit_lookup", "preview_candidates"),
        "reports": ("edit_report", "export_preview"),
        "theme": ("edit_resources", "apply_variant"),
        "three_d": ("edit_scene", "open_transform_gizmo"),
    }}
    gestures = (
        "drag_from_toolbox",
        "drop_on_canvas",
        "resize_handles",
        "keyboard_nudge",
        "copy_paste",
        "context_menu",
    )
    if metadata["canvas"]["supports_nested_children"]:
        gestures += ("drop_child", "reorder_children")
    if category in {{"graphics", "three_d"}}:
        gestures += ("direct_manipulation", "hit_test_overlay")
    if category in {{"data", "data_access", "relationship"}}:
        gestures += ("drag_field_binding", "open_lookup_designer")
    icon = _component_icon(component_type)
    context_actions = tuple(
        {{"id": action, "label": action.replace("_", " ").title()}}
        for action in common_actions + category_actions.get(category, ())
    )
    return {{
        "format": "appgen.generated-component-design-surface-contract.v1",
        "component": component_type,
        "ok": icon.startswith("fa-") and bool(context_actions) and bool(gestures),
        "toolbox": {{
            "icon": icon,
            "label": component_type,
            "category": category,
            "tooltip": f"Drop {{component_type}} on the form",
            "drag_payload": {{"component": component_type, "default_size": contract["default_size"]}},
            "data_attributes": {{
                "data-component": component_type,
                "data-component-icon": icon,
                "data-component-category": category,
            }},
        }},
        "drop_preview": {{
            "node_class": "agfd-node",
            "icon": icon,
            "label": component_type,
            "bounds": contract["default_size"],
            "preview_kind": contract["preview"]["preview_kind"],
        }},
        "context_menu": context_actions,
        "gestures": gestures,
        "routes": ("object_inspector", "binding_designer", "component_tree", "property_grid"),
        "side_effects": (),
    }}


def component_behavior_contract(component_type):
    """Return behavior evidence for one generated built-in component."""
    render = component_render_contract(component_type)
    validation = component_prop_validation_contract(component_type)
    events = component_event_dispatch_contract(component_type)
    adapters = component_target_adapter_contract(component_type)
    state_model = component_state_model_contract(component_type)
    serialization = component_serialization_contract(component_type)
    binding_surface = component_binding_surface_contract(component_type)
    capabilities = component_capability_contract(component_type)
    designer_metadata = component_designer_metadata_contract(component_type)
    design_surface = component_design_surface_contract(component_type)
    checks = (
        {{"id": "render_nodes", "ok": {{"web", "mobile", "desktop"}} <= {{node["target"] for node in render["nodes"]}} and not render["side_effects"], "evidence": render}},
        {{"id": "property_validation", "ok": validation["ok"] and not validation["side_effects"], "evidence": validation}},
        {{"id": "event_dispatch", "ok": bool(events["handlers"]) and all(not handler["side_effects"] for handler in events["handlers"]), "evidence": events}},
        {{"id": "target_adapters", "ok": all({{"create", "update", "validate", "destroy"}} <= set(adapter["lifecycle"]) and not adapter["side_effects"] for adapter in adapters["adapters"]), "evidence": adapters}},
        {{"id": "accessibility_preview", "ok": "label_source" in render["accessibility"], "evidence": render["accessibility"]}},
        {{"id": "state_model", "ok": {{"created", "loaded"}} <= set(state_model["states"]) and not state_model["side_effects"], "evidence": state_model}},
        {{"id": "design_serialization", "ok": bool(serialization["property_stream"]) and not serialization["side_effects"], "evidence": serialization}},
        {{"id": "binding_surface", "ok": bool(binding_surface["bindable_properties"]) and not binding_surface["side_effects"], "evidence": binding_surface}},
        {{"id": "category_capabilities", "ok": capabilities["ok"] and not capabilities["side_effects"], "evidence": capabilities}},
        {{"id": "designer_metadata", "ok": bool(designer_metadata["inspector"]["property_editors"]) and not designer_metadata["side_effects"], "evidence": designer_metadata}},
        {{"id": "design_surface_actions", "ok": design_surface["ok"] and design_surface["toolbox"]["icon"].startswith("fa-") and "context_menu" in design_surface["gestures"] and not design_surface["side_effects"], "evidence": design_surface}},
    )
    ok = all(check["ok"] for check in checks)
    return {{
        "format": "appgen.generated-component-behavior-contract.v1",
        "component": component_type,
        "ok": ok,
        "render": render,
        "validation": validation,
        "events": events,
        "adapters": adapters,
        "state_model": state_model,
        "serialization": serialization,
        "binding_surface": binding_surface,
        "capabilities": capabilities,
        "designer_metadata": designer_metadata,
        "design_surface": design_surface,
        "checks": checks,
        "blocking_gaps": tuple(check for check in checks if not check["ok"]),
    }}


def component_behavior_workbench():
    """Prove every generated built-in component has render, validation, event, and adapter behavior."""
    behaviors = tuple(component_behavior_contract(item["type"]) for item in PALETTE)
    checks = (
        {{"id": "all_components_have_behavior", "ok": len(behaviors) == len(PALETTE) and all(item["ok"] for item in behaviors), "evidence": tuple(item["component"] for item in behaviors)}},
        {{"id": "render_behavior", "ok": all(any(check["id"] == "render_nodes" and check["ok"] for check in item["checks"]) for item in behaviors), "evidence": tuple(item["render"] for item in behaviors)}},
        {{"id": "validation_behavior", "ok": all(any(check["id"] == "property_validation" and check["ok"] for check in item["checks"]) for item in behaviors), "evidence": tuple(item["validation"] for item in behaviors)}},
        {{"id": "event_behavior", "ok": all(any(check["id"] == "event_dispatch" and check["ok"] for check in item["checks"]) for item in behaviors), "evidence": tuple(item["events"] for item in behaviors)}},
        {{"id": "target_adapter_behavior", "ok": all(any(check["id"] == "target_adapters" and check["ok"] for check in item["checks"]) for item in behaviors), "evidence": tuple(item["adapters"] for item in behaviors)}},
        {{"id": "category_capability_behavior", "ok": all(any(check["id"] == "category_capabilities" and check["ok"] for check in item["checks"]) for item in behaviors), "evidence": tuple(item["capabilities"] for item in behaviors)}},
        {{"id": "design_surface_behavior", "ok": all(any(check["id"] == "design_surface_actions" and check["ok"] for check in item["checks"]) for item in behaviors), "evidence": tuple(item["design_surface"] for item in behaviors)}},
        {{"id": "implementation_depth", "ok": all({{"state_model", "design_serialization", "binding_surface", "category_capabilities", "designer_metadata", "design_surface_actions"}} <= {{check["id"] for check in item["checks"] if check["ok"]}} for item in behaviors), "evidence": tuple((item["component"], item["state_model"]["states"], item["serialization"]["streams"], item["binding_surface"]["binding_modes"], item["capabilities"]["operations"], item["design_surface"]["gestures"]) for item in behaviors)}},
    )
    ok = all(check["ok"] for check in checks)
    return {{
        "format": "appgen.generated-component-behavior-workbench.v1",
        "ok": ok,
        "decision": "approved" if ok else "blocked",
        "component_count": len(behaviors),
        "behaviors": behaviors,
        "checks": checks,
        "blocking_gaps": tuple(check for check in checks if not check["ok"]),
    }}


def component_drop_wiring_handler_contract(table_name=None, design=None):
    """Return generated palette drag/drop, event wiring, and handler definition evidence."""
    if design is None:
        table_name = table_name or next(iter(FORM_TABLES))
        design = form_design(table_name)
    drop_payloads = tuple(
        {{
            "component": item["type"],
            "category": _component_category(item["type"]),
            "icon": _component_icon(item["type"]),
            "default_size": item["defaults"],
            "payload": {{
                "kind": "component",
                "component": item["type"],
                "default_size": item["defaults"],
                "icon": _component_icon(item["type"]),
            }},
        }}
        for item in PALETTE
    )
    drop_targets = (
        {{"surface": "form_canvas", "accepts": ("component", "field"), "preview": "snap_grid"}},
        {{"surface": "container_component", "accepts": ("component",), "preview": "nested_bounds"}},
        {{"surface": "menu_designer", "accepts": ("menu_item", "action"), "preview": "menu_tree"}},
        {{"surface": "component_tree", "accepts": ("reorder", "parent_child"), "preview": "outline"}},
    )
    drop_pipeline = (
        "start_palette_drag",
        "show_drop_preview",
        "snap_to_grid",
        "validate_bounds",
        "create_component_instance",
        "select_component",
        "open_object_inspector",
        "record_undo",
    )
    sample_components = (
        {{"component": "Button", "field": "submit", "event": "OnClick", "handler": "button_submit_click"}},
        {{"component": "TextBox", "field": "name", "event": "OnChange", "handler": "textbox_name_change"}},
        {{"component": "Lookup", "field": "customer_id", "event": "OnLookup", "handler": "lookup_customer_id_lookup"}},
        {{"component": "Grid", "field": "lines", "event": "OnDblClick", "handler": "grid_lines_double_click"}},
    )
    wiring_links = tuple(
        {{
            "event": f"{{item['component']}}.{{item['event']}}",
            "component": item["component"],
            "field": item["field"],
            "handler": item["handler"],
            "dispatch": ("resolve_component", "resolve_handler", "invoke_handler"),
            "designer_surface": "events_inspector",
        }}
        for item in sample_components
    )
    handler_definitions = tuple(
        {{
            "name": item["handler"],
            "signature": "sender, context",
            "component": item["component"],
            "event": item["event"],
            "body_regions": ("generated_prelude", "user_code", "generated_postlude"),
            "context_keys": ("form", "component", "dataset", "event", "selection"),
            "preserves_user_code": True,
        }}
        for item in sample_components
    )
    checks = (
        {{
            "id": "palette_drag_payloads",
            "ok": bool(drop_payloads)
            and all(item["icon"].startswith("fa-") and item["payload"]["kind"] == "component" for item in drop_payloads),
            "evidence": tuple((item["component"], item["icon"]) for item in drop_payloads),
        }},
        {{
            "id": "drop_pipeline_declared",
            "ok": {{"start_palette_drag", "show_drop_preview", "snap_to_grid", "create_component_instance", "record_undo"}} <= set(drop_pipeline),
            "evidence": drop_pipeline,
        }},
        {{
            "id": "drop_targets_declared",
            "ok": {{"form_canvas", "container_component", "menu_designer", "component_tree"}} <= {{item["surface"] for item in drop_targets}},
            "evidence": drop_targets,
        }},
        {{
            "id": "wiring_routes_to_handlers",
            "ok": {{"Button.OnClick", "TextBox.OnChange", "Lookup.OnLookup", "Grid.OnDblClick"}} <= {{item["event"] for item in wiring_links}}
            and all("invoke_handler" in item["dispatch"] for item in wiring_links),
            "evidence": wiring_links,
        }},
        {{
            "id": "handlers_have_sender_context_signature",
            "ok": bool(handler_definitions) and all(item["signature"] == "sender, context" for item in handler_definitions),
            "evidence": tuple((item["name"], item["signature"]) for item in handler_definitions),
        }},
        {{
            "id": "undo_and_user_code_guards",
            "ok": "record_undo" in drop_pipeline
            and all(item["preserves_user_code"] and "user_code" in item["body_regions"] for item in handler_definitions),
            "evidence": handler_definitions,
        }},
    )
    ok = all(check["ok"] for check in checks)
    return {{
        "format": "appgen.generated-component-drop-wiring-handler-contract.v1",
        "ok": ok,
        "decision": "approved" if ok else "blocked",
        "form": design.get("name") or design.get("table"),
        "drop_payloads": drop_payloads,
        "drop_targets": drop_targets,
        "drop_pipeline": drop_pipeline,
        "wiring_links": wiring_links,
        "handler_definitions": handler_definitions,
        "checks": checks,
        "guards": (
            "handler_name_unique",
            "sender_context_signature",
            "user_code_regions_preserved",
            "undo_snapshot_required",
            "component_lookup_required",
        ),
        "side_effects": (),
        "blocking_gaps": tuple(check for check in checks if not check["ok"]),
    }}


def component_wiring_module_file_manifest(existing_paths=None):
    """Return generated component drop/wiring module files and whether they exist."""
    paths = set(existing_paths) if existing_paths is not None else _local_component_paths()
    modules = (
        ("component_drop_payload_module", "drop_payloads"),
        ("component_drop_target_module", "drop_targets"),
        ("component_event_wiring_module", "event_wiring"),
        ("component_handler_definition_module", "handler_definitions"),
    )
    exports = (
        "module_contract",
        "component_wiring_manifest",
        "run_wiring_operation",
        "runtime_manifest",
        "smoke_test",
    )
    manifest = []
    for module, kind in modules:
        path = f"app/component_wiring_modules/{{module}}.py"
        manifest.append({{
            "module": module,
            "kind": kind,
            "path": path,
            "exists": path in paths,
            "exports": exports,
            "ok": bool(module) and bool(kind) and path in paths,
        }})
    return {{
        "format": "appgen.generated-component-wiring-module-file-manifest.v1",
        "ok": bool(manifest) and all(item["ok"] for item in manifest),
        "modules": tuple(manifest),
        "guards": ("one_file_per_wiring_surface", "declared_exports_present", "module_smoke_replays"),
        "side_effects": (),
    }}


