        {{"id": "api_breadth", "ok": {{"camera", "photos", "location", "sensors", "biometrics", "push_notifications", "contacts", "calendar", "secure_storage", "bluetooth", "nfc", "file_picker", "share_sheet", "background_tasks", "microphone", "audio_player", "video_player", "haptics", "vibration", "clipboard", "deep_links", "app_lifecycle", "network_status", "filesystem", "device_info", "maps", "screen_capture"}} <= api_set, "evidence": contract["apis"]}},
        {{"id": "permission_manifest", "ok": api_set <= permission_apis and "least_privilege" in contract["permission_manifest"]["guards"], "evidence": contract["permission_manifest"]}},
        {{"id": "component_adapters", "ok": api_set <= adapter_apis and all(adapter["events"] and {{"android", "ios"}} & set(adapter["targets"]) for adapter in contract["component_adapters"]["adapters"]), "evidence": contract["component_adapters"]}},
        {{"id": "simulator_profiles", "ok": {{"phone_portrait", "tablet", "desktop_touch"}} <= set(contract["simulator"]["profiles"]) and {{"permissions", "orientation", "sensor_stream"}} <= set(contract["simulator"]["scenario_controls"]), "evidence": contract["simulator"]}},
        {{"id": "simulator_fixture_coverage", "ok": api_set <= fixture_apis, "evidence": contract["simulator"]["fixtures"]}},
        {{"id": "side_effect_guards", "ok": not contract["simulator"]["side_effects"] and {{"permission_manifest_generated", "runtime_permission_prompt"}} <= set(contract["guards"]), "evidence": {{"guards": contract["guards"], "simulator": contract["simulator"]["side_effects"]}}}},
        {{"id": "permission_prompt_workflow", "ok": permission_workflow["ok"] and {{"show_reviewable_prompt", "dispatch_result"}} <= set(permission_workflow["steps"]) and not permission_workflow["side_effects"], "evidence": permission_workflow}},
        {{"id": "adapter_dispatch_workflow", "ok": adapter_dispatch["ok"] and {{"check_permission", "emit_component_event"}} <= set(adapter_dispatch["pipeline"]) and not adapter_dispatch["side_effects"], "evidence": adapter_dispatch}},
        {{"id": "simulator_replay_workflow", "ok": simulator_replay["ok"] and {{"load_fixture", "assert_component_events"}} <= set(simulator_replay["scenario"]) and not simulator_replay["side_effects"], "evidence": simulator_replay}},
        {{"id": "platform_fallback_workflow", "ok": platform_fallback["ok"] and "designer_warning_visible" in platform_fallback["guards"] and not platform_fallback["side_effects"], "evidence": platform_fallback}},
        {{"id": "privacy_review_workflow", "ok": api_set <= set(privacy_review["apis"]) and {{"purpose_string", "least_privilege"}} <= set(privacy_review["review_items"]) and not privacy_review["side_effects"], "evidence": privacy_review}},
        {{"id": "background_resume_workflow", "ok": {{"persist_checkpoint", "resume_foreground"}} <= set(background_resume["schedule"]) and not background_resume["side_effects"], "evidence": background_resume}},
        {{"id": "actionable_mobile_api_operations", "ok": actionable_operations["ok"] and {{"request_permission", "dispatch_adapter", "replay_simulator", "review_platform_fallback", "review_privacy", "resume_background", "validate_device_component"}} <= set(actionable_operations["operations"]) and not actionable_operations["side_effects"], "evidence": actionable_operations}},
        {{"id": "device_component_specs", "ok": device_component_specs["ok"] and api_set == {{spec["api"] for spec in device_component_specs["specs"]}} and all({{"permission_editor", "simulator_fixture_picker", "event_trace_viewer"}} <= set(spec["design_tools"]) for spec in device_component_specs["specs"]) and not device_component_specs["side_effects"], "evidence": device_component_specs}},
