def snap_to_grid(value, minimum=0):
    """Snap browser drop coordinates to the generated form grid."""
    return max(int(minimum), int(round(float(value or 0))))


def form_catalog():
    """Return generated form designer catalog entries."""
    return tuple({{"table": name, "label": spec["label"], "field_count": len(spec["fields"])}} for name, spec in FORM_TABLES.items())


def _palette_spec(component_type):
    for spec in PALETTE:
        if spec["type"] == component_type:
            return spec
    raise KeyError(f"Unknown component type: {{component_type}}")


def _dfm_identifier(field, component_type):
    base = f"{{field or component_type}}_{{component_type}}"
    cleaned = re.sub(r"[^A-Za-z0-9_]", "_", base)
    if not cleaned or cleaned[0].isdigit():
        cleaned = f"AppGen_{{cleaned}}"
    return cleaned


