def _dfm_value(value):
    value = value.strip()
    if value.startswith("'") and value.endswith("'"):
        return value[1:-1].replace("''", "'")
    if value.isdigit() or (value.startswith("-") and value[1:].isdigit()):
        return int(value)
    return value


def _pascal_identifier(value):
    cleaned = re.sub(r"[^A-Za-z0-9_]", "_", value)
    if not cleaned or cleaned[0].isdigit():
        cleaned = f"AppGen_{{cleaned}}"
    return cleaned


def _module_name(name):
    chars = []
    for index, char in enumerate(name.replace("-", "_")):
        if char.isupper() and index and (not name[index - 1].isupper()):
            chars.append("_")
        chars.append(char.lower() if char.isalnum() else "_")
    return "_".join(part for part in "".join(chars).split("_") if part)


def _component_package(package_id):
    for package in THIRD_PARTY_COMPONENT_SUITES:
        if package["id"] == package_id:
            return package
    raise KeyError(f"Unknown component package: {{package_id}}")


def _property_editor_descriptor(name, component_type, category):
    editor = _property_editor_type(name)
    if name in ("items", "columns", "tabs", "actions", "series", "fields"):
        editor = "collection"
    elif name in ("data_source", "dataset", "bindings", "target_table"):
        editor = "binding"
    elif name in ("fill", "stroke", "color", "start_color", "end_color"):
        editor = "color"
    elif name in ("source", "resources", "theme", "style_books", "mesh", "material"):
        editor = "resource"
    elif name in ("align", "direction", "orientation_mode", "light_type", "effect", "easing"):
        editor = "choice"
    return {{
        "name": name,
        "editor": editor,
        "component": component_type,
        "category": category,
        "default": _default_property_value(name, component_type, category),
        "supports_reset": True,
        "supports_binding": category in ("input", "choice", "calendar", "data", "data_access", "media", "graphics"),
    }}


def _binding_property(component_type):
    category = _component_category(component_type)
    if category in ("input", "choice", "calendar", "relationship"):
        return "value"
    if category in ("data", "data_access", "analytics", "reports"):
        return "dataset"
    if category in ("media", "graphics"):
        return "source"
    return "caption"


def _local_component_paths():
    root = Path(__file__).resolve().parent
    paths = set()
    for folder in (
        "component_contracts",
        "component_packages",
        "component_tests",
        "component_package_tests",
        "component_family_modules",
        "component_family_module_tests",
        "component_wiring_modules",
        "component_wiring_module_tests",
        "handler_architecture_modules",
        "handler_architecture_module_tests",
    ):
        base = root / folder
        if not base.exists():
            continue
        for path in base.glob("*.py"):
            if path.name == "__init__.py":
                continue
            paths.add(f"app/{{folder}}/{{path.name}}")
    return paths


