def _component_validation_rules(component_type, category):
    rules = ["within_canvas_bounds", "stable_component_id", "known_property_names"]
    if category in ("input", "choice", "calendar", "relationship", "data", "analytics", "reports", "media", "data_access"):
        rules.append("binding_or_field_reviewed")
    if category in ("mobile", "integration", "data", "data_access"):
        rules.append("permission_or_secret_reviewed")
    if category in ("effects", "three_d", "graphics"):
        rules.append("performance_budget_declared")
    if category in ("theme", "gesture"):
        rules.append("target_surface_declared")
    if category == "menu":
        rules.append("role_visibility_reviewed")
    if category == "app_shell":
        rules.append("startup_preview_reviewed")
    return tuple(rules)


def field_component(table_name, field_name):
    """Return the default component for a table field."""
    field = next(item for item in FORM_TABLES[table_name]["fields"] if item["name"] == field_name)
    normalized = field["type"].lower()
    if field["references"]:
        component_type = "RelationshipPicker"
    elif normalized in {{"text", "longtext", "textarea"}}:
        component_type = "TextArea"
    elif normalized in {{"image", "photo", "picture"}}:
        component_type = "ImageUpload"
    elif normalized in {{"file", "upload", "document", "attachment", "blob", "binary", "bytea"}}:
        component_type = "FileUpload"
    elif normalized in {{"bool", "boolean"}}:
        component_type = "Checkbox"
    elif normalized in {{"datetime", "timestamp", "timestamptz"}}:
        component_type = "DateTimePicker"
    elif normalized == "time":
        component_type = "TimePicker"
    elif "date" in normalized:
        component_type = "DatePicker"
    elif normalized in {{"int", "integer", "float", "decimal", "numeric", "money"}}:
        component_type = "NumberInput"
    else:
        component_type = "TextBox"
    return {{"field": field_name, "type": component_type, "required": field["required"]}}


def drop_component(table_name, component_type, field=None, x=0, y=0, w=None, h=None, props=None):
    """Return a dropped form component instance."""
    spec = _palette_spec(component_type)
    defaults = spec["defaults"]
    width = max(1, int(w if w is not None else defaults["w"]))
    height = max(1, int(h if h is not None else defaults["h"]))
    left = min(snap_to_grid(x), max(0, CANVAS_COLUMNS - width))
    top = snap_to_grid(y)
    return {{
        "id": f"{{table_name}}_{{field or component_type}}_{{left}}_{{top}}".lower(),
        "table": table_name,
        "type": component_type,
        "field": field,
        "x": left,
        "y": top,
        "w": width,
        "h": height,
        "props": dict(props or {{}}),
    }}


def component_bounds(component):
    """Return a RAD-style grid rectangle for one component."""
    left = int(component.get("x", 0))
    top = int(component.get("y", 0))
    width = int(component.get("w", 1))
    height = int(component.get("h", 1))
    return {{"left": left, "top": top, "right": left + width, "bottom": top + height}}


def components_overlap(left_component, right_component):
    """Return whether two form components overlap on the grid."""
    left = component_bounds(left_component)
    right = component_bounds(right_component)
    return not (
        left["right"] <= right["left"]
        or right["right"] <= left["left"]
        or left["bottom"] <= right["top"]
        or right["bottom"] <= left["top"]
    )


def layout_conflicts(components):
    """Return deterministic overlap conflicts for a generated form design."""
    rows = tuple(components or ())
    conflicts = []
    for index, component in enumerate(rows):
        for other in rows[index + 1:]:
            if components_overlap(component, other):
                conflicts.append({{
                    "component": component.get("id"),
                    "overlaps": other.get("id"),
                }})
    return tuple(conflicts)


def property_sheet(component):
    """Return editable property descriptors for a dropped component."""
    return (
        {{"name": "field", "type": "field", "value": component.get("field")}},
        {{"name": "x", "type": "number", "value": component.get("x")}},
        {{"name": "y", "type": "number", "value": component.get("y")}},
        {{"name": "w", "type": "number", "value": component.get("w")}},
        {{"name": "h", "type": "number", "value": component.get("h")}},
        {{"name": "type", "type": "component", "value": component.get("type")}},
    )


def placement_suggestion(design, component_type, field=None):
    """Return the next non-overlapping placement for a new component."""
    components = tuple(design.get("components", ()))
    spec = _palette_spec(component_type)
    height = spec["defaults"]["h"]
    y = 0
    if components:
        y = max(int(component.get("y", 0)) + int(component.get("h", 1)) for component in components) + 1
    component = drop_component(design["table"], component_type, field=field, x=0, y=y)
    canvas = dict(design.get("canvas", {{}}))
    canvas["rows"] = max(int(canvas.get("rows", MIN_CANVAS_ROWS)), y + height + 2)
    return {{"component": component, "canvas": canvas}}


def form_design(table_name):
    """Return a generated RAD-style design surface for a table."""
    table_spec = FORM_TABLES[table_name]
    database_columns = tuple(field["name"] for field in table_spec["fields"])
    calculated_columns = tuple(field["name"] for field in table_spec.get("calculated_fields", ()))
    declared = DECLARED_DESIGNS.get(table_name)
    if declared:
        components = tuple(declared["components"])
        rows = max((int(component.get("y", 0)) + int(component.get("h", 1)) for component in components), default=10)
        return {{"table": table_name, "source_view": declared["view"], "database_backed": True, "database_columns": database_columns, "calculated_columns": calculated_columns, "canvas": {{"columns": CANVAS_COLUMNS, "rows": max(MIN_CANVAS_ROWS, rows + 2), "grid": GRID_SIZE}}, "components": components}}
    components = []
    y = 0
    for field in table_spec["fields"]:
        mapping = field_component(table_name, field["name"])
        components.append(drop_component(table_name, mapping["type"], field=field["name"], x=0, y=y))
        y += 2
    return {{"table": table_name, "database_backed": True, "database_columns": database_columns, "calculated_columns": calculated_columns, "canvas": {{"columns": CANVAS_COLUMNS, "rows": max(MIN_CANVAS_ROWS, y + 2), "grid": GRID_SIZE}}, "components": tuple(components)}}


def _field_names(values):
    """Normalize field references from component properties or section lists."""
    if values is None:
        return ()
    if isinstance(values, str):
        return (values,) if values else ()
    if isinstance(values, dict):
        name = values.get("field") or values.get("name")
        return (str(name),) if name else ()
    names = []
    if isinstance(values, (tuple, list, set)):
        for item in values:
            names.extend(_field_names(item))
    return tuple(names)


def _form_field_references(design):
    """Return every database-field reference made by a form design."""
    references = []
    for component in design.get("components", ()):
        component_id = component.get("id") or component.get("field") or component.get("type")
        for field in _field_names(component.get("field")):
            references.append({{"source": "component.field", "component": component_id, "field": field}})
        props = component.get("props") or {{}}
        for prop_name in ("field", "data_field", "label_field", "parent_field", "fields", "columns", "bindings"):
            for field in _field_names(props.get(prop_name)):
                references.append({{
                    "source": f"component.props.{{prop_name}}",
                    "component": component_id,
                    "field": field,
                }})
    for section in design.get("sections", ()):
        for field in _field_names(section.get("fields")):
            references.append({{"source": "section.fields", "section": section.get("name"), "field": field}})
    return tuple(references)


def database_backed_form_column_guard(design):
    """Ensure database-backed forms only bind persisted or calculated columns."""
    database_backed = bool(design.get("database_backed") or design.get("database_columns"))
    persistent_columns = tuple(design.get("database_columns", ()))
    calculated_columns = tuple(design.get("calculated_columns", ()))
    allowed = set(persistent_columns) | set(calculated_columns)
    references = _form_field_references(design) if database_backed else ()
    unknown = tuple(reference for reference in references if reference["field"] not in allowed)
    return {{
        "format": "appgen.database-backed-form-column-guard.v1",
        "database_backed": database_backed,
        "persistent_columns": persistent_columns,
        "calculated_columns": calculated_columns,
        "allowed_columns": tuple(sorted(allowed)),
        "referenced_columns": tuple(reference["field"] for reference in references),
        "unknown_references": unknown,
        "guards": (
            "persistent_columns_from_schema",
            "calculated_columns_declared",
            "component_bindings_checked",
            "section_fields_checked",
        ),
        "ok": not database_backed or (bool(allowed) and not unknown),
    }}


def validate_form_design(design):
    """Validate bounds, duplicate IDs, overlaps, and database-field bindings."""
    errors = []
    seen = set()
    canvas = design.get("canvas", {{}})
    columns = int(canvas.get("columns", CANVAS_COLUMNS))
    rows = int(canvas.get("rows", MIN_CANVAS_ROWS))
    for component in design.get("components", ()):
        if component.get("type") not in {{item["type"] for item in PALETTE}}:
            errors.append(f"unknown component {{component.get('type')}}")
        if component.get("id") in seen:
            errors.append(f"duplicate component {{component.get('id')}}")
        seen.add(component.get("id"))
        bounds = component_bounds(component)
        if int(component.get("w", 0)) <= 0 or int(component.get("h", 0)) <= 0:
            errors.append(f"invalid size {{component.get('id')}}")
        if bounds["left"] < 0 or bounds["top"] < 0 or bounds["right"] > columns or bounds["bottom"] > rows:
            errors.append(f"out of bounds {{component.get('id')}}")
    conflicts = layout_conflicts(design.get("components", ()))
    for conflict in conflicts:
        errors.append(f"overlap {{conflict['component']}} {{conflict['overlaps']}}")
    column_guard = database_backed_form_column_guard(design)
    for reference in column_guard["unknown_references"]:
        errors.append(f"unknown database field {{reference['field']}}")
    return {{"ok": not errors, "errors": tuple(errors), "conflicts": conflicts, "database_column_guard": column_guard}}


def proposal_from_drop(payload):
    """Convert a browser drag/drop payload into a stable form proposal."""
    table = payload["table"]
    component_type = payload["component"]
    component = drop_component(table, component_type, payload.get("field"), payload.get("x", 0), payload.get("y", 0), payload.get("w"), payload.get("h"), payload.get("props"))
    return {{"kind": "drop_component", "component": component, "properties": property_sheet(component)}}


def apply_form_proposal(design, proposal):
    """Apply a form-designer proposal to a design copy."""
    components = list(design.get("components", ()))
    if proposal.get("kind") == "drop_component":
        components.append(proposal["component"])
    return dict(design, components=tuple(components))


def form_designer_check(existing_paths):
    """Return readiness for generated form designer artifacts."""
    existing = set(existing_paths)
    required = ("app/form_designer.py", "app/templates/appgen_form_designer.html")
    missing = tuple(path for path in required if path not in existing)
    return {{"ok": not missing, "missing": missing, "palette": tuple(item["type"] for item in PALETTE)}}


