def evolution_capabilities():
    """Return app areas that natural language can evolve."""
    return ("tables", "fields", "forms", "workflows", "rules", "reports", "dashboards", "chatbots", "agents", "targets", "erp_modules")


def destructive_intent_report(prompt):
    """Return explicit destructive-change requests detected in a natural-language prompt."""
    text = str(prompt or "")
    removals = []
    for match in re.finditer(r"\\b(?:delete|drop|remove)\\s+(?:the\\s+)?table\\s+([A-Za-z_][A-Za-z0-9_]*)", text, re.I):
        removals.append({{"kind": "remove_table", "table": match.group(1), "destructive": True}})
    for match in re.finditer(
        r"\\b(?:delete|drop|remove)\\s+(?:the\\s+)?(?:field|column)\\s+([A-Za-z_][A-Za-z0-9_]*)(?:\\s+(?:from|on|in)\\s+([A-Za-z_][A-Za-z0-9_]*))?",
        text,
        re.I,
    ):
        removals.append({{"kind": "remove_field", "field": match.group(1), "table": match.group(2) or None, "destructive": True}})
    return {{
        "format": "appgen.nl-destructive-intent.v1",
        "destructive": bool(removals),
        "items": tuple(removals),
        "requires_backup": bool(removals),
        "requires_data_loss_review": bool(removals),
    }}


def _field_type(name, context):
    """Infer a practical DSL field type from a field name and nearby words."""
    text = f"{{name}} {{context}}".lower()
    if name.lower().endswith("_id") or " reference " in f" {{text}} " or " references " in f" {{text}} ":
        return "int"
    if any(word in text for word in ("description", "summary", "notes", "note", "comment")):
        return "text"
    if any(word in text for word in ("amount", "price", "total", "balance", "rate", "cost")):
        return "decimal"
    if any(word in text for word in ("count", "quantity", "qty", "number")):
        return "int"
    if "email" in text:
        return "email"
    if "datetime" in text or "timestamp" in text:
        return "datetime"
    if "date" in text:
        return "date"
    return "string"


def _field_modifiers(name, context):
    """Infer common field modifiers from natural language."""
    text = f"{{name}} {{context}}".lower()
    modifiers = []
    if "required" in text or name.lower() in ("name", "title"):
        modifiers.append("required")
    if "unique" in text or name.lower() in ("email", "code", "sku"):
        modifiers.append("unique")
    if "search" in text or "searchable" in text or name.lower() in ("name", "title", "code", "sku", "email"):
        modifiers.append("search")
    return tuple(dict.fromkeys(modifiers))


def _field_reference(name, context):
    """Infer a known table reference for relationship-like field prompts."""
    text = f"{{name}} {{context}}".lower()
    explicit = re.search(r"\\b(?:ref|reference|references|to)\\s+([A-Za-z_][A-Za-z0-9_]*)", context, re.I)
    candidates = []
    if explicit:
        candidates.append(explicit.group(1))
    if name.lower().endswith("_id"):
        candidates.append(name[:-3])
    for table in KNOWN_TABLES:
        table_lower = table.lower()
        for candidate in candidates:
            if candidate and candidate.lower() == table_lower:
                return {{"table": table, "column": "id"}}
        if re.search(rf"\\b{{re.escape(table_lower)}}\\b", text) and any(word in text for word in ("ref", "reference", "references", "relationship", "belongs", "parent")):
            return {{"table": table, "column": "id"}}
    return None


def _field_cardinality(context):
    text = context.lower().replace("_", "-")
    for value in ("one-to-one", "one-to-many", "many-to-many", "many-to-one"):
        if value in text:
            return value
    if "unique" in text:
        return "one-to-one"
    return "many-to-one"


def _field_specs(text):
    """Extract one or more field proposals from a natural-language prompt."""
    specs = []
    for match in re.finditer(r"(?:fields?|columns?)\\s+([^.;]+)", text, re.I):
        segment = match.group(1)
        segment = re.split(
            r"\\b(?:form|workflow|flow|rule|policy|report|reports|dashboard|dashboards|chart|analytics|chatbot|agent|targets?|platforms?)\\b",
            segment,
            maxsplit=1,
            flags=re.I,
        )[0]
        for raw_item in re.split(r",|\\band\\b", segment, flags=re.I):
            item = raw_item.strip()
            if not item:
                continue
            words = re.findall(r"[A-Za-z_][A-Za-z0-9_]*", item)
            if not words:
                continue
            name = words[0]
            if name.lower() in {{"required", "unique", "search", "searchable", "text", "decimal", "int", "integer", "string"}}:
                continue
            specs.append({{
                "name": name,
                "type": _field_type(name, item),
                "modifiers": _field_modifiers(name, item),
                "references": _field_reference(name, item),
                "cardinality": _field_cardinality(item),
            }})
    seen = set()
    unique_specs = []
    for spec in specs:
        if spec["name"] in seen:
            continue
        seen.add(spec["name"])
        unique_specs.append(spec)
    return tuple(unique_specs)


def _target_specs(text):
    """Extract platform targets from explicit target/platform phrases only."""
    match = re.search(r"\\b(?:targets?|platforms?)\\s+([^.;]+)", text, re.I)
    if not match:
        return ()
    segment = match.group(1).lower()
    return tuple(
        target
        for target in ("web", "pwa", "mobile", "desktop", "chatbot")
        if re.search(rf"\\b{{target}}\\b", segment)
    )


def _erp_module_specs(text):
    """Extract ERP module requests from natural-language prompts."""
    lowered = text.lower()
    selected = []
    for stack, modules in ERP_STACKS.items():
        if re.search(rf"\\b{{re.escape(stack)}}\\b", lowered):
            selected.extend(modules)
    for alias, module in ERP_MODULE_ALIASES.items():
        if re.search(rf"\\b{{re.escape(alias)}}\\b", lowered):
            selected.append(module)
    ordered = []
    for module in selected:
        if module not in ordered:
            ordered.append(module)
    return tuple(ordered)


def evolution_plan(prompt):
    """Convert natural language into auditable low-code change proposals."""
    text = prompt.strip()
    lowered = text.lower()
    proposals = []
    destructive = destructive_intent_report(text)
    table_match = re.search(r"(?:table|entity)\\s+([A-Za-z_][A-Za-z0-9_]*)", text, re.I)
    field_specs = _field_specs(text)
    form_match = re.search(r"form\\s+([A-Za-z_][A-Za-z0-9_]*)", text, re.I)
    workflow_match = re.search(r"(?:workflow|flow)\\s+([A-Za-z_][A-Za-z0-9_]*)", text, re.I)
    transition_match = re.search(r"(?:from\\s+)?([A-Za-z_][A-Za-z0-9_]*)\\s+(?:to|->)\\s+([A-Za-z_][A-Za-z0-9_]*)", text, re.I)
    rule_match = re.search(r"(?:rule|policy)\\s+([A-Za-z_][A-Za-z0-9_]*)", text, re.I)
    report_match = re.search(r"reports?\\s+([A-Za-z_][A-Za-z0-9_]*)", text, re.I)
    dashboard_match = re.search(r"dashboards?\\s+([A-Za-z_][A-Za-z0-9_]*)", text, re.I)
    chatbot_match = re.search(r"chatbot\\s+([A-Za-z_][A-Za-z0-9_]*)", text, re.I)
    agent_match = re.search(r"agent\\s+([A-Za-z_][A-Za-z0-9_]*)", text, re.I)
    target_matches = _target_specs(text)
    erp_modules = _erp_module_specs(text)
    target_table = table_match.group(1) if table_match else (KNOWN_TABLES[0] if KNOWN_TABLES else "Generated")
    if table_match and any(word in lowered for word in ("create", "add", "generate", "build")):
        proposals.append({{"kind": "add_table", "name": target_table, "source": "natural_language"}})
    for item in destructive["items"]:
        if item["kind"] == "remove_table":
            proposals.append({{"kind": "remove_table", "name": item["table"], "destructive": True, "source": "natural_language"}})
        elif item["kind"] == "remove_field":
            proposals.append({{"kind": "remove_field", "table": item["table"] or target_table, "name": item["field"], "destructive": True, "source": "natural_language"}})
    for field_spec in field_specs:
        proposals.append({{"kind": "add_field", "table": target_table, "name": field_spec["name"], "type": field_spec["type"], "modifiers": field_spec["modifiers"], "references": field_spec["references"], "cardinality": field_spec["cardinality"], "source": "natural_language"}})
    if form_match or "form" in lowered:
        proposals.append({{"kind": "add_form", "table": target_table, "name": (form_match.group(1) if form_match else f"{{target_table}}Form"), "source": "natural_language"}})
    if workflow_match or "workflow" in lowered or "flow" in lowered:
        source, target = transition_match.groups() if transition_match else ("draft", "approved")
        proposals.append({{"kind": "add_workflow", "name": (workflow_match.group(1) if workflow_match else f"{{target_table}}Workflow"), "source_state": source, "target_state": target, "source": "natural_language"}})
    if rule_match or "rule" in lowered or "required" in lowered:
        required_field = field_specs[0]["name"] if field_specs else "title"
        proposals.append({{"kind": "add_rule", "name": (rule_match.group(1) if rule_match else f"{{target_table}}Policy"), "table": target_table, "field": required_field, "operator": "required", "source": "natural_language"}})
    if report_match or "report" in lowered or "reports" in lowered:
        proposals.append({{"kind": "add_report", "name": (report_match.group(1) if report_match else f"{{target_table}}Report"), "table": target_table, "formats": ("csv", "pdf"), "source": "natural_language"}})
    if dashboard_match or "dashboard" in lowered or "dashboards" in lowered or "analytics" in lowered:
        proposals.append({{"kind": "add_dashboard", "name": (dashboard_match.group(1) if dashboard_match else f"{{target_table}}Dashboard"), "table": target_table, "charts": ("kpi", "bar"), "source": "natural_language"}})
    if chatbot_match or "chatbot" in lowered:
        proposals.append({{"kind": "add_chatbot", "name": (chatbot_match.group(1) if chatbot_match else f"{{target_table}}Assistant"), "table": target_table, "source": "natural_language"}})
    if agent_match or "agent" in lowered:
        proposals.append({{"kind": "add_agent", "name": (agent_match.group(1) if agent_match else f"{{target_table}}Agent"), "provider": "local_default", "tools": ("schema", "forms", "chatbots"), "source": "natural_language"}})
    for module in erp_modules:
        proposals.append({{"kind": "add_erp_module", "module": module, "uses": "app/erp_templates.py", "source": "natural_language"}})
    if "target" in lowered or "platform" in lowered or "generate" in lowered:
        selected_targets = target_matches or ("web", "mobile", "desktop")
        proposals.append({{"kind": "set_targets", "targets": selected_targets, "source": "natural_language"}})
    return {{"prompt": text, "capabilities": evolution_capabilities(), "destructive_intent": destructive, "proposals": tuple(proposals)}}


def _field_dsl_line(proposal):
    modifiers = " ".join(proposal.get("modifiers", ()))
    suffix = f" {{modifiers}}" if modifiers else ""
    reference = proposal.get("references")
    relation = ""
    if reference:
        relation = f" -> {{reference['table']}}.{{reference.get('column', 'id')}} [{{proposal.get('cardinality') or 'many-to-one'}}]"
    return f"  {{proposal['name']}}: {{proposal['type']}}{{relation}}{{suffix}}"


def proposals_to_dsl(plan):
    """Render natural-language proposals as compact AppGen DSL snippets."""
    lines = []
    proposals = tuple(plan.get("proposals", ()))
    new_tables = {{proposal["name"] for proposal in proposals if proposal["kind"] == "add_table"}}
    fields_by_table = {{}}
    for proposal in proposals:
        if proposal["kind"] == "add_field":
            fields_by_table.setdefault(proposal["table"], []).append(proposal)
    for proposal in proposals:
        if proposal["kind"] == "add_table":
            field_lines = [_field_dsl_line(field) for field in fields_by_table.get(proposal["name"], ())]
            body = "\\n".join(("  id: int pk", *field_lines))
            lines.append(f"table {{proposal['name']}} {{{{\\n{{body}}\\n}}}}")
        elif proposal["kind"] == "add_field":
            if proposal["table"] in new_tables:
                continue
            modifiers = " ".join(proposal.get("modifiers", ()))
            suffix = f" {{modifiers}}" if modifiers else ""
            reference = proposal.get("references")
            relation = ""
            if reference:
                relation = f" -> {{reference['table']}}.{{reference.get('column', 'id')}} [{{proposal.get('cardinality') or 'many-to-one'}}]"
            lines.append(f"// add field {{proposal['table']}}.{{proposal['name']}}: {{proposal['type']}}{{relation}}{{suffix}}")
        elif proposal["kind"] == "add_workflow":
            lines.append(f"flow {{proposal['name']}} {{{{\\n  {{proposal['source_state']}} -> {{proposal['target_state']}};\\n}}}}")
        elif proposal["kind"] == "add_rule":
            lines.append(f"rule {{proposal['name']}} for {{proposal['table']}} {{{{\\n  {{proposal['field']}} {{proposal['operator']}};\\n}}}}")
        elif proposal["kind"] == "add_agent":
            lines.append(f"agent {{proposal['name']}} {{{{\\n  provider: {{proposal['provider']}}\\n  tools: schema, forms, chatbots\\n}}}}")
        elif proposal["kind"] == "add_chatbot":
            lines.append(f"// add chatbot {{proposal['name']}} for {{proposal['table']}}")
        elif proposal["kind"] == "add_report":
            lines.append(f"// add report {{proposal['name']}} for {{proposal['table']}} formats {{', '.join(proposal['formats'])}}")
        elif proposal["kind"] == "add_dashboard":
            lines.append(f"// add dashboard {{proposal['name']}} for {{proposal['table']}} charts {{', '.join(proposal['charts'])}}")
        elif proposal["kind"] == "add_form":
            lines.append(f"view {{proposal['name']}} for {{proposal['table']}} {{{{\\n}}}}")
        elif proposal["kind"] == "add_erp_module":
            lines.append(f"// add ERP module {{proposal['module']}} with erp_templates.erp_module_dsl('{{proposal['module']}}')")
        elif proposal["kind"] == "remove_table":
            lines.append(f"// destructive: remove table {{proposal['name']}} after backup and data-loss review")
        elif proposal["kind"] == "remove_field":
            lines.append(f"// destructive: remove field {{proposal['table']}}.{{proposal['name']}} after backup and data-loss review")
        elif proposal["kind"] == "set_targets":
            lines.append("app Generated {{ targets: " + ", ".join(proposal["targets"]) + " }}")
    return "\\n\\n".join(lines)


def proposal_summary(plan):
    """Return deterministic proposal counts by generated change kind."""
    counts = {{}}
    for proposal in plan.get("proposals", ()):
        kind = proposal.get("kind", "unknown")
        counts[kind] = counts.get(kind, 0) + 1
    return {{
        "proposal_count": sum(counts.values()),
        "kinds": counts,
        "tables": tuple(
            proposal.get("name") or proposal.get("table")
            for proposal in plan.get("proposals", ())
            if proposal.get("kind") in {{"add_table", "add_field", "add_form", "add_report", "add_dashboard"}}
        ),
    }}


def migration_impact(plan):
    """Return review metadata for database-impacting natural-language changes."""
    ddl = []
    data = []
    review = []
    for proposal in plan.get("proposals", ()):
        kind = proposal.get("kind")
        if kind == "add_table":
            ddl.append({{"action": "create_table", "table": proposal["name"], "destructive": False}})
        elif kind == "add_field":
            ddl.append({{
                "action": "add_column",
                "table": proposal["table"],
                "field": proposal["name"],
                "type": proposal["type"],
                "destructive": False,
                "requires_backfill": "required" in proposal.get("modifiers", ()) and proposal.get("table") in KNOWN_TABLES,
            }})
        elif kind in {{"add_form", "add_chatbot", "add_agent", "add_report", "add_dashboard", "set_targets"}}:
            review.append({{"action": kind, "destructive": False}})
        elif kind == "add_erp_module":
            review.append({{"action": "add_erp_module", "module": proposal["module"], "destructive": False, "requires_migration_preview": True}})
        elif kind == "remove_table":
            ddl.append({{"action": "drop_table", "table": proposal["name"], "destructive": True, "requires_backup": True}})
            data.append({{"action": "export_table_backup", "table": proposal["name"], "destructive": False}})
        elif kind == "remove_field":
            ddl.append({{"action": "drop_column", "table": proposal["table"], "field": proposal["name"], "destructive": True, "requires_backup": True}})
            data.append({{"action": "export_column_backup", "table": proposal["table"], "field": proposal["name"], "destructive": False}})
    return {{
        "format": "appgen.nl-migration-impact.v1",
        "ddl": tuple(ddl),
        "data": tuple(data),
        "review": tuple(review),
        "requires_review": bool(ddl or review),
        "destructive": any(item.get("destructive") for item in (*ddl, *data, *review)),
    }}


def _app_target_patch(targets):
    return "targets: " + ", ".join(targets)


def _apply_target_patch(base_dsl, targets):
    """Apply target metadata to an existing app declaration when possible."""
    text = base_dsl.strip()
    if not text:
        return "app Generated {{ " + _app_target_patch(targets) + " }}"
    pattern = re.compile(r"\\bapp\\s+([A-Za-z_][A-Za-z0-9_]*)\\s*(?:\\{{(?P<body>[^}}]*)\\}})?", re.S)
    match = pattern.search(text)
    if not match:
        return "app Generated {{ " + _app_target_patch(targets) + " }}\\n\\n" + text
    app_name = match.group(1)
    body = match.group("body")
    if body is None:
        replacement = f"app {{app_name}} {{{{ {{_app_target_patch(targets)}} }}}}"
    elif re.search(r"\\btargets\\s*:", body):
        replacement_body = re.sub(r"\\btargets\\s*:\\s*[^;}}\\n]+", _app_target_patch(targets), body)
        replacement = f"app {{app_name}} {{{{ {{replacement_body.strip()}} }}}}"
    else:
        separator = "; " if body.strip() else ""
        replacement = f"app {{app_name}} {{{{ {{body.strip()}}{{separator}}{{_app_target_patch(targets)}} }}}}"
    return text[:match.start()] + replacement + text[match.end():]


def evolution_test_plan(plan):
    """Return generated checks for a natural-language evolution plan."""
    kinds = tuple(proposal.get("kind") for proposal in plan.get("proposals", ()))
    checks = ["dsl_lint", "migration_impact", "generated_tests"]
    if any(kind in {{"add_table", "add_field", "remove_table", "remove_field"}} for kind in kinds):
        checks.extend(("schema_diff", "migration_preview", "data_backup_review"))
    if any(kind in {{"add_form", "add_chatbot", "add_agent"}} for kind in kinds):
        checks.extend(("ui_smoke", "chatbot_conversation_preview", "agent_provider_readiness"))
    if "add_report" in kinds:
        checks.extend(("report_catalog_preview", "report_delivery_preview"))
    if "add_dashboard" in kinds:
        checks.extend(("dashboard_render_preview", "analytics_smoke"))
    if "set_targets" in kinds:
        checks.append("platform_target_generation")
    return {{
        "format": "appgen.nl-test-plan.v1",
        "checks": tuple(dict.fromkeys(checks)),
        "requires_runtime_tests": bool(kinds),
        "destructive": any(kind in {{"remove_table", "remove_field"}} for kind in kinds),
    }}


def rollback_plan(changeset):
    """Return a rollback plan for an approved natural-language change set."""
    destructive = changeset.get("migration_impact", {{}}).get("destructive", False)
    return {{
        "format": "appgen.nl-rollback-plan.v1",
        "changeset": changeset.get("id"),
        "steps": (
            "restore_previous_dsl_snapshot",
            "restore_database_backup" if destructive else "revert_generated_migration",
            "rerun_generated_tests",
        ),
        "requires_backup": bool(destructive),
        "review_required": True,
    }}


def evolution_changeset(prompt, base_dsl=""):
    """Return an approval-ready natural-language application change set."""
    plan = evolution_plan(prompt)
    proposals = tuple(plan.get("proposals", ()))
    target_proposals = tuple(proposal for proposal in proposals if proposal.get("kind") == "set_targets")
    dsl_blocks = tuple(
        block
        for block in proposals_to_dsl({{"proposals": tuple(proposal for proposal in proposals if proposal.get("kind") != "set_targets")}}).split("\\n\\n")
        if block.strip()
    )
    targets = target_proposals[-1]["targets"] if target_proposals else ()
    digest_material = "\\n".join((prompt.strip(), base_dsl.strip(), repr(proposals)))
    impact = migration_impact(plan)
    changeset = {{
        "format": "appgen.nl-changeset.v1",
        "id": "nlchg-" + sha1(digest_material.encode("utf-8")).hexdigest()[:12],
        "prompt": plan["prompt"],
        "summary": proposal_summary(plan),
        "proposals": proposals,
        "destructive_intent": plan["destructive_intent"],
        "dsl_blocks": dsl_blocks,
        "app_patch": {{"targets": targets}} if targets else None,
        "migration_impact": impact,
        "test_plan": evolution_test_plan(plan),
        "requires_approval": impact["requires_review"] or plan["destructive_intent"]["destructive"],
        "applied_preview": apply_changeset(base_dsl, {{"dsl_blocks": dsl_blocks, "app_patch": {{"targets": targets}} if targets else None}}),
    }}
    return dict(changeset, rollback=rollback_plan(changeset))


def apply_changeset(base_dsl, changeset):
    """Apply an approved generated change set to an AppGen DSL document."""
    result = (base_dsl or "").strip()
    app_patch = changeset.get("app_patch") or {{}}
    targets = tuple(app_patch.get("targets") or ())
    if targets:
        result = _apply_target_patch(result, targets)
    blocks = tuple(block.strip() for block in changeset.get("dsl_blocks", ()) if str(block).strip())
    return "\\n\\n".join(part for part in (result, *blocks) if part).strip() + ("\\n" if result or blocks else "")


def approval_workflow(changeset, actor="builder"):
    """Return a deterministic approval workflow for generated app evolution."""
    return {{
        "changeset": changeset["id"],
        "actor": actor,
        "states": ("draft", "review", "approved", "applied"),
        "current": "review" if changeset.get("requires_approval") else "approved",
        "required_checks": tuple(dict.fromkeys(("dsl_lint", "migration_impact", *changeset.get("test_plan", {{}}).get("checks", ()), "rollback_plan"))),
        "destructive": changeset.get("migration_impact", {{}}).get("destructive", False),
    }}


def nl_evolution_release_gate(existing_paths=()):
    """Return a release decision for natural-language application evolution."""
    existing = set(existing_paths)
    required = ("app/nl_evolution.py", "app/templates/appgen_nl_evolution.html")
    missing = tuple(path for path in required if path not in existing)
    sample_prompt = (
        "create table Ticket with fields title, email unique and form TicketForm "
        "workflow Triage from open to closed rule TicketPolicy report TicketReport "
        "dashboard TicketDashboard chatbot SupportBot agent SupportAgent "
        "add ERP accounts payable targets web mobile desktop"
    )
    sample_plan = evolution_plan(sample_prompt)
    sample_kinds = {{proposal["kind"] for proposal in sample_plan["proposals"]}}
    sample_changeset = evolution_changeset(sample_prompt, "app Existing {{ targets: web }}\\n")
    destructive_changeset = evolution_changeset(
        "remove field title from Ticket and drop table OldTicket",
        "app Existing {{ targets: web }}\\n\\ntable Ticket {{\\n  id: int pk\\n  title: string\\n}}\\n",
    )
    test_checks = set(sample_changeset["test_plan"]["checks"])
    expected_kinds = {{
        "add_table",
        "add_field",
        "add_form",
        "add_workflow",
        "add_rule",
        "add_report",
        "add_dashboard",
        "add_chatbot",
        "add_agent",
        "add_erp_module",
        "set_targets",
    }}
    required_checks = {{
        "dsl_lint",
        "schema_diff",
        "migration_preview",
        "ui_smoke",
        "agent_provider_readiness",
        "report_delivery_preview",
        "dashboard_render_preview",
        "platform_target_generation",
    }}
    checks = (
        {{
            "id": "artifacts_present",
            "ok": not missing,
            "evidence": {{"required": required, "missing": missing}},
        }},
        {{
            "id": "plain_language_scope",
            "ok": expected_kinds <= sample_kinds,
            "evidence": {{"expected": tuple(sorted(expected_kinds)), "sample": tuple(sorted(sample_kinds))}},
        }},
        {{
            "id": "reviewable_changeset",
            "ok": sample_changeset["requires_approval"] and sample_changeset["migration_impact"]["requires_review"] and bool(sample_changeset["dsl_blocks"]),
            "evidence": {{
                "changeset": sample_changeset["id"],
                "dsl_blocks": len(sample_changeset["dsl_blocks"]),
                "migration_review": sample_changeset["migration_impact"]["requires_review"],
            }},
        }},
        {{
            "id": "generated_test_plan",
            "ok": required_checks <= test_checks,
            "evidence": {{"required": tuple(sorted(required_checks)), "sample": tuple(sorted(test_checks))}},
        }},
        {{
            "id": "destructive_guardrails",
            "ok": destructive_changeset["destructive_intent"]["destructive"] and destructive_changeset["migration_impact"]["destructive"] and destructive_changeset["rollback"]["requires_backup"],
            "evidence": {{
                "destructive": destructive_changeset["migration_impact"]["destructive"],
                "requires_backup": destructive_changeset["rollback"]["requires_backup"],
                "checks": destructive_changeset["test_plan"]["checks"],
            }},
        }},
        {{
            "id": "target_patch_preview",
            "ok": "targets: web, mobile, desktop" in sample_changeset["applied_preview"],
            "evidence": {{"app_patch": sample_changeset["app_patch"]}},
        }},
    )
    ok = all(check["ok"] for check in checks)
    return {{
        "format": "appgen.nl-evolution-release-gate.v1",
        "ok": ok,
        "decision": "approved" if ok else "blocked",
        "checks": checks,
        "capabilities": evolution_capabilities(),
        "sample_changeset": sample_changeset["id"],
    }}


def nl_evolution_workbench(existing_paths=()):
    """Return aggregate natural-language evolution workbench evidence."""
    existing = set(existing_paths)
    required = ("app/nl_evolution.py", "app/templates/appgen_nl_evolution.html")
    missing = tuple(path for path in required if path not in existing)
    lifecycle_prompt = (
        "create table Ticket with fields title, email unique, amount decimal, author_id references Author required "
        "and form TicketForm workflow Triage from open to closed rule TicketPolicy "
        "report TicketReport dashboard TicketDashboard chatbot SupportBot agent SupportAgent "
        "generate ERP accounts payable and inventory targets web mobile desktop"
    )
    lifecycle_plan = evolution_plan(lifecycle_prompt)
    lifecycle_kinds = {{proposal["kind"] for proposal in lifecycle_plan["proposals"]}}
    lifecycle_dsl = proposals_to_dsl(lifecycle_plan)
    lifecycle_changeset = evolution_changeset(lifecycle_prompt, "app Library {{ theme: sage }}\\n")
    destructive_changeset = evolution_changeset(
        "remove field title from Ticket and drop table OldTicket",
        "app Library {{ targets: web }}\\n\\ntable Ticket {{\\n  id: int pk\\n  title: string\\n}}\\n",
    )
    approval = approval_workflow(lifecycle_changeset, actor="builder")
    impact = lifecycle_changeset["migration_impact"]
    required_capabilities = ("tables", "fields", "forms", "workflows", "rules", "reports", "dashboards", "chatbots", "agents", "targets", "erp_modules")
    required_kinds = {{
        "add_table",
        "add_field",
        "add_form",
        "add_workflow",
        "add_rule",
        "add_report",
        "add_dashboard",
        "add_chatbot",
        "add_agent",
        "add_erp_module",
        "set_targets",
    }}
    checks = (
        {{
            "id": "artifact_coverage",
            "ok": not missing,
            "evidence": {{"required": required, "missing": missing}},
        }},
        {{
            "id": "plain_language_capabilities",
            "ok": set(required_capabilities) <= set(evolution_capabilities()),
            "evidence": {{"required": required_capabilities, "available": evolution_capabilities()}},
        }},
        {{
            "id": "proposal_lifecycle_scope",
            "ok": required_kinds <= lifecycle_kinds,
            "evidence": {{"required": tuple(sorted(required_kinds)), "actual": tuple(sorted(lifecycle_kinds))}},
        }},
        {{
            "id": "dsl_patch_generation",
            "ok": all(fragment in lifecycle_dsl for fragment in ("table Ticket", "title: string", "view TicketForm", "flow Triage", "rule TicketPolicy", "agent SupportAgent", "targets: web, mobile, desktop", "erp_templates.erp_module_dsl('accounts_payable')")),
            "evidence": {{"preview": lifecycle_dsl}},
        }},
        {{
            "id": "reviewable_changesets",
            "ok": lifecycle_changeset["requires_approval"] and approval["current"] == "review" and "rollback_plan" in approval["required_checks"],
            "evidence": {{"changeset": lifecycle_changeset["id"], "approval": approval}},
        }},
        {{
            "id": "migration_impact",
            "ok": impact["requires_review"] and any(item.get("action") == "create_table" for item in impact["ddl"]) and any(item.get("action") == "add_erp_module" for item in impact["review"]),
            "evidence": impact,
        }},
        {{
            "id": "destructive_guardrails",
            "ok": destructive_changeset["destructive_intent"]["destructive"] and destructive_changeset["migration_impact"]["destructive"] and destructive_changeset["rollback"]["requires_backup"],
            "evidence": {{
                "intent": destructive_changeset["destructive_intent"],
                "impact": destructive_changeset["migration_impact"],
                "rollback": destructive_changeset["rollback"],
            }},
        }},
        {{
            "id": "existing_dsl_patch_preview",
            "ok": "app Library {{ theme: sage; targets: web, mobile, desktop }}" in lifecycle_changeset["applied_preview"] and "table Ticket" in lifecycle_changeset["applied_preview"],
            "evidence": {{"preview": lifecycle_changeset["applied_preview"]}},
        }},
        {{
            "id": "generated_test_plan",
            "ok": {{"dsl_lint", "schema_diff", "ui_smoke", "agent_provider_readiness", "report_delivery_preview", "dashboard_render_preview", "platform_target_generation"}} <= set(lifecycle_changeset["test_plan"]["checks"]),
            "evidence": lifecycle_changeset["test_plan"],
        }},
        {{
            "id": "route_surface",
            "ok": not missing,
            "evidence": {{"routes": ("/nl-evolution/", "/nl-evolution/plan", "/nl-evolution/changeset", "/nl-evolution/capabilities.json", "/nl-evolution/workbench.json", "/nl-evolution/release-gate.json")}},
        }},
    )
    ok = all(check["ok"] for check in checks)
    return {{
        "format": "appgen.nl-evolution-workbench.v1",
        "ok": ok,
        "decision": "approved" if ok else "blocked",
        "checks": checks,
        "plan": lifecycle_plan,
        "changeset": lifecycle_changeset,
        "destructive_changeset": destructive_changeset,
    }}


def nl_evolution_check(existing_paths):
    """Return readiness for natural-language evolution artifacts."""
    existing = set(existing_paths)
    required = ("app/nl_evolution.py", "app/templates/appgen_nl_evolution.html")
    missing = tuple(path for path in required if path not in existing)
    sample = evolution_plan("create table Ticket with field title and form TicketForm workflow Triage from open to closed rule TicketPolicy report TicketReport dashboard TicketDashboard chatbot SupportBot agent SupportAgent add ERP accounts payable targets web mobile desktop")
    kinds = tuple(item["kind"] for item in sample["proposals"])
    changeset = evolution_changeset("create table Ticket with field title and form TicketForm chatbot SupportBot agent SupportAgent targets web mobile desktop")
    destructive = evolution_changeset("remove field title from Ticket", "app Demo {{ targets: web }}\\n\\ntable Ticket {{\\n  id: int pk\\n  title: string\\n}}")
    return {{"ok": not missing and "add_table" in kinds and "add_report" in kinds and "add_dashboard" in kinds and "add_agent" in kinds and "add_workflow" in kinds and "add_erp_module" in kinds and "set_targets" in kinds and changeset["requires_approval"] and destructive["migration_impact"]["destructive"] and destructive["rollback"]["requires_backup"], "missing": missing, "sample_kinds": kinds}}


class NaturalLanguageEvolutionView(BaseView):
    route_base = "/nl-evolution"
    default_view = "index"

    @expose("/")
    def index(self):
        return self.render_template("appgen_nl_evolution.html", capabilities=evolution_capabilities())

    @expose("/plan", methods=("POST",))
    def plan_json(self):
        payload = request.get_json(force=True) or {{}}
        plan = evolution_plan(payload.get("prompt", ""))
        return jsonify(dict(plan, dsl=proposals_to_dsl(plan), changeset=evolution_changeset(payload.get("prompt", ""), payload.get("base_dsl", ""))))

    @expose("/changeset", methods=("POST",))
    def changeset_json(self):
        payload = request.get_json(force=True) or {{}}
        changeset = evolution_changeset(payload.get("prompt", ""), payload.get("base_dsl", ""))
        return jsonify(dict(changeset, approval=approval_workflow(changeset, payload.get("actor", "builder"))))

    @expose("/capabilities.json")
    def capabilities_json(self):
        return jsonify(list(evolution_capabilities()))

    @expose("/workbench.json")
    def workbench_json(self):
        return jsonify(nl_evolution_workbench({{"app/nl_evolution.py", "app/templates/appgen_nl_evolution.html"}}))

    @expose("/release-gate.json")
    def release_gate_json(self):
        return jsonify(nl_evolution_release_gate({{"app/nl_evolution.py", "app/templates/appgen_nl_evolution.html"}}))


