def capability_matrix():
    """Return the generated low-code feature matrix."""
    return tuple(dict(item) for item in CAPABILITIES)


def capability_lookup(key):
    """Return one generated capability by key."""
    for capability in CAPABILITIES:
        if capability["key"] == key:
            return dict(capability)
    raise KeyError(f"Unknown low-code capability: {{key}}")


def application_composition_catalog(kind=None):
    """Return reusable application-composition blocks for no-code assembly."""
    blocks = tuple(dict(item) for item in COMPOSITION_BLOCKS)
    if kind is None:
        return blocks
    return tuple(block for block in blocks if block["kind"] == kind)


def composition_dependency_graph():
    """Return a dependency graph for generated composition blocks."""
    return {{
        "format": "appgen.composition-graph.v1",
        "nodes": tuple(block["key"] for block in COMPOSITION_BLOCKS),
        "edges": tuple(
            {{"from": dependency, "to": block["key"]}}
            for block in COMPOSITION_BLOCKS
            for dependency in block["depends_on"]
        ),
    }}


def composition_dependency_audit():
    """Return topology evidence for safe reusable block installation."""
    keys = tuple(block["key"] for block in COMPOSITION_BLOCKS)
    key_set = set(keys)
    duplicate_keys = tuple(key for key in keys if keys.count(key) > 1)
    unknown_dependencies = tuple(
        {{"block": block["key"], "dependency": dependency}}
        for block in COMPOSITION_BLOCKS
        for dependency in block["depends_on"]
        if dependency not in key_set
    )
    self_dependencies = tuple(
        {{"block": block["key"], "dependency": dependency}}
        for block in COMPOSITION_BLOCKS
        for dependency in block["depends_on"]
        if dependency == block["key"]
    )
    temporary = set()
    permanent = set()
    order = []
    cycles = []

    def visit(block_key, stack):
        if block_key in permanent:
            return
        if block_key in temporary:
            cycles.append(stack + (block_key,))
            return
        temporary.add(block_key)
        block = _composition_block(block_key)
        for dependency in block["depends_on"]:
            if dependency in key_set:
                visit(dependency, stack + (block_key,))
        temporary.remove(block_key)
        permanent.add(block_key)
        order.append(block_key)

    for key in keys:
        visit(key, ())
    blocking_gaps = ()
    if duplicate_keys:
        blocking_gaps += ("duplicate_blocks",)
    if unknown_dependencies:
        blocking_gaps += ("unknown_dependencies",)
    if self_dependencies:
        blocking_gaps += ("self_dependencies",)
    if cycles:
        blocking_gaps += ("dependency_cycles",)
    return {{
        "format": "appgen.composition-dependency-audit.v1",
        "nodes": keys,
        "installation_order": tuple(dict.fromkeys(order)),
        "duplicate_blocks": duplicate_keys,
        "unknown_dependencies": unknown_dependencies,
        "self_dependencies": self_dependencies,
        "cycles": tuple(cycles),
        "blocking_gaps": blocking_gaps,
        "ok": not blocking_gaps and set(order) == key_set,
    }}


def _composition_block(block_key):
    for block in COMPOSITION_BLOCKS:
        if block["key"] == block_key:
            return block
    raise KeyError(f"Unknown composition block: {{block_key}}")


def composition_install_plan(block_keys, target="studio"):
    """Return an approval-ready install plan for reusable app blocks."""
    selected = []
    visited = set()

    def add_block(block_key):
        if block_key in visited:
            return
        block = _composition_block(block_key)
        for dependency in block["depends_on"]:
            add_block(dependency)
        visited.add(block_key)
        selected.append(block)

    for block_key in tuple(block_keys):
        add_block(block_key)
    artifacts = tuple(dict.fromkeys(path for block in selected for path in block["artifacts"]))
    checks = tuple(dict.fromkeys(check for block in selected for check in block["review_checks"]))
    return {{
        "format": "appgen.composition-install-plan.v1",
        "target": target,
        "blocks": tuple(block["key"] for block in selected),
        "artifacts": artifacts,
        "checks": checks,
        "requires_review": True,
        "sandbox_preview": True,
    }}


def composition_package(name, block_keys):
    """Return a portable package descriptor for sharing composed app features."""
    plan = composition_install_plan(block_keys)
    return {{
        "format": "appgen.composition-package.v1",
        "name": name,
        "blocks": plan["blocks"],
        "artifacts": plan["artifacts"],
        "checks": plan["checks"],
        "publish_targets": ("studio", "entando", "invenio", "cookiecutter"),
        "version": "0.1.0",
    }}


def composition_preview(block_keys):
    """Return a no-side-effect preview for app composition before generation."""
    plan = composition_install_plan(block_keys)
    return {{
        "format": "appgen.composition-preview.v1",
        "summary": f"Install {{len(plan['blocks'])}} blocks into {{plan['target']}}",
        "blocks": plan["blocks"],
        "new_artifacts": plan["artifacts"],
        "review_checks": plan["checks"],
        "destructive": False,
    }}


def composition_marketplace_readiness(existing_paths=()):
    """Return readiness for composition marketplace contracts."""
    existing = set(existing_paths)
    required = {{"app/low_code_features.py", "app/templates/appgen_low_code_features.html", "app/appgen.json"}}
    missing = tuple(sorted(required - existing))
    graph = composition_dependency_graph()
    audit = composition_dependency_audit()
    return {{
        "ok": not missing and len(COMPOSITION_BLOCKS) >= 7 and bool(graph["edges"]) and audit["ok"],
        "missing": missing,
        "blocks": tuple(block["key"] for block in COMPOSITION_BLOCKS),
        "publish_targets": ("studio", "entando", "invenio", "cookiecutter"),
        "graph": graph,
        "dependency_audit": audit,
    }}


def composition_release_gate(existing_paths=()):
    """Return release evidence for AppGen's reusable application-composition layer."""
    block_keys = tuple(block["key"] for block in COMPOSITION_BLOCKS)
    readiness = composition_marketplace_readiness(existing_paths)
    audit = composition_dependency_audit()
    install = composition_install_plan(block_keys)
    package = composition_package("appgen-marketplace-release", block_keys)
    preview = composition_preview(block_keys)
    expected_targets = ("studio", "entando", "invenio", "cookiecutter")
    gates = (
        {{"gate": "catalog_size", "ok": len(block_keys) >= 7, "value": len(block_keys)}},
        {{"gate": "dependency_topology", "ok": audit["ok"] and len(audit["installation_order"]) == len(block_keys), "evidence": audit}},
        {{"gate": "install_order", "ok": install["blocks"][0] == "schema-core" and set(install["blocks"]) == set(block_keys), "evidence": install}},
        {{"gate": "review_controls", "ok": install["requires_review"] and install["sandbox_preview"] and len(install["checks"]) >= len(block_keys), "evidence": install["checks"]}},
        {{"gate": "package_publication", "ok": all(target in package["publish_targets"] for target in expected_targets), "evidence": package}},
        {{"gate": "non_destructive_preview", "ok": preview["destructive"] is False and preview["new_artifacts"] == install["artifacts"], "evidence": preview}},
        {{"gate": "artifact_evidence", "ok": readiness["ok"], "missing": readiness["missing"]}},
    )
    return {{
        "format": "appgen.composition-release-gate.v1",
        "position": "appgen-application-composition-is-a-jhipster-superiority-advantage",
        "ok": all(gate["ok"] for gate in gates),
        "gates": gates,
        "blocking_gaps": tuple(gate["gate"] for gate in gates if not gate["ok"]),
        "blocks": block_keys,
        "installation_order": audit["installation_order"],
        "publish_targets": package["publish_targets"],
    }}


def composition_workbench(existing_paths=()):
    """Return an IDE-ready workbench for installing and publishing reusable app blocks."""
    existing = set(existing_paths)
    block_keys = tuple(block["key"] for block in COMPOSITION_BLOCKS)
    catalog = application_composition_catalog()
    audit = composition_dependency_audit()
    install = composition_install_plan(block_keys)
    package = composition_package("appgen-composition-workbench", block_keys)
    preview = composition_preview(block_keys)
    readiness = composition_marketplace_readiness(existing)
    release = composition_release_gate(existing)
    expected_targets = ("studio", "entando", "invenio", "cookiecutter")
    routes = (
        "/low-code-features/composition.json",
        "/low-code-features/composition-readiness.json",
        "/low-code-features/composition-workbench.json",
        "/low-code-features/composition-release-gate.json",
    )
    checks = (
        {{
            "id": "block_catalog",
            "ok": len(catalog) >= 7 and "schema-core" in block_keys and len({{block["kind"] for block in catalog}}) >= 5,
            "evidence": {{"blocks": block_keys, "kinds": tuple(sorted({{block["kind"] for block in catalog}}))}},
        }},
        {{
            "id": "dependency_topology",
            "ok": audit["ok"] and install["blocks"][0] == "schema-core" and set(install["blocks"]) == set(block_keys),
            "evidence": audit,
        }},
        {{
            "id": "reviewed_install",
            "ok": install["requires_review"] and install["sandbox_preview"] and preview["destructive"] is False and len(install["checks"]) >= len(block_keys),
            "evidence": {{"install": install, "preview": preview}},
        }},
        {{
            "id": "publication_handoffs",
            "ok": all(target in package["publish_targets"] for target in expected_targets),
            "evidence": {{"publish_targets": package["publish_targets"], "package": package}},
        }},
        {{
            "id": "artifact_evidence",
            "ok": readiness["ok"] and release["ok"],
            "evidence": {{"missing": readiness["missing"], "blocking_gaps": release["blocking_gaps"]}},
        }},
        {{
            "id": "route_surface",
            "ok": all(route.startswith("/low-code-features/") for route in routes),
            "evidence": {{"routes": routes}},
        }},
    )
    ok = all(check["ok"] for check in checks)
    return {{
        "format": "appgen.composition-workbench.v1",
        "ok": ok,
        "decision": "approved" if ok else "blocked",
        "catalog": catalog,
        "install_plan": install,
        "package": package,
        "preview": preview,
        "release_gate": release,
        "checks": checks,
    }}


def grouped_capabilities():
    """Group capabilities by their top-level area."""
    grouped = defaultdict(list)
    for capability in CAPABILITIES:
        group = capability["key"].split(".", 1)[0]
        grouped[group].append(dict(capability))
    return {{group: tuple(items) for group, items in sorted(grouped.items())}}


def roadmap_alignment():
    """Map docs/Lo-code features.md themes to generated capability evidence."""
    capabilities = {{item["key"]: item for item in CAPABILITIES}}
    alignment = []
    for area in ROADMAP_AREAS:
        items = tuple(dict(capabilities[key]) for key in area["capabilities"] if key in capabilities)
        alignment.append(
            {{
                "area": area["area"],
                "label": area["label"],
                "capabilities": items,
                "covered": len(items) == len(area["capabilities"]),
            }}
        )
    return tuple(alignment)


def source_document_contracts():
    """Return the roadmap documents that generated readiness must trace to."""
    return tuple(dict(item) for item in ROADMAP_SOURCES)


def _requirement_alignment(requirements):
    capabilities = {{item["key"]: item for item in CAPABILITIES}}
    rows = []
    for requirement in requirements:
        present = tuple(key for key in requirement["capabilities"] if key in capabilities)
        missing = tuple(key for key in requirement["capabilities"] if key not in capabilities)
        rows.append(
            {{
                "id": requirement["id"],
                "label": requirement["label"],
                "capabilities": tuple(dict(capabilities[key]) for key in present),
                "capability_keys": present,
                "missing_capabilities": missing,
                "artifacts": requirement["artifacts"],
                "covered": not missing,
            }}
        )
    return tuple(rows)


def base_feature_alignment():
    """Map docs/base_features.md requirements to generated capabilities."""
    return _requirement_alignment(BASE_FEATURE_REQUIREMENTS)


def ideas_roadmap_alignment():
    """Map docs/ideas.md roadmap items to generated capabilities."""
    return _requirement_alignment(IDEAS_ROADMAP_REQUIREMENTS)


def roadmap_source_report():
    """Return combined readiness for docs/ideas.md, docs/base_features.md, and low-code features."""
    base = base_feature_alignment()
    ideas = ideas_roadmap_alignment()
    low_code = roadmap_alignment()
    documents = source_document_contracts()
    return {{
        "format": "appgen.roadmap-source-report.v1",
        "documents": documents,
        "document_count": len(documents),
        "base_features": base,
        "ideas_roadmap": ideas,
        "low_code_features": low_code,
        "base_features_complete": all(item["covered"] for item in base),
        "ideas_roadmap_complete": all(item["covered"] for item in ideas),
        "low_code_features_complete": all(item["covered"] for item in low_code),
        "ok": all(item["covered"] for item in base) and all(item["covered"] for item in ideas) and all(item["covered"] for item in low_code),
    }}


def roadmap_release_audit(existing_paths=None):
    """Prove roadmap coverage with implemented capabilities, artifacts, routes, and tests."""
    base = base_feature_alignment()
    ideas = ideas_roadmap_alignment()
    low_code = roadmap_alignment()
    documents = source_document_contracts()
    expected_artifacts = tuple(
        dict.fromkeys(
            path
            for requirement in tuple(BASE_FEATURE_REQUIREMENTS) + tuple(IDEAS_ROADMAP_REQUIREMENTS)
            for path in requirement["artifacts"]
        )
    )
    required_tests = (
        "tests/test_generated_contract.py",
        "tests/test_generated_coverage.py",
        "scripts/appgen_quality.py",
    )
    existing = set(expected_artifacts + required_tests if existing_paths is None else existing_paths)
    capability_status = {{item["key"]: item["status"] for item in CAPABILITIES}}

    def harden_alignment(rows):
        hardened = []
        for row in rows:
            implemented = tuple(key for key in row["capability_keys"] if capability_status.get(key) == "implemented")
            not_implemented = tuple(key for key in row["capability_keys"] if capability_status.get(key) != "implemented")
            missing_artifacts = tuple(path for path in row["artifacts"] if path not in existing)
            hardened.append({{
                **row,
                "implemented_capabilities": implemented,
                "not_implemented_capabilities": not_implemented,
                "missing_artifacts": missing_artifacts,
                "covered": row["covered"] and not not_implemented and not missing_artifacts,
            }})
        return tuple(hardened)

    base_hardened = harden_alignment(base)
    ideas_hardened = harden_alignment(ideas)
    low_code_hardened = tuple(
        {{
            **row,
            "implemented_capabilities": tuple(item["key"] for item in row["capabilities"] if item["status"] == "implemented"),
            "not_implemented_capabilities": tuple(item["key"] for item in row["capabilities"] if item["status"] != "implemented"),
            "covered": row["covered"] and all(item["status"] == "implemented" for item in row["capabilities"]),
        }}
        for row in low_code
    )
    route_map = jhipster_superset_route_map()
    critical_routes = (
        "/studio/",
        "/dsl-reference/",
        "/schema-import/",
        "/designer/",
        "/form-designer/",
        "/nl-evolution/",
        "/agents/",
        "/platforms/",
        "/erp-templates/",
        "/runtime-assurance/",
        "/low-code-features/",
    )
    route_paths = {{item["route"] for item in route_map}} | {{"/dsl-reference/"}}
    missing_routes = tuple(route for route in critical_routes if route not in route_paths)
    missing_tests = tuple(path for path in required_tests if path not in existing)
    non_implemented = tuple(item for item in CAPABILITIES if item["status"] != "implemented")
    checks = (
        {{
            "id": "source_document_lineage",
            "ok": {{"docs/ideas.md", "docs/base_features.md", "docs/Lo-code features.md"}} <= {{item["document"] for item in documents}},
            "evidence": documents,
        }},
        {{
            "id": "implementation_status",
            "ok": not non_implemented,
            "evidence": {{"total": len(CAPABILITIES), "non_implemented": non_implemented}},
        }},
        {{
            "id": "base_feature_requirements",
            "ok": all(row["covered"] for row in base_hardened),
            "evidence": base_hardened,
        }},
        {{
            "id": "ideas_roadmap_requirements",
            "ok": all(row["covered"] for row in ideas_hardened),
            "evidence": ideas_hardened,
        }},
        {{
            "id": "low_code_feature_families",
            "ok": all(row["covered"] for row in low_code_hardened),
            "evidence": low_code_hardened,
        }},
        {{
            "id": "artifact_evidence",
            "ok": all(not row["missing_artifacts"] for row in base_hardened + ideas_hardened),
            "evidence": {{"expected_artifacts": expected_artifacts}},
        }},
        {{
            "id": "route_surface",
            "ok": not missing_routes,
            "evidence": {{"critical_routes": critical_routes, "missing_routes": missing_routes}},
        }},
        {{
            "id": "test_evidence",
            "ok": not missing_tests,
            "evidence": {{"required_tests": required_tests, "missing_tests": missing_tests}},
        }},
        {{
            "id": "jhipster_superset",
            "ok": jhipster_superset_certification()["ok"] and jhipster_feature_superiority_index()["ok"],
            "evidence": {{"certification": jhipster_superset_certification(), "feature_index": jhipster_feature_superiority_index()}},
        }},
    )
    ok = all(check["ok"] for check in checks)
    return {{
        "format": "appgen.roadmap-release-audit.v1",
        "ok": ok,
        "decision": "approved" if ok else "blocked",
        "documents": documents,
        "base_features": base_hardened,
        "ideas_roadmap": ideas_hardened,
        "low_code_features": low_code_hardened,
        "expected_artifacts": expected_artifacts,
        "required_tests": required_tests,
        "critical_routes": critical_routes,
        "checks": checks,
    }}


def jhipster_capability_benchmark():
    """Return overlap and AppGen-only capability rows for JHipster comparison."""
    rows = tuple(dict(item) for item in COMPETITIVE_BENCHMARK)
    appgen_only = tuple(item for item in rows if item["appgen"] and not item["jhipster"])
    overlap = tuple(item for item in rows if item["appgen"] and item["jhipster"])
    return {{
        "baseline": dict(JHIPSTER_BASELINE),
        "rows": rows,
        "overlap": overlap,
        "appgen_only": appgen_only,
        "appgen_only_count": len(appgen_only),
        "overlap_count": len(overlap),
        "ok": len(appgen_only) >= 7 and len(overlap) >= 4,
    }}


def jhipster_capability_depth_index(existing_paths=None):
    """Return depth evidence for every AppGen-only JHipster differentiator."""
    scorecard = jhipster_superset_scorecard()
    evidence = jhipster_superset_evidence(existing_paths)
    artifact_rows = {{row["area"]: row for row in evidence["rows"]}}
    scorecard_rows = {{gate["area"]: gate for gate in scorecard["required_gates"]}}
    rows = []
    for requirement in JHIPSTER_DEPTH_REQUIREMENTS:
        dimensions = tuple(requirement["dimensions"])
        present_dimensions = tuple(item["dimension"] for item in dimensions if item["evidence"])
        artifact_row = artifact_rows.get(requirement["area"], {{"ok": False, "missing_artifacts": ()}})
        scorecard_row = scorecard_rows.get(requirement["area"], {{"ok": False, "missing_capabilities": ()}})
        rows.append({{
            "area": requirement["area"],
            "minimum_dimensions": requirement["minimum_dimensions"],
            "dimensions": dimensions,
            "present_dimensions": present_dimensions,
            "missing_dimensions": tuple(
                item["dimension"]
                for item in dimensions
                if item["dimension"] not in present_dimensions
            ),
            "artifact_evidence_ok": artifact_row["ok"],
            "missing_artifacts": artifact_row.get("missing_artifacts", ()),
            "capabilities_ok": scorecard_row["ok"],
            "missing_capabilities": scorecard_row.get("missing_capabilities", ()),
            "ok": len(present_dimensions) >= requirement["minimum_dimensions"] and artifact_row["ok"] and scorecard_row["ok"],
        }})
    return {{
        "format": "appgen.jhipster-capability-depth-index.v1",
        "baseline": dict(JHIPSTER_BASELINE),
        "minimum_areas": len(JHIPSTER_DEPTH_REQUIREMENTS),
        "minimum_dimensions_per_area": 4,
        "areas": tuple(rows),
        "blocking_gaps": tuple(row for row in rows if not row["ok"]),
        "ok": len(rows) >= 10 and all(row["ok"] for row in rows),
    }}


def jhipster_superset_scorecard():
    """Return the non-negotiable gates for being more capable than JHipster."""
    benchmark = jhipster_capability_benchmark()
    appgen_only_areas = {{item["area"] for item in benchmark["appgen_only"]}}
    required_advantages = (
        {{
            "area": "visual_builders",
            "required": ("ui.visual-modeling", "ui.form-designer", "workflow.statecharts"),
            "artifacts": ("app/designer.py", "app/form_designer.py", "app/workflow.py"),
        }},
        {{
            "area": "schema_import",
            "required": ("schema.import", "data.database-ops"),
            "artifacts": ("app/schema_import.py", "app/database_ops.py"),
        }},
        {{
            "area": "native_targets",
            "required": ("platform.targets", "platform.native"),
            "artifacts": ("native/mobile/app.py", "native/desktop/app.py"),
        }},
        {{
            "area": "agentic_systems",
            "required": ("ai.agentic-systems", "ai.guided-chatbot"),
            "artifacts": ("app/agents.py", "app/chatbot.py", "app/assistant.py"),
        }},
        {{
            "area": "natural_language_evolution",
            "required": ("ui.nl-evolution", "dsl.language-design"),
            "artifacts": ("app/nl_evolution.py", "app/dsl_reference.py"),
        }},
        {{
            "area": "erp_templates",
            "required": ("components.erp-templates", "operations.finance", "operations.inventory-traceability"),
            "artifacts": ("app/erp_templates.py", "app/finance_ops.py", "app/inventory_ops.py"),
        }},
        {{
            "area": "runtime_studio",
            "required": ("devops.studio", "ops.monitoring", "ops.resilience", "ops.performance", "ops.assurance"),
            "artifacts": ("app/studio.py", "app/monitoring.py", "app/resilience.py", "app/performance.py", "app/runtime_assurance.py"),
        }},
        {{
            "area": "runtime_assurance",
            "required": ("ops.assurance", "quality.diagnostics", "ops.backup"),
            "artifacts": ("app/runtime_assurance.py", "app/templates/appgen_runtime_assurance.html", "app/backup.py", "scripts/appgen_quality.py"),
        }},
        {{
            "area": "application_composition",
            "required": ("components.application-composition", "platform.jhipster"),
            "artifacts": ("app/low_code_features.py", "jhipster/app.jdl", "cookiecutter/cookiecutter.json"),
        }},
        {{
            "area": "database_ide",
            "required": ("devops.studio", "data.database-ops", "ui.visual-modeling"),
            "artifacts": ("app/studio.py", "app/database_ops.py", "app/designer.py"),
        }},
        {{
            "area": "jhipster_migration",
            "required": ("platform.jhipster", "schema.import", "dsl.language-design", "devops.studio"),
            "artifacts": ("jhipster/app.jdl", "jhipster/appgen_jhipster.py", "app/schema_import.py", "app/studio.py", "app/low_code_features.py"),
        }},
    )
    capability_keys = {{item["key"] for item in CAPABILITIES}}
    gates = tuple(
        {{
            **gate,
            "benchmark_advantage": gate["area"] in appgen_only_areas,
            "capabilities_present": tuple(key for key in gate["required"] if key in capability_keys),
            "missing_capabilities": tuple(key for key in gate["required"] if key not in capability_keys),
            "ok": gate["area"] in appgen_only_areas and all(key in capability_keys for key in gate["required"]),
        }}
        for gate in required_advantages
    )
    return {{
        "format": "appgen.jhipster-superset-scorecard.v1",
        "baseline": dict(JHIPSTER_BASELINE),
        "position": "more-capable-than-jhipster",
        "minimum_appgen_only_advantages": 11,
        "actual_appgen_only_advantages": benchmark["appgen_only_count"],
        "required_gates": gates,
        "blocking_gaps": tuple(gate for gate in gates if not gate["ok"]),
        "interop_preserved": "platform.jhipster" in capability_keys,
        "ok": benchmark["appgen_only_count"] >= 11 and all(gate["ok"] for gate in gates) and "platform.jhipster" in capability_keys,
    }}


def jhipster_superset_evidence(existing_paths=None):
    """Return artifact evidence that AppGen's JHipster-superset gates are generated."""
    scorecard = jhipster_superset_scorecard()
    expected = tuple(dict.fromkeys(path for gate in scorecard["required_gates"] for path in gate["artifacts"]))
    existing = set(expected if existing_paths is None else existing_paths)
    rows = tuple(
        {{
            "area": gate["area"],
            "ok": gate["ok"] and not tuple(path for path in gate["artifacts"] if path not in existing),
            "capabilities": gate["required"],
            "artifacts": gate["artifacts"],
            "missing_artifacts": tuple(path for path in gate["artifacts"] if path not in existing),
        }}
        for gate in scorecard["required_gates"]
    )
    return {{
        "format": "appgen.jhipster-superset-evidence.v1",
        "position": scorecard["position"],
        "scorecard_ok": scorecard["ok"],
        "expected_artifacts": expected,
        "artifact_evidence_ok": all(row["ok"] for row in rows),
        "rows": rows,
        "ok": scorecard["ok"] and all(row["ok"] for row in rows),
    }}


def jhipster_capability_proof_matrix(existing_paths=None):
    """Return hard evidence for every AppGen-only superiority claim."""
    scorecard = jhipster_superset_scorecard()
    benchmark = jhipster_capability_benchmark()
    evidence = jhipster_superset_evidence(existing_paths)
    depth = jhipster_capability_depth_index(existing_paths)
    route_map = jhipster_superset_route_map()
    appgen_only_areas = {{item["area"] for item in benchmark["appgen_only"]}}
    evidence_rows = {{row["area"]: row for row in evidence["rows"]}}
    depth_rows = {{row["area"]: row for row in depth["areas"]}}
    routes_by_area = defaultdict(list)
    for route in route_map:
        routes_by_area[route["area"]].append(route)
    rows = []
    for gate in scorecard["required_gates"]:
        area = gate["area"]
        artifact_row = evidence_rows.get(area, {{"ok": False, "missing_artifacts": gate["artifacts"]}})
        depth_row = depth_rows.get(area, {{"ok": False, "present_dimensions": (), "missing_dimensions": ("design_time", "generation_time", "runtime", "governance")}})
        route_rows = tuple(routes_by_area.get(area, ()))
        checks = (
            {{"check": "benchmark_advantage", "ok": area in appgen_only_areas}},
            {{"check": "capability_gate", "ok": gate["ok"], "missing_capabilities": gate.get("missing_capabilities", ())}},
            {{"check": "artifact_evidence", "ok": artifact_row["ok"], "missing_artifacts": artifact_row.get("missing_artifacts", ())}},
            {{"check": "depth_evidence", "ok": depth_row["ok"], "present_dimensions": depth_row.get("present_dimensions", ()), "missing_dimensions": depth_row.get("missing_dimensions", ())}},
            {{"check": "route_evidence", "ok": bool(route_rows), "routes": tuple(route["route"] for route in route_rows)}},
        )
        rows.append({{
            "area": area,
            "checks": checks,
            "routes": route_rows,
            "artifacts": gate["artifacts"],
            "capabilities": gate["required"],
            "ok": all(check["ok"] for check in checks),
        }})
    return {{
        "format": "appgen.jhipster-capability-proof-matrix.v1",
        "baseline": dict(JHIPSTER_BASELINE),
        "position": "appgen-superiority-requires-runnable-generated-proof",
        "minimum_appgen_only_advantages": scorecard["minimum_appgen_only_advantages"],
        "actual_appgen_only_advantages": scorecard["actual_appgen_only_advantages"],
        "required_proof_checks": ("benchmark_advantage", "capability_gate", "artifact_evidence", "depth_evidence", "route_evidence"),
        "areas": tuple(rows),
        "blocking_gaps": tuple(row for row in rows if not row["ok"]),
        "ok": scorecard["ok"] and evidence["ok"] and depth["ok"] and all(row["ok"] for row in rows),
    }}


def jhipster_superset_certification(existing_paths=None):
    """Return a single release gate proving AppGen remains more capable than JHipster."""
    benchmark = jhipster_capability_benchmark()
    scorecard = jhipster_superset_scorecard()
    evidence = jhipster_superset_evidence(existing_paths)
    depth = jhipster_capability_depth_index(existing_paths)
    roadmap = roadmap_source_report()
    proof = jhipster_capability_proof_matrix(existing_paths)
    composition_paths = set(evidence["expected_artifacts"] if existing_paths is None else existing_paths)
    composition_paths.update({{"app/low_code_features.py", "app/templates/appgen_low_code_features.html", "app/appgen.json"}})
    composition = composition_marketplace_readiness(composition_paths)
    overlap_required = ("entity_modeling", "full_stack_web", "frontends", "devops")
    overlap_areas = {{item["area"] for item in benchmark["overlap"]}}
    missing_overlap = tuple(area for area in overlap_required if area not in overlap_areas)
    advantage_ratio = round(benchmark["appgen_only_count"] / max(1, benchmark["overlap_count"]), 2)
    generated_contracts = (
        "jhipster/app.jdl",
        "jhipster/appgen_jhipster.py",
        "app/low_code_features.py",
        "app/dsl_reference.py",
        "app/studio.py",
        "app/form_designer.py",
        "app/agents.py",
        "app/runtime_assurance.py",
        "app/erp_templates.py",
    )
    gates = (
        {{"gate": "jhipster_overlap_preserved", "ok": not missing_overlap, "missing": missing_overlap}},
        {{"gate": "appgen_only_advantage_threshold", "ok": benchmark["appgen_only_count"] >= 10, "value": benchmark["appgen_only_count"]}},
        {{"gate": "advantage_ratio", "ok": advantage_ratio >= 2.0, "value": advantage_ratio}},
        {{"gate": "scorecard", "ok": scorecard["ok"], "blocking_gaps": scorecard["blocking_gaps"]}},
        {{"gate": "artifact_evidence", "ok": evidence["ok"], "missing_rows": tuple(row for row in evidence["rows"] if not row["ok"])}},
        {{"gate": "capability_depth", "ok": depth["ok"], "blocking_gaps": depth["blocking_gaps"]}},
        {{"gate": "capability_proof_matrix", "ok": proof["ok"], "blocking_gaps": proof["blocking_gaps"]}},
        {{"gate": "roadmap_traceability", "ok": roadmap["ok"], "documents": roadmap["documents"]}},
        {{"gate": "composition_readiness", "ok": composition["ok"], "missing": composition["missing"]}},
    )
    return {{
        "format": "appgen.jhipster-superset-certification.v1",
        "certification": "appgen-more-capable-than-jhipster",
        "baseline": dict(JHIPSTER_BASELINE),
        "position": scorecard["position"],
        "minimum_overlap_count": len(overlap_required),
        "actual_overlap_count": benchmark["overlap_count"],
        "minimum_appgen_only_advantages": 11,
        "actual_appgen_only_advantages": benchmark["appgen_only_count"],
        "advantage_ratio": advantage_ratio,
        "capability_depth": depth,
        "capability_proof": proof,
        "generated_contracts": generated_contracts,
        "gates": gates,
        "blocking_gaps": tuple(gate for gate in gates if not gate["ok"]),
        "ok": all(gate["ok"] for gate in gates),
    }}


