def jhipster_frontier_gate(existing_paths=None):
    """Prove AppGen preserves advanced JHipster families and exceeds each one."""
    capability_keys = {{item["key"] for item in CAPABILITIES}}
    benchmark = jhipster_capability_benchmark()
    appgen_only_areas = {{item["area"] for item in benchmark["appgen_only"]}}
    route_map = jhipster_superset_route_map()
    route_areas = {{item["area"] for item in route_map}}
    expected_artifacts = tuple(
        dict.fromkeys(path for requirement in JHIPSTER_FRONTIER_REQUIREMENTS for path in requirement["parity_artifacts"])
    )
    existing = set(expected_artifacts if existing_paths is None else existing_paths)
    families = []
    for requirement in JHIPSTER_FRONTIER_REQUIREMENTS:
        missing_capabilities = tuple(
            capability
            for capability in requirement["parity_capabilities"]
            if capability not in capability_keys
        )
        missing_artifacts = tuple(
            artifact
            for artifact in requirement["parity_artifacts"]
            if artifact not in existing
        )
        missing_advantages = tuple(
            area
            for area in requirement["exceeds_with"]
            if area not in appgen_only_areas
        )
        surfaced_advantages = tuple(
            area
            for area in requirement["exceeds_with"]
            if area in route_areas
        )
        parity_ok = not missing_capabilities and not missing_artifacts
        exceeds_ok = not missing_advantages and bool(surfaced_advantages)
        families.append({{
            **requirement,
            "missing_capabilities": missing_capabilities,
            "missing_artifacts": missing_artifacts,
            "missing_advantages": missing_advantages,
            "surfaced_advantages": surfaced_advantages,
            "parity_ok": parity_ok,
            "exceeds_ok": exceeds_ok,
            "ok": parity_ok and exceeds_ok,
        }})
    certification = jhipster_superset_certification(existing_paths)
    superiority = jhipster_superiority_tiers(existing_paths)
    return {{
        "format": "appgen.jhipster-frontier-gate.v1",
        "position": "appgen-exceeds-jhipster-frontier",
        "baseline": dict(JHIPSTER_BASELINE),
        "minimum_jhipster_families": len(JHIPSTER_FRONTIER_REQUIREMENTS),
        "actual_jhipster_families": len(families),
        "expected_artifacts": expected_artifacts,
        "families": tuple(families),
        "certification_ok": certification["ok"],
        "superiority_ok": superiority["ok"],
        "blocking_gaps": tuple(family for family in families if not family["ok"]) + certification["blocking_gaps"] + superiority["blocking_gaps"],
        "stop_condition": "do-not-claim-frontier-superiority-unless-ok-is-true",
        "ok": len(families) >= len(JHIPSTER_FRONTIER_REQUIREMENTS) and all(family["ok"] for family in families) and certification["ok"] and superiority["ok"],
    }}


def jhipster_feature_superiority_index(existing_paths=None):
    """Score AppGen feature depth against JHipster by product domain."""
    route_map = jhipster_superset_route_map()
    route_paths = {{item["route"] for item in route_map}}
    expected_artifacts = tuple(
        dict.fromkeys(path for domain in JHIPSTER_FEATURE_DOMAINS for path in domain["artifacts"])
    )
    existing = set(expected_artifacts if existing_paths is None else existing_paths)
    domains = []
    total_jhipster = 0
    total_appgen = 0
    for domain in JHIPSTER_FEATURE_DOMAINS:
        missing_routes = tuple(route for route in domain["routes"] if route not in route_paths)
        missing_artifacts = tuple(path for path in domain["artifacts"] if path not in existing)
        jhipster_score = len(domain["jhipster_features"])
        appgen_score = len(domain["appgen_features"])
        ratio = round(appgen_score / max(1, jhipster_score), 2)
        total_jhipster += jhipster_score
        total_appgen += appgen_score
        domains.append({{
            **domain,
            "jhipster_score": jhipster_score,
            "appgen_score": appgen_score,
            "score_ratio": ratio,
            "missing_routes": missing_routes,
            "missing_artifacts": missing_artifacts,
            "ok": appgen_score > jhipster_score and ratio >= 1.5 and not missing_routes and not missing_artifacts,
        }})
    certification = jhipster_superset_certification(existing_paths)
    proof = jhipster_capability_proof_matrix(existing_paths)
    frontier = jhipster_frontier_gate(existing_paths)
    superiority = jhipster_superiority_tiers(existing_paths)
    aggregate_ratio = round(total_appgen / max(1, total_jhipster), 2)
    gates = (
        {{"gate": "domain_scores", "ok": all(domain["ok"] for domain in domains), "domains": tuple(domain["domain"] for domain in domains if domain["ok"])}},
        {{"gate": "aggregate_ratio", "ok": aggregate_ratio >= 1.75, "value": aggregate_ratio}},
        {{"gate": "superset_certification", "ok": certification["ok"]}},
        {{"gate": "capability_proof", "ok": proof["ok"]}},
        {{"gate": "frontier_gate", "ok": frontier["ok"]}},
        {{"gate": "superiority_tiers", "ok": superiority["ok"]}},
    )
    return {{
        "format": "appgen.jhipster-feature-superiority-index.v1",
        "position": "appgen-is-feature-richer-than-jhipster-by-domain",
        "minimum_domain_ratio": 1.5,
        "minimum_aggregate_ratio": 1.75,
        "jhipster_total_score": total_jhipster,
        "appgen_total_score": total_appgen,
        "aggregate_ratio": aggregate_ratio,
        "domains": tuple(domains),
        "expected_artifacts": expected_artifacts,
        "gates": gates,
        "blocking_gaps": tuple(gate for gate in gates if not gate["ok"]) + tuple(domain for domain in domains if not domain["ok"]),
        "ok": all(gate["ok"] for gate in gates),
    }}


def jhipster_superiority_tiers(existing_paths=None):
    """Return tiered gates for being more capable than JHipster."""
    benchmark = jhipster_capability_benchmark()
    scorecard = jhipster_superset_scorecard()
    certification = jhipster_superset_certification(existing_paths)
    route_map = jhipster_superset_route_map()
    overlap_areas = {{item["area"] for item in benchmark["overlap"]}}
    appgen_only_areas = {{item["area"] for item in benchmark["appgen_only"]}}
    route_areas = {{item["area"] for item in route_map}}
    route_paths = {{item["route"] for item in route_map}}
    rows = []
    for tier in JHIPSTER_SUPERIORITY_TIERS:
        if tier["source"] == "overlap":
            available = overlap_areas
        elif tier["source"] == "appgen_only":
            available = appgen_only_areas
        else:
            available = route_areas
        present_areas = tuple(area for area in tier["areas"] if area in available)
        missing_areas = tuple(area for area in tier["areas"] if area not in available)
        expected_routes = tier.get("routes", ())
        present_routes = tuple(route for route in expected_routes if route in route_paths)
        missing_routes = tuple(route for route in expected_routes if route not in route_paths)
        actual = len(present_routes) if expected_routes else len(present_areas)
        rows.append(
            {{
                **tier,
                "present_areas": present_areas,
                "missing_areas": missing_areas,
                "present_routes": present_routes,
                "missing_routes": missing_routes,
                "actual": actual,
                "ok": actual >= tier["minimum"] and not missing_areas and not missing_routes,
            }}
        )
    return {{
        "format": "appgen.jhipster-superiority-tiers.v1",
        "baseline": dict(JHIPSTER_BASELINE),
        "position": "appgen-must-be-measurably-more-capable-than-jhipster",
        "tiers": tuple(rows),
        "scorecard_ok": scorecard["ok"],
        "certification_ok": certification["ok"],
        "minimum_appgen_only_advantages": 11,
        "actual_appgen_only_advantages": benchmark["appgen_only_count"],
        "advantage_ratio": certification["advantage_ratio"],
        "blocking_gaps": tuple(row for row in rows if not row["ok"]) + certification["blocking_gaps"],
        "stop_condition": "do-not-claim-jhipster-superiority-unless-ok-is-true",
        "ok": certification["ok"] and all(row["ok"] for row in rows) and benchmark["appgen_only_count"] >= 11,
    }}


def jhipster_superset_blueprint(existing_paths=None):
    """Return the user-facing blueprint for exceeding JHipster capability."""
    route_map = jhipster_superset_route_map()
    certification = jhipster_superset_certification(existing_paths)
    expected = tuple(dict.fromkeys(path for route in route_map for path in route["artifacts"]))
    existing = set(expected if existing_paths is None else existing_paths)
    route_rows = tuple(
        {{
            **route,
            "missing_artifacts": tuple(path for path in route["artifacts"] if path not in existing),
            "ok": not tuple(path for path in route["artifacts"] if path not in existing),
        }}
        for route in route_map
    )
    pillars = (
        {{
            "pillar": "design",
            "routes": ("/designer/", "/form-designer/", "/view-composition/"),
            "outcome": "no-code database, form, relationship, and screen design instead of entity-file editing only",
        }},
        {{
            "pillar": "generate",
            "routes": ("/schema-import/", "/studio/", "/platforms/"),
            "outcome": "web, mobile, desktop, chatbot, frontend, API, SDK, and deployment targets from one schema",
        }},
        {{
            "pillar": "operate",
            "routes": ("/runtime-assurance/", "/monitoring/", "/resilience/", "/performance/", "/backup/"),
            "outcome": "generated runbooks and release gates for production operations",
        }},
        {{
            "pillar": "evolve",
            "routes": ("/nl-evolution/", "/dsl-reference/", "/agents/"),
            "outcome": "natural-language and agent-assisted evolution with reviewed deterministic DSL patches",
        }},
        {{
            "pillar": "compose",
            "routes": ("/low-code-features/", "/erp-templates/", "/integrations/"),
            "outcome": "ERP packs, application-composition packages, and portal/repository integration handoffs",
        }},
    )
    return {{
        "format": "appgen.jhipster-superset-blueprint.v1",
        "baseline": dict(JHIPSTER_BASELINE),
        "position": "appgen-is-a-generated-application-platform-not-only-a-crud-scaffolder",
        "route_map": route_rows,
        "pillars": pillars,
        "certification": certification,
        "expected_artifacts": expected,
        "blocking_gaps": tuple(row for row in route_rows if not row["ok"]) + certification["blocking_gaps"],
        "ok": certification["ok"] and all(row["ok"] for row in route_rows),
    }}


