def _beeware_desktop_text(schema: AppSchema, app_name: str) -> str:
    tables = _native_tables(schema)
    return f'''"""Generated BeeWare desktop starter for {app_name}."""

from __future__ import annotations

APP_NAME = {app_name!r}
TABLES = {tables!r}
DESKTOP_ENTITLEMENTS = {{
    "macos": ("com.apple.security.files.user-selected.read-write",),
    "linux": ("xdg-documents",),
    "windows": ("documentsLibrary",),
}}


def desktop_contract():
    """Return generated desktop table and API descriptors."""
    return {{"app_name": APP_NAME, "framework": "beeware", "tables": TABLES, "entitlements": DESKTOP_ENTITLEMENTS}}


def menu_actions():
    """Return desktop menu actions for generated tables."""
    return tuple(
        {{"label": table["label"], "action": f"open_{{table['name'].lower()}}", "endpoint": table["endpoint"]}}
        for table in TABLES
    )


def local_cache_plan(cache_dir):
    """Return local cache file names for generated desktop data."""
    return tuple(
        {{"table": table["name"], "path": f"{{cache_dir}}/{{table['name'].lower()}}.json"}}
        for table in TABLES
    )


def desktop_cache_snapshot(cache_dir, records=None):
    """Return a reviewable desktop cache snapshot without touching disk."""
    records = dict(records or {{}})
    return {{
        "format": "appgen.desktop-cache-snapshot.v1",
        "cache_dir": cache_dir,
        "files": tuple(
            {{
                "table": item["table"],
                "path": item["path"],
                "record_count": len(records.get(item["table"], ())),
                "status": "planned",
            }}
            for item in local_cache_plan(cache_dir)
        ),
        "requires_review": False,
    }}


def desktop_change_set(table_name, changes=(), *, source="desktop"):
    """Return a local desktop change set for later API replay."""
    table = next((item for item in TABLES if item["name"] == table_name or item["name"].lower() == str(table_name).lower()), None)
    if table is None:
        raise KeyError(f"Unknown desktop table: {{table_name}}")
    normalized = tuple(
        {{
            "table": table["name"],
            "operation": change.get("operation", "upsert"),
            "values": dict(change.get("values", change)),
            "status": "pending",
        }}
        for change in changes
    )
    return {{
        "format": "appgen.desktop-change-set.v1",
        "source": source,
        "table": table["name"],
        "endpoint": table["endpoint"],
        "changes": normalized,
        "requires_review": True,
    }}


def desktop_sync_plan(api_base, change_sets=()):
    """Return reviewed desktop cache replay steps for generated API routes."""
    normalized_sets = tuple(change_sets)
    return {{
        "format": "appgen.desktop-sync-plan.v1",
        "api_base": api_base.rstrip("/"),
        "change_sets": normalized_sets,
        "steps": tuple(
            {{
                "table": change_set["table"],
                "url": api_base.rstrip("/") + change_set["endpoint"],
                "method": "POST",
                "change_count": len(change_set["changes"]),
                "conflict_policy": "manual_review",
            }}
            for change_set in normalized_sets
        ),
        "checks": ("cache_snapshot", "network_available", "auth_token_present", "conflict_scan", "audit_sync_result"),
        "requires_review": True,
    }}


def desktop_file_action(path, *, action="open", table_name=None):
    """Return a reviewed desktop local-file action without touching the file system."""
    if not str(path).strip():
        raise ValueError("Desktop file path is required")
    return {{
        "action": action,
        "path": str(path),
        "table": table_name,
        "entitlement": "com.apple.security.files.user-selected.read-write",
        "review_required": True,
    }}


def desktop_notification_payload(title, body, data=None):
    """Return a generated desktop notification payload."""
    if not str(title).strip() or not str(body).strip():
        raise ValueError("Notification title and body are required")
    return {{"title": str(title), "body": str(body), "data": dict(data or {{}})}}


try:
    import toga
except ImportError:  # pragma: no cover - generated starter can be inspected without BeeWare.
    toga = None


class AppGenDesktopApp(toga.App if toga else object):
    def startup(self):
        if toga is None:
            return None
        table_names = "\\n".join(table["label"] for table in TABLES) or "No tables"
        self.main_window = toga.MainWindow(title=APP_NAME)
        self.main_window.content = toga.Box(children=[toga.Label(table_names)])
        self.main_window.show()


def main():
    """Run the generated BeeWare desktop app."""
    if toga is None:
        return desktop_contract()
    return AppGenDesktopApp(APP_NAME, "org.appgen.generated").main_loop()


if __name__ == "__main__":
    main()
'''


def _jhipster_type(type_name: str) -> str:
    normalized = type_name.lower().strip()
    if normalized.endswith("[]"):
        return "String"
    normalized = normalized.split("(", 1)[0]
    if normalized in {"int", "integer", "serial", "smallint"}:
        return "Integer"
    if normalized in {"bigint", "bigserial"}:
        return "Long"
    if normalized in {"float", "real", "double", "double precision"}:
        return "Double"
    if normalized in {"decimal", "numeric", "money"}:
        return "BigDecimal"
    if normalized in {"bool", "boolean"}:
        return "Boolean"
    if normalized in {"date"}:
        return "LocalDate"
    if normalized in {"datetime", "timestamp", "timestamptz", "time"}:
        return "Instant"
    if normalized in {"text", "longtext", "mediumtext"}:
        return "TextBlob"
    if normalized in {"blob", "binary", "bytea"}:
        return "AnyBlob"
    return "String"


def _jhipster_entity_name(table_name: str) -> str:
    if "_" in table_name:
        return snake_to_pascal(table_name)
    return table_name[:1].upper() + table_name[1:]


def _jhipster_field_name(column: ColumnSchema) -> str:
    return underscore(_model_attribute_name(column))


def _jhipster_relationship_name(source_column: str) -> str:
    name = underscore(source_column)
    if name.endswith("_id"):
        name = name[:-3]
    return name or underscore(source_column)


def _jhipster_relationship_type(cardinality: str) -> str:
    return {
        "one-to-one": "OneToOne",
        "one-to-many": "OneToMany",
        "many-to-many": "ManyToMany",
        "many-to-one": "ManyToOne",
    }.get(cardinality, "ManyToOne")


def _jhipster_collection_name(entity_name: str) -> str:
    return pluralize(underscore(entity_name))


def _jhipster_jdl_relationship_line(relationship: dict) -> str:
    if relationship["type"] == "OneToMany":
        collection = _jhipster_collection_name(relationship["target"])
        inverse = _jhipster_relationship_name(relationship.get("target_column") or "")
        if inverse:
            return f"  {relationship['source']}{{{collection}}} to {relationship['target']}{{{inverse}}}"
        return f"  {relationship['source']}{{{collection}}} to {relationship['target']}"
    return f"  {relationship['source']}{{{relationship['field']}}} to {relationship['target']}"


def _jhipster_entity_contracts(schema: AppSchema) -> tuple[dict, ...]:
    return tuple(
        {
            "table": table.name,
            "entity": _jhipster_entity_name(table.name),
            "fields": tuple(
                {
                    "name": _jhipster_field_name(column),
                    "type": _jhipster_type(column.type_name),
                    "required": not column.nullable and not column.primary_key,
                    "source_column": column.name,
                }
                for column in table.columns
                if not column.primary_key and not column.references and not column.derived
            ),
        }
        for table in schema.tables
    )


def _jhipster_relationship_contracts(schema: AppSchema) -> tuple[dict, ...]:
    return tuple(
        {
            "type": _jhipster_relationship_type(relation.cardinality),
            "cardinality": relation.cardinality,
            "source": _jhipster_entity_name(relation.source_table),
            "field": _jhipster_relationship_name(relation.source_column),
            "target": _jhipster_entity_name(relation.target_table),
            "source_column": relation.source_column,
            "target_column": relation.target_column,
        }
        for relation in schema.relations
    )


def _jhipster_contract_text(schema: AppSchema, app_name: str) -> str:
    entities = _jhipster_entity_contracts(schema)
    relationships = _jhipster_relationship_contracts(schema)
    appgen_upgrade_targets = (
        {
            "key": "visual-builders",
            "label": "Visual builders and RAD-style form design",
            "jhipster_equivalent": None,
            "appgen_artifacts": ("app/designer.py", "app/form_designer.py", "app/studio.py"),
            "adoption_step": "Use generated schema/form workbenches to evolve the model and regenerate DSL.",
        },
        {
            "key": "python-native-targets",
            "label": "Python web, mobile, and desktop generation",
            "jhipster_equivalent": "Spring Boot web application",
            "appgen_artifacts": ("app/__init__.py", "native/appgen_native.py", "native/mobile/app.py", "native/desktop/app.py"),
            "adoption_step": "Generate Python-native FAB, Kivy, and BeeWare targets beside the JDL export.",
        },
        {
            "key": "security-data-governance",
            "label": "Tenant isolation, PostgreSQL role sync, SSO, and compliance",
            "jhipster_equivalent": None,
            "appgen_artifacts": ("app/rls.py", "app/identity.py", "app/compliance.py"),
            "adoption_step": "Review generated RLS policies, PostgreSQL role sync SQL, identity providers, and compliance release gates.",
        },
        {
            "key": "agentic-systems",
            "label": "Agentic systems and LLM provider contracts",
            "jhipster_equivalent": None,
            "appgen_artifacts": ("app/agents.py", "app/chatbot.py", "app/intelligence.py"),
            "adoption_step": "Model local/API-key LLM providers and agent execution plans in AppGen DSL.",
        },
        {
            "key": "erp-modules",
            "label": "ERP template library",
            "jhipster_equivalent": None,
            "appgen_artifacts": ("app/erp_templates.py", "app/finance_ops.py", "app/inventory_ops.py"),
            "adoption_step": "Compose generated ledger, AP, AR, invoicing, HR, inventory, and report modules.",
        },
        {
            "key": "operational-workbenches",
            "label": "Operations, diagnostics, performance, and resilience workbenches",
            "jhipster_equivalent": "Docker/Kubernetes helpers",
            "appgen_artifacts": ("app/diagnostics.py", "app/performance.py", "app/resilience.py", "app/studio.py"),
            "adoption_step": "Use generated runbooks, debug sessions, load tests, and generation job manifests.",
        },
        {
            "key": "schema-import-roundtrip",
            "label": "DBML, SQL, PonyORM, live database, and JDL coexistence",
            "jhipster_equivalent": "JDL modeling",
            "appgen_artifacts": ("app/schema_import.py", "jhipster/app.jdl", "jhipster/appgen_jhipster.py"),
            "adoption_step": "Keep JDL as an export target while AppGen owns the broader multi-source schema loop.",
        },
    )
    return f'''"""Generated JHipster/JDL export contract for AppGen apps."""

from __future__ import annotations


JHIPSTER = {{
    "app_name": {app_name!r},
    "jdl_file": "jhipster/app.jdl",
    "entities": {entities!r},
    "relationships": {relationships!r},
    "command": ("jhipster", "jdl", "jhipster/app.jdl"),
}}
APPGEN_UPGRADE_TARGETS = {appgen_upgrade_targets!r}
JHIPSTER_MIGRATION_ARTIFACTS = (
    "jhipster/app.jdl",
    "jhipster/appgen_jhipster.py",
    "app/schema_import.py",
    "app/studio.py",
    "app/low_code_features.py",
)


def jhipster_entities():
    """Return generated JHipster entity contracts."""
    return tuple(JHIPSTER["entities"])


def jhipster_relationships():
    """Return generated JHipster relationship contracts."""
    return tuple(JHIPSTER["relationships"])


def jhipster_import_command():
    """Return the generated JHipster JDL import command."""
    return JHIPSTER["command"]


def jdl_file():
    """Return the generated JDL file path."""
    return JHIPSTER["jdl_file"]


def export_check(existing_paths):
    """Return readiness for generated JHipster export artifacts."""
    existing = set(existing_paths)
    missing = tuple(path for path in ("jhipster/app.jdl", "jhipster/appgen_jhipster.py") if path not in existing)
    return {{
        "ok": not missing,
        "missing": missing,
        "entities": tuple(entity["entity"] for entity in JHIPSTER["entities"]),
        "relationships": JHIPSTER["relationships"],
    }}


def appgen_upgrade_targets():
    """Return AppGen capabilities that extend beyond JHipster generation."""
    return APPGEN_UPGRADE_TARGETS


def _appgen_field_type(jhipster_type):
    return {{
        "Integer": "int",
        "Long": "int",
        "Double": "float",
        "Float": "float",
        "BigDecimal": "decimal",
        "Boolean": "bool",
        "LocalDate": "date",
        "Instant": "datetime",
        "ZonedDateTime": "datetime",
        "TextBlob": "text",
        "AnyBlob": "blob",
        "ImageBlob": "blob",
    }}.get(jhipster_type, "string")


def _entity_table_map():
    return {{entity["entity"]: entity["table"] for entity in JHIPSTER["entities"]}}


def jhipster_to_appgen_dsl(*, targets=("web", "mobile", "desktop")):
    """Render an AppGen DSL migration draft from the generated JHipster contracts."""
    table_by_entity = _entity_table_map()
    relationships_by_source = {{}}
    for relationship in JHIPSTER["relationships"]:
        source_table = table_by_entity.get(relationship["source"], relationship["source"])
        relationships_by_source.setdefault(source_table, []).append(relationship)
    target_list = ", ".join(targets)
    lines = [f"app {{JHIPSTER['app_name']}} {{{{ targets: {{target_list}} }}}}", ""]
    for entity in JHIPSTER["entities"]:
        lines.append(f"table {{entity['table']}} {{{{")
        for field in entity["fields"]:
            required = " required" if field["required"] else ""
            lines.append(f"  {{field['source_column']}}:{{_appgen_field_type(field['type'])}}{{required}}")
        for relationship in relationships_by_source.get(entity["table"], ()):
            target_table = table_by_entity.get(relationship["target"], relationship["target"])
            lines.append(
                f"  {{relationship['source_column']}}:int -> {{target_table}}.{{relationship['target_column']}}[{{relationship['cardinality']}}]"
            )
        lines.append("}}")
        lines.append("")
    return "\\n".join(lines).strip() + "\\n"


def jhipster_upgrade_migration_plan(existing_paths=(), *, targets=("web", "mobile", "desktop")):
    """Return a reviewable JDL-to-AppGen upgrade plan with generated DSL output."""
    existing = set(existing_paths)
    export = export_check(existing)
    missing_platform_artifacts = tuple(path for path in JHIPSTER_MIGRATION_ARTIFACTS if path not in existing)
    upgrade_artifacts = tuple(
        sorted({{artifact for target in APPGEN_UPGRADE_TARGETS for artifact in target["appgen_artifacts"]}})
    )
    missing_upgrade_artifacts = tuple(path for path in upgrade_artifacts if path not in existing)
    return {{
        "format": "appgen.jhipster-upgrade-migration-plan.v1",
        "source": jdl_file(),
        "targets": tuple(targets),
        "appgen_dsl": jhipster_to_appgen_dsl(targets=targets),
        "export_ready": export["ok"],
        "missing_platform_artifacts": missing_platform_artifacts,
        "missing_upgrade_artifacts": missing_upgrade_artifacts,
        "steps": (
            {{"order": 1, "action": "read_jdl_contract", "artifact": jdl_file(), "ok": export["ok"]}},
            {{"order": 2, "action": "translate_to_appgen_dsl", "review_required": True}},
            {{"order": 3, "action": "run_appgen_generation", "targets": tuple(targets), "review_required": True}},
            {{"order": 4, "action": "enable_appgen_only_capabilities", "targets": tuple(target["key"] for target in APPGEN_UPGRADE_TARGETS)}},
        ),
        "ok": export["ok"] and not missing_platform_artifacts and not missing_upgrade_artifacts,
    }}


def jhipster_migration_release_gate(existing_paths=()):
    """Return readiness for upgrading JHipster/JDL-shaped projects into AppGen."""
    plan = jhipster_upgrade_migration_plan(existing_paths)
    dsl = plan["appgen_dsl"]
    blockers = tuple(
        {{"kind": "missing_platform_artifact", "path": path}}
        for path in plan["missing_platform_artifacts"]
    ) + tuple(
        {{"kind": "missing_upgrade_artifact", "path": path}}
        for path in plan["missing_upgrade_artifacts"]
    )
    return {{
        "format": "appgen.jhipster-migration-release-gate.v1",
        "ok": plan["ok"] and "table " in dsl and "targets:" in dsl and not blockers,
        "decision": "approved" if plan["ok"] and "table " in dsl and "targets:" in dsl and not blockers else "blocked",
        "plan": plan,
        "blockers": blockers,
    }}


def jhipster_gap_analysis():
    """Return JHipster parity plus AppGen-only upgrade areas."""
    return {{
        "format": "appgen.jhipster-gap-analysis.v1",
        "jhipster_strengths": (
            "JDL entity modeling",
            "Spring Boot service generation",
            "Java/TypeScript application conventions",
            "Docker and Kubernetes helpers",
        ),
        "parity": (
            "entity_modeling",
            "relationship_modeling",
            "rest_api_generation",
            "security_conventions",
            "deployment_helpers",
        ),
        "appgen_only": tuple(target["key"] for target in APPGEN_UPGRADE_TARGETS if target["jhipster_equivalent"] is None),
        "upgrade_targets": APPGEN_UPGRADE_TARGETS,
        "position": "appgen-is-broader-than-jhipster",
    }}


def jhipster_adoption_plan(existing_paths=(), *, strategy="coexist"):
    """Return a reviewable plan for using JHipster as an interop target."""
    export = export_check(existing_paths)
    steps = (
        {{
            "order": 1,
            "action": "verify_jdl_export",
            "ok": export["ok"],
            "missing": export["missing"],
        }},
        {{
            "order": 2,
            "action": "run_jhipster_import_when_needed",
            "command": jhipster_import_command(),
            "side_effect": "external_code_generation",
            "review_required": True,
        }},
        {{
            "order": 3,
            "action": "adopt_appgen_upgrade_targets",
            "targets": tuple(target["key"] for target in APPGEN_UPGRADE_TARGETS),
            "review_required": True,
        }},
    )
    return {{
        "format": "appgen.jhipster-adoption-plan.v1",
        "strategy": strategy,
        "source": jdl_file(),
        "entity_count": len(JHIPSTER["entities"]),
        "relationship_count": len(JHIPSTER["relationships"]),
        "ready": export["ok"],
        "steps": steps,
        "gap_analysis": jhipster_gap_analysis(),
    }}
'''


def _jhipster_jdl_text(schema: AppSchema, app_name: str) -> str:
    base_name = snake_to_pascal(app_name).replace("_", "")
    lines = [
        "application {",
        "  config {",
        f"    baseName {base_name}",
        "    applicationType monolith",
        "    authenticationType jwt",
        "    prodDatabaseType postgresql",
        "    devDatabaseType h2Disk",
        "    buildTool maven",
        "    clientFramework react",
        "    enableTranslation true",
        "    nativeLanguage en",
        "    languages [en]",
        "  }",
        "  entities *",
        "}",
        "",
    ]
    for entity in _jhipster_entity_contracts(schema):
        lines.append(f"entity {entity['entity']} {{")
        for field in entity["fields"]:
            suffix = " required" if field["required"] else ""
            lines.append(f"  {field['name']} {field['type']}{suffix}")
        lines.append("}")
        lines.append("")
    relationships = _jhipster_relationship_contracts(schema)
    if relationships:
        for relationship_type in ("ManyToOne", "OneToOne", "OneToMany", "ManyToMany"):
            typed_relationships = [
                relationship for relationship in relationships if relationship["type"] == relationship_type
            ]
            if not typed_relationships:
                continue
            lines.append(f"relationship {relationship_type} {{")
            for relationship in typed_relationships:
                lines.append(_jhipster_jdl_relationship_line(relationship))
            lines.append("}")
            lines.append("")
    lines.extend(
        [
            "dto * with mapstruct",
            "service * with serviceClass",
            "paginate * with pagination",
            "filter *",
            "",
        ]
    )
    return "\n".join(lines)


def _node_red_events(schema: AppSchema) -> tuple[dict, ...]:
    actions = ("created", "updated", "deleted")
    return tuple(
        {
            "kind": "table",
            "table": table.name,
            "action": action,
            "topic": f"{table.name}.{action}",
            "path": f"/appgen/{underscore(table.name)}/{action}",
        }
        for table in schema.tables
        for action in actions
    )


def _node_red_workflow_events(schema: AppSchema) -> tuple[dict, ...]:
    return tuple(
        {
            "kind": "workflow",
            "workflow": flow.name,
            "source": step.source,
            "target": step.target,
            "topic": f"workflow.{flow.name}.{step.source}.{step.target}",
            "path": (
                f"/appgen/workflow/{underscore(flow.name)}/"
                f"{underscore(step.source)}/{underscore(step.target)}"
            ),
        }
        for flow in schema.flows
        for step in flow.steps
    )


def _node_red_contract_text(schema: AppSchema, app_name: str) -> str:
    events = _node_red_events(schema)
    workflow_events = _node_red_workflow_events(schema)
    return f'''"""Generated Node-RED automation contract for AppGen apps."""

from __future__ import annotations


FLOW_FILE = "automation/node-red/flows.json"

APP_CONTRACT = {{
    "app_name": {app_name!r},
    "flow_file": FLOW_FILE,
    "events": {events!r},
    "workflow_events": {workflow_events!r},
    "runtime": {{
        "service": "node-red",
        "image": "nodered/node-red:3.1",
        "port": 1880,
        "flows_file": FLOW_FILE,
        "compose_mount": "./automation/node-red:/data",
        "credential_env": "NODE_RED_CREDENTIAL_SECRET",
        "health_url": "http://localhost:1880/",
    }},
}}


def node_red_events():
    """Return generated table-event topics exposed to Node-RED."""
    return tuple(APP_CONTRACT["events"])


def workflow_events():
    """Return generated workflow transition topics exposed to Node-RED."""
    return tuple(APP_CONTRACT["workflow_events"])


def automation_events():
    """Return every generated table and workflow automation topic."""
    return node_red_events() + workflow_events()


def node_red_runtime_service():
    """Return the default generated Node-RED runtime service descriptor."""
    return dict(APP_CONTRACT["runtime"])


def compose_service_plan():
    """Return the Docker Compose service contract for the generated Node-RED runtime."""
    runtime = node_red_runtime_service()
    return {{
        "service": runtime["service"],
        "image": runtime["image"],
        "ports": (f"{{runtime['port']}}:{{runtime['port']}}",),
        "environment": {{
            "FLOWS": "flows.json",
            runtime["credential_env"]: "${{NODE_RED_CREDENTIAL_SECRET:-appgen-change-me}}",
        }},
        "volumes": (runtime["compose_mount"], "node_red_data:/data/projects"),
        "health_url": runtime["health_url"],
    }}


def runtime_readiness(existing_paths=()):
    """Return readiness for running generated Node-RED flows locally by default."""
    required = {{"automation/node-red/flows.json", "docker-compose.yml"}}
    existing = set(existing_paths or ())
    missing = tuple(sorted(required - existing))
    runtime = node_red_runtime_service()
    return {{
        "ok": not missing,
        "default_service": runtime["service"],
        "image": runtime["image"],
        "port": runtime["port"],
        "missing": missing,
        "run": "docker compose up node-red",
    }}


def event_topic(table_name, action):
    """Return the generated event topic for a table action."""
    normalized = str(table_name).lower()
    for event in APP_CONTRACT["events"]:
        if event["table"].lower() == normalized and event["action"] == action:
            return event["topic"]
    raise KeyError(f"Unknown Node-RED event: {{table_name}}.{{action}}")


def workflow_event_topic(flow_name, source, target):
    """Return the generated event topic for a workflow transition."""
    normalized = str(flow_name).lower()
    for event in APP_CONTRACT["workflow_events"]:
        if (
            event["workflow"].lower() == normalized
            and event["source"] == source
            and event["target"] == target
        ):
            return event["topic"]
    raise KeyError(f"Unknown Node-RED workflow event: {{flow_name}}.{{source}}.{{target}}")


def webhook_plan(table_name, action, base_url=""):
    """Return the HTTP webhook endpoint that feeds a generated Node-RED event."""
    normalized = str(table_name).lower()
    for event in APP_CONTRACT["events"]:
        if event["table"].lower() == normalized and event["action"] == action:
            prefix = str(base_url).rstrip("/")
            return {{
                "topic": event["topic"],
                "method": "POST",
                "path": event["path"],
                "url": prefix + event["path"],
            }}
    raise KeyError(f"Unknown Node-RED webhook: {{table_name}}.{{action}}")


def workflow_webhook_plan(flow_name, source, target, base_url=""):
    """Return the HTTP webhook endpoint that feeds a generated workflow event."""
    normalized = str(flow_name).lower()
    for event in APP_CONTRACT["workflow_events"]:
        if (
            event["workflow"].lower() == normalized
            and event["source"] == source
            and event["target"] == target
        ):
            prefix = str(base_url).rstrip("/")
            return {{
                "topic": event["topic"],
                "method": "POST",
                "path": event["path"],
                "url": prefix + event["path"],
            }}
    raise KeyError(f"Unknown Node-RED workflow webhook: {{flow_name}}.{{source}}.{{target}}")


def validate_flow_export(flow_export):
    """Validate a Node-RED flow export against generated automation events."""
    if not isinstance(flow_export, list):
        return {{"ok": False, "error": "flow export must be a list"}}
    node_names = {{node.get("name") for node in flow_export if isinstance(node, dict)}}
    http_inputs = tuple(
        node for node in flow_export if isinstance(node, dict) and node.get("type") == "http in"
    )
    expected_events = automation_events()
    missing = tuple(event["topic"] for event in expected_events if event["topic"] not in node_names)
    return {{
        "ok": not missing and bool(http_inputs),
        "events": tuple(event["topic"] for event in expected_events),
        "table_events": tuple(event["topic"] for event in APP_CONTRACT["events"]),
        "workflow_events": tuple(event["topic"] for event in APP_CONTRACT["workflow_events"]),
        "http_inputs": len(http_inputs),
        "runtime": node_red_runtime_service(),
        "missing": missing,
    }}


def node_red_release_gate(existing_paths=(), flow_export=None):
    """Return a release decision for the generated Node-RED automation runtime."""
    existing = set(existing_paths or ())
    required = {{"automation/appgen_node_red.py", "automation/node-red/flows.json", "docker-compose.yml"}}
    missing = tuple(sorted(required - existing))
    events = automation_events()
    flow_validation = validate_flow_export(flow_export) if flow_export is not None else {{
        "ok": False,
        "missing": tuple(event["topic"] for event in events),
        "http_inputs": 0,
        "runtime": node_red_runtime_service(),
    }}
    runtime = runtime_readiness(existing)
    table_webhooks = tuple(
        webhook_plan(event["table"], event["action"])
        for event in node_red_events()
    )
    workflow_webhooks = tuple(
        workflow_webhook_plan(event["workflow"], event["source"], event["target"])
        for event in workflow_events()
    )
    checks = (
        {{
            "gate": "artifact_coverage",
            "ok": not missing,
            "evidence": {{"required": tuple(sorted(required)), "missing": missing}},
        }},
        {{
            "gate": "event_topic_coverage",
            "ok": bool(events) and flow_validation["ok"],
            "evidence": {{
                "events": tuple(event["topic"] for event in events),
                "missing": flow_validation.get("missing", ()),
                "http_inputs": flow_validation.get("http_inputs", 0),
            }},
        }},
        {{
            "gate": "webhook_contracts",
            "ok": len(table_webhooks) == len(node_red_events()) and len(workflow_webhooks) == len(workflow_events()),
            "evidence": {{
                "table_webhooks": table_webhooks,
                "workflow_webhooks": workflow_webhooks,
            }},
        }},
        {{
            "gate": "default_runtime",
            "ok": runtime["ok"] and runtime["default_service"] == "node-red" and runtime["port"] == 1880,
            "evidence": runtime,
        }},
        {{
            "gate": "compose_service",
            "ok": compose_service_plan()["image"].startswith("nodered/node-red") and compose_service_plan()["ports"] == ("1880:1880",),
            "evidence": compose_service_plan(),
        }},
    )
    ok = all(check["ok"] for check in checks)
    return {{
        "format": "appgen.node-red-release-gate.v1",
        "ok": ok,
        "decision": "approved" if ok else "blocked",
        "checks": checks,
        "runtime": node_red_runtime_service(),
    }}


def node_red_workbench(existing_paths=(), flow_export=None):
    """Return consolidated Node-RED automation evidence for generated IDEs."""
    release_gate = node_red_release_gate(existing_paths, flow_export)
    validation = validate_flow_export(flow_export or [])
    runtime = runtime_readiness(existing_paths)
    routes = tuple(event["path"] for event in automation_events())
    table_webhooks = tuple(
        webhook_plan(event["table"], event["action"])
        for event in node_red_events()
    )
    workflow_webhooks = tuple(
        workflow_webhook_plan(event["workflow"], event["source"], event["target"])
        for event in workflow_events()
    )
    checks = (
        {{"id": "artifact_coverage", "ok": runtime["ok"] and not node_red_release_gate(existing_paths, flow_export)["checks"][0]["evidence"]["missing"], "evidence": runtime}},
        {{"id": "event_topic_coverage", "ok": bool(automation_events()) and validation["ok"], "evidence": validation}},
        {{"id": "webhook_contracts", "ok": len(table_webhooks) == len(node_red_events()) and len(workflow_webhooks) == len(workflow_events()), "evidence": {{"table_webhooks": table_webhooks, "workflow_webhooks": workflow_webhooks}}}},
        {{"id": "default_runtime", "ok": runtime["default_service"] == "node-red" and runtime["port"] == 1880, "evidence": runtime}},
        {{"id": "compose_service", "ok": compose_service_plan()["image"].startswith("nodered/node-red") and compose_service_plan()["ports"] == ("1880:1880",), "evidence": compose_service_plan()}},
        {{"id": "release_gate", "ok": release_gate["ok"], "evidence": release_gate["decision"]}},
        {{"id": "route_surface", "ok": all(route.startswith("/appgen/") for route in routes), "evidence": {{"routes": routes}}}},
    )
    ok = all(check["ok"] for check in checks)
    return {{
        "format": "appgen.node-red-workbench.v1",
        "ok": ok,
        "decision": "approved" if ok else "blocked",
        "events": automation_events(),
        "runtime": node_red_runtime_service(),
        "compose": compose_service_plan(),
        "routes": routes,
        "release_gate": release_gate,
        "checks": checks,
    }}
'''


def _node_red_flows_text(schema: AppSchema, app_name: str) -> str:
    nodes = [
        {
            "id": "appgen-flow",
            "type": "tab",
            "label": f"{app_name} Automation",
            "disabled": False,
            "info": "Generated AppGen table-event automation flow.",
        }
    ]
    for event in _node_red_events(schema) + _node_red_workflow_events(schema):
        node_base = underscore(event["topic"].replace(".", "_"))
        context_lines = [
            "  event: msg.topic,",
            f"  kind: {json.dumps(event['kind'])},",
        ]
        if event["kind"] == "table":
            context_lines.extend(
                [
                    f"  table: {json.dumps(event['table'])},",
                    f"  action: {json.dumps(event['action'])},",
                ]
            )
        else:
            context_lines.extend(
                [
                    f"  workflow: {json.dumps(event['workflow'])},",
                    f"  source: {json.dumps(event['source'])},",
                    f"  target: {json.dumps(event['target'])},",
                ]
            )
        context_lines.append("  body: msg.payload")
        function_body = "\n".join(
            [
                f"msg.topic = {json.dumps(event['topic'])};",
                "msg.payload = {",
                *context_lines,
                "};",
                "return msg;",
            ]
        )
        nodes.extend(
            [
                {
                    "id": f"{node_base}-in",
                    "type": "http in",
                    "z": "appgen-flow",
                    "name": event["topic"],
                    "url": event["path"],
                    "method": "post",
                    "upload": False,
                    "swaggerDoc": "",
                    "wires": [[f"{node_base}-normalize"]],
                },
                {
                    "id": f"{node_base}-normalize",
                    "type": "function",
                    "z": "appgen-flow",
                    "name": f"Normalize {event['topic']}",
                    "func": function_body,
                    "outputs": 1,
                    "noerr": 0,
                    "initialize": "",
                    "finalize": "",
                    "libs": [],
                    "wires": [[f"{node_base}-response"]],
                },
                {
                    "id": f"{node_base}-response",
                    "type": "http response",
                    "z": "appgen-flow",
                    "name": f"{event['topic']} accepted",
                    "statusCode": "202",
                    "headers": {},
                    "wires": [],
                },
            ]
        )
    return json.dumps(nodes, indent=2, sort_keys=True) + "\n"


def _chatbot_table_contracts(schema: AppSchema) -> tuple[dict, ...]:
    contracts = []
    for table in schema.tables:
        prompts = []
        for column in table.columns:
            if column.hidden or column.derived or column.primary_key:
                continue
            field = _model_attribute_name(column)
            prompts.append(
                {
                    "field": field,
                    "source_column": column.name,
                    "type": column.type_name,
                    "required": not column.nullable,
                    "prompt": f"What should {field.replace('_', ' ')} be?",
                }
            )
        contracts.append(
            {
                "intent": f"create_{underscore(table.name)}",
                "display_name": f"Create {snake_to_label(table.name)}",
                "table": table.name,
                "label": snake_to_label(table.name),
                "required_fields": tuple(prompt["field"] for prompt in prompts if prompt["required"]),
                "optional_fields": tuple(prompt["field"] for prompt in prompts if not prompt["required"]),
                "prompts": tuple(prompts),
            }
        )
    return tuple(contracts)


def _chatbot_contract_text(schema: AppSchema, app_name: str) -> str:
    intents = _chatbot_table_contracts(schema)
    selected_targets = _selected_platform_targets(schema)
    chatbot_targets = ("dialogflow", "botframework") if "chatbot" in selected_targets else ()
    return f'''"""Generated chatbot platform export contract for AppGen apps."""

from __future__ import annotations


CHATBOT_EXPORTS = {{
    "dialogflow": ("chatbots/dialogflow/intents.json",),
    "botframework": ("chatbots/botframework/manifest.json",),
}}
SELECTED_CHATBOT_TARGETS = {chatbot_targets!r}

CHATBOT_CONTRACT = {{
    "app_name": {app_name!r},
    "intents": {intents!r},
}}


def chatbot_targets():
    """Return provider targets with generated chatbot export artifacts."""
    return SELECTED_CHATBOT_TARGETS


def chatbot_intents():
    """Return generated table-creation chatbot intents."""
    return tuple(CHATBOT_CONTRACT["intents"])


def platform_artifacts(target):
    """Return generated artifact paths for a chatbot provider target."""
    if target not in CHATBOT_EXPORTS:
        raise KeyError(f"Unknown chatbot target: {{target}}")
    return CHATBOT_EXPORTS[target]


def provider_export_matrix(existing_paths=()):
    """Return provider-specific export evidence for generated chatbot targets."""
    existing = set(existing_paths)
    rows = []
    for target in SELECTED_CHATBOT_TARGETS:
        artifacts = platform_artifacts(target)
        missing = tuple(path for path in artifacts if existing and path not in existing)
        checks = (
            ("intent_display_names", "training_phrases", "parameters")
            if target == "dialogflow"
            else ("manifest_metadata", "command_lists", "parameters")
        )
        rows.append({{
            "provider": target,
            "artifacts": artifacts,
            "missing": missing,
            "checks": checks,
            "intent_count": len(chatbot_intents()),
            "prompt_count": sum(len(intent["prompts"]) for intent in chatbot_intents()),
            "ok": not missing and bool(chatbot_intents()) and all(intent["prompts"] for intent in chatbot_intents()),
        }})
    return {{
        "format": "appgen.chatbot-provider-export-matrix.v1",
        "ok": bool(rows) and all(row["ok"] for row in rows),
        "providers": SELECTED_CHATBOT_TARGETS,
        "rows": tuple(rows),
    }}


def conversation_plan(intent_name, values):
    """Return missing fields and next prompt for a provider-neutral conversation."""
    provided = {{str(key): value for key, value in dict(values).items() if value not in (None, "")}}
    for intent in CHATBOT_CONTRACT["intents"]:
        if intent["intent"] != intent_name:
            continue
        all_fields = intent["required_fields"] + intent["optional_fields"]
        missing = tuple(field for field in intent["required_fields"] if field not in provided)
        prompt_map = {{prompt["field"]: prompt["prompt"] for prompt in intent["prompts"]}}
        next_field = missing[0] if missing else None
        return {{
            "intent": intent["intent"],
            "table": intent["table"],
            "ready": not missing,
            "missing_fields": missing,
            "next_prompt": prompt_map.get(next_field),
            "values": {{field: provided[field] for field in all_fields if field in provided}},
        }}
    raise KeyError(f"Unknown chatbot intent: {{intent_name}}")


def export_check(existing_paths):
    """Return readiness for generated chatbot provider artifacts."""
    existing = set(existing_paths)
    required = ("chatbots/appgen_chatbots.py",) + tuple(
        path
        for target in SELECTED_CHATBOT_TARGETS
        for path in CHATBOT_EXPORTS[target]
    )
    missing = tuple(path for path in required if path not in existing)
    return {{
        "ok": not missing,
        "missing": missing,
        "targets": chatbot_targets(),
        "intents": tuple(intent["intent"] for intent in CHATBOT_CONTRACT["intents"]),
    }}


def chatbot_provider_release_gate(existing_paths=()):
    """Return release readiness for Dialogflow and Bot Framework exports."""
    exports = export_check(existing_paths)
    matrix = provider_export_matrix(existing_paths)
    targets = set(chatbot_targets())
    intents = chatbot_intents()
    first_intent = intents[0]["intent"] if intents else None
    empty_plan = conversation_plan(first_intent, {{}}) if first_intent else {{}}
    gates = (
        {{"gate": "provider_targets", "ok": {{"dialogflow", "botframework"}} <= targets, "evidence": tuple(sorted(targets))}},
        {{"gate": "artifact_coverage", "ok": exports["ok"], "evidence": exports}},
        {{"gate": "provider_export_matrix", "ok": matrix["ok"], "evidence": matrix["rows"]}},
        {{"gate": "intent_prompt_coverage", "ok": bool(intents) and all(intent["prompts"] for intent in intents), "evidence": tuple((intent["intent"], len(intent["prompts"])) for intent in intents)}},
        {{"gate": "conversation_readiness", "ok": bool(first_intent) and empty_plan.get("ready") is False and bool(empty_plan.get("next_prompt")), "evidence": empty_plan}},
    )
    ok = all(gate["ok"] for gate in gates)
    return {{
        "format": "appgen.chatbot-provider-release-gate.v1",
        "ok": ok,
        "decision": "approved" if ok else "blocked",
        "providers": SELECTED_CHATBOT_TARGETS,
        "export_matrix": matrix,
        "gates": gates,
        "blocking_gaps": tuple(gate["gate"] for gate in gates if not gate["ok"]),
    }}
'''


def _dialogflow_intents_text(schema: AppSchema, app_name: str) -> str:
    intents = []
    for contract in _chatbot_table_contracts(schema):
        intents.append(
            {
                "displayName": contract["intent"],
                "trainingPhrases": [
                    {"parts": [{"text": f"create {contract['label'].lower()}"}]},
                    {"parts": [{"text": f"add {contract['label'].lower()}"}]},
                    {"parts": [{"text": f"new {contract['label'].lower()}"}]},
                ],
                "parameters": [
                    {
                        "displayName": prompt["field"],
                        "entityType": "@sys.any",
                        "mandatory": prompt["required"],
                        "prompts": [prompt["prompt"]],
                    }
                    for prompt in contract["prompts"]
                ],
                "messages": [
                    {
                        "text": {
                            "text": [
                                f"I can create {contract['label'].lower()} records from this conversation."
                            ]
                        }
                    }
                ],
            }
        )
    return json.dumps(
        {
            "displayName": app_name,
            "languageCode": "en",
            "intents": intents,
        },
        indent=2,
        sort_keys=True,
    ) + "\n"


def _botframework_manifest_text(schema: AppSchema, app_name: str) -> str:
    bot_id = f"{underscore(app_name)}-bot"
    commands = [
        {
            "title": contract["intent"],
            "description": f"Create {contract['label'].lower()} records with guided field prompts.",
        }
        for contract in _chatbot_table_contracts(schema)
    ]
    manifest = {
        "$schema": "https://developer.microsoft.com/json-schemas/teams/v1.16/MicrosoftTeams.schema.json",
        "manifestVersion": "1.16",
        "version": "0.1.0",
        "id": bot_id,
        "packageName": f"appgen.{underscore(app_name)}.bot",
        "name": {"short": app_name[:30], "full": app_name},
        "description": {
            "short": f"{app_name} generated chatbot",
            "full": "Generated Bot Framework manifest with schema-derived commands and field prompts.",
        },
        "bots": [
            {
                "botId": bot_id,
                "scopes": ["personal", "team"],
                "commandLists": [
                    {
                        "scopes": ["personal", "team"],
                        "commands": commands,
                    }
                ],
            }
        ],
    }
    return json.dumps(manifest, indent=2, sort_keys=True) + "\n"


def _ci_workflow_text() -> str:
    return """name: AppGen CI

on:
  push:
  pull_request:

jobs:
  quality:
    runs-on: ubuntu-latest

    steps:
      - name: Check out repository
        uses: actions/checkout@v4

      - name: Set up Python
        uses: actions/setup-python@v5
        with:
          python-version: "3.12"

      - name: Install dependencies
        run: |
          python -m pip install --upgrade pip
          python -m pip install -r requirements.txt pytest

      - name: Run generated quality gate
        run: python scripts/appgen_quality.py

      - name: Run generated tests
        run: pytest
"""


